/* AUTO-GENERATED — Nebraska Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["NE"] = {"code":"NE","name":"Nebraska","agency":"Nebraska DMV","agencyShort":"DMV","handbook":"https://dmv.nebraska.gov/cdl/cdl","links":{},"en":[{"q":"On Nebraska highways, what is the maximum overall width allowed for a commercial vehicle without a special permit?","options":["8 feet 6 inches","8 feet","9 feet","10 feet"],"answer":0,"explanation":"Nebraska limits maximum overall vehicle width to 8 feet 6 inches (102 inches). Source: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' item 1; consistent with Neb. Rev. Stat. 60-6,288.","handbook":"","hbref":""},{"q":"What is the maximum overall vehicle height permitted on Nebraska highways without a permit?","options":["14 feet 6 inches","13 feet 6 inches","14 feet","15 feet"],"answer":0,"explanation":"Nebraska's maximum overall vehicle height is 14 feet 6 inches. Source: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' item 2.","handbook":"","hbref":""},{"q":"In Nebraska, what is the maximum overall length for a single vehicle (not a combination)?","options":["40 feet","45 feet","53 feet","35 feet"],"answer":0,"explanation":"A single vehicle in Nebraska may be no longer than 40 feet overall. Source: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' item 3.","handbook":"","hbref":""},{"q":"What is the maximum legal length of a semitrailer (excluding the truck-tractor) in Nebraska?","options":["53 feet","48 feet","40 feet","57 feet"],"answer":0,"explanation":"Nebraska allows a semitrailer (excluding the truck-tractor) up to 53 feet. Source: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' item 5.","handbook":"","hbref":""},{"q":"What is the maximum overall length for a combination of vehicles in Nebraska?","options":["65 feet","60 feet","75 feet","53 feet"],"answer":0,"explanation":"Nebraska sets the maximum overall length for a combination of vehicles at 65 feet. Source: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' item 4.","handbook":"","hbref":""},{"q":"What is the maximum single wheel load allowed on a Nebraska highway?","options":["10,000 pounds","12,000 pounds","8,000 pounds","20,000 pounds"],"answer":0,"explanation":"No wheel may carry a gross load greater than 10,000 pounds on any Nebraska highway. Source: NDOT 'Legal Sizes and Weights,' item 7; Neb. Rev. Stat. 60-6,294.","handbook":"","hbref":""},{"q":"What is the maximum single axle load permitted on Nebraska highways?","options":["20,000 pounds","18,000 pounds","22,400 pounds","34,000 pounds"],"answer":0,"explanation":"Nebraska limits a single axle to 20,000 pounds. Source: NDOT 'Legal Sizes and Weights,' item 8; Neb. Rev. Stat. 60-6,294.","handbook":"","hbref":""},{"q":"What is the maximum tandem axle load allowed on Nebraska highways?","options":["34,000 pounds","36,000 pounds","40,000 pounds","32,000 pounds"],"answer":0,"explanation":"The gross weight transmitted through a tandem axle group may not exceed 34,000 pounds in Nebraska. Source: NDOT 'Legal Sizes and Weights,' item 9; Neb. Rev. Stat. 60-6,294.","handbook":"","hbref":""},{"q":"What is the maximum gross weight for a vehicle operating on Interstate-designated routes in Nebraska without a permit?","options":["80,000 pounds","94,000 pounds","84,000 pounds","76,000 pounds"],"answer":0,"explanation":"Legal gross weight on Interstate-designated routes in Nebraska is 80,000 pounds. Source: NDOT 'Legal Sizes and Weights,' Weight exceptions note; Neb. Rev. Stat. 60-6,294.","handbook":"","hbref":""},{"q":"On U.S. and State routes (non-Interstate) in Nebraska, what is the legal gross weight limit?","options":["94,000 pounds","80,000 pounds","90,000 pounds","100,000 pounds"],"answer":0,"explanation":"Nebraska allows a legal gross weight of 94,000 pounds on U.S. and State routes (subject to axle and bridge-formula limits), versus 80,000 pounds on the Interstate. Source: NDOT 'Legal Sizes and Weights,' Weight exceptions note.","handbook":"","hbref":""},{"q":"How does Nebraska define a 'tandem axle' for weight-limit purposes?","options":["Two consecutive axles more than 40 and not more than 96 inches apart","Two axles less than 40 inches apart","Any two axles within 120 inches of each other","Two axles exactly 60 inches apart"],"answer":0,"explanation":"Nebraska defines a tandem axle as any two consecutive axles whose centers are more than 40 inches and not more than 96 inches apart. Source: Neb. Rev. Stat. 60-6,294.","handbook":"","hbref":""},{"q":"Under Nebraska's axle-group weight table (federal bridge formula), what is the maximum load for two axles spaced 8 feet apart?","options":["34,000 pounds","38,000 pounds","40,000 pounds","36,000 pounds"],"answer":0,"explanation":"Nebraska's 'Maximum Load on Any Group of Two or More Axles' table shows 34,000 pounds for two axles spaced 8 feet apart. Source: NDOT 'Legal Sizes and Weights' axle-group table; Neb. Rev. Stat. 60-6,294.","handbook":"","hbref":""},{"q":"According to Nebraska's axle-group weight table, what is the maximum load on five axles spaced 51 feet apart (extremes)?","options":["80,000 pounds","76,000 pounds","84,000 pounds","78,000 pounds"],"answer":0,"explanation":"Nebraska's bridge-formula table lists 80,000 pounds for five axles spaced 51 feet between extremes. Source: NDOT 'Legal Sizes and Weights' axle-group table; Neb. Rev. Stat. 60-6,294.","handbook":"","hbref":""},{"q":"What governs the maximum load a group of two or more axles may carry on Nebraska highways?","options":["The spacing distance between the extreme axles of the group, per the bridge-formula table","The number of tires on the vehicle only","The horsepower of the engine","The width of the trailer only"],"answer":0,"explanation":"Nebraska caps the load on any axle group based on the distance between the group's extreme axles, applying the federal bridge-formula table. Source: NDOT 'Legal Sizes and Weights'; Neb. Rev. Stat. 60-6,294.","handbook":"","hbref":""},{"q":"Which agency issues oversize/overweight permits for travel on Nebraska state highways?","options":["Nebraska Department of Transportation (NDOT)","Nebraska Department of Motor Vehicles","Nebraska State Patrol","The county sheriff's office"],"answer":0,"explanation":"The Nebraska Department of Transportation (NDOT) issues oversize/overweight permits for state highways; the DMV directs applicants to NDOT. Source: Nebraska DMV FAQ; NDOT Permits / Automated Truck Permit System.","handbook":"","hbref":""},{"q":"How can a carrier most commonly obtain an oversize/overweight permit from Nebraska's DOT?","options":["Through NDOT's online Automated Truck Permit System","By mailing a paper form to the DMV","By calling the local police department","Permits cannot be obtained in advance"],"answer":0,"explanation":"Nebraska oversize/overweight permits are obtained through NDOT's online Automated Truck Permit System (dottruckpermits.nebraska.gov). Source: NDOT Permits; Nebraska DMV FAQ.","handbook":"","hbref":""},{"q":"When is an oversize or overweight permit required to operate on Nebraska highways?","options":["When the vehicle or load exceeds the legal maximum size or weight limits","Only when crossing into another state","Only on gravel roads","Only for vehicles carrying hazardous materials"],"answer":0,"explanation":"A special NDOT permit is required to move a vehicle or load that exceeds the legal maximum size or weight; no permit is issued for a load that could be reduced or dismantled without great difficulty. Source: NDOT 'Legal Sizes and Weights' (Excess Size or Weight); Neb. Rev. Stat. 60-6,294.","handbook":"","hbref":""},{"q":"In Nebraska, above what height does the operator assume the risk of loss and liability for striking overhead obstructions?","options":["Over 12 feet 6 inches","Over 13 feet 6 inches","Over 14 feet 6 inches","Over 11 feet"],"answer":0,"explanation":"Nebraska law provides that owners/operators of a vehicle exceeding 12 feet 6 inches in height assume the risk and are liable for damage to overhead obstructions. Source: NDOT 'Legal Sizes and Weights,' Height exception.","handbook":"","hbref":""},{"q":"Which special exception does Nebraska grant from the 8-foot-6-inch width limit?","options":["Farm equipment moved during daylight hours in the normal course of farm operation","Any flatbed trailer hauling steel","All refrigerated trailers","Vehicles registered out of state"],"answer":0,"explanation":"Nebraska's 8'6\" width limit does not apply to farm equipment in temporary movement during daylight hours in the normal course of farm operation. Source: NDOT 'Legal Sizes and Weights,' Width exception.","handbook":"","hbref":""},{"q":"Under Nebraska's statutory weight rules, what happens if a truck crosses a bridge with a gross load exceeding the bridge's posted capacity and causes damage?","options":["The vehicle's owner is responsible for all of the damage","Liability is shared equally with NDOT","There is no liability if a permit was purchased","Only the driver, not the owner, is liable"],"answer":0,"explanation":"Nebraska law makes the truck owner responsible for all damage resulting from crossing a bridge with a load over its posted capacity. Source: NDOT 'Legal Sizes and Weights' (bridge provision); Neb. Rev. Stat. 60-6,294.","handbook":"","hbref":""},{"q":"In Nebraska, which CDL class is required to operate a combination of vehicles with a Gross Combination Weight Rating (GCWR) of 26,001 pounds or more, provided the GVWR of the unit(s) being towed exceeds 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Nebraska defines a Class A CDL as a combination of vehicles with a GCWR of 26,001 or more pounds where the towed unit(s) have a GVWR over 10,000 pounds. Source: Nebraska DMV, CDL Classes, Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"Under Nebraska rules, which CDL class covers a single vehicle with a GVWR of 26,001 pounds or more (or such a vehicle towing a unit not over 10,000 pounds)?","options":["Class A","Class B","Class C","Class M"],"answer":1,"explanation":"Nebraska defines a Class B CDL as a single vehicle with a GVWR of 26,001 or more pounds, or any such vehicle towing a unit not in excess of 10,000 pounds. Source: Nebraska DMV, CDL Classes, Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"A Nebraska driver operates a single vehicle under 26,001 pounds GVWR that is required to be placarded for hazardous materials. Which CDL class applies?","options":["Class A","Class B","Class C","Class O"],"answer":2,"explanation":"Nebraska's Class C CDL covers a single vehicle under 26,001 pounds GVWR (or towing a unit up to 10,000 pounds) that is required to be placarded for hazardous materials or is a bus designed to carry 16 or more passengers including the driver. Source: Nebraska DMV, CDL Classes, Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"Per Nebraska's Class C definition, a bus requires a CDL when it is designed to transport how many passengers?","options":["8 or more including the driver","11 or more including the driver","16 or more including the driver","24 or more including the driver"],"answer":2,"explanation":"Nebraska's Class C definition includes any bus designed to transport 16 or more passengers including the driver. Source: Nebraska DMV, CDL Classes, Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"What is the minimum age to be issued a Nebraska commercial driver's license for intrastate (within Nebraska only) operation?","options":["16 years old","17 years old","18 years old","21 years old"],"answer":2,"explanation":"Nebraska does not issue a CDL or CLP to anyone who has not attained the age of 18; 18 is the minimum age for intrastate CDL operation. Source: Neb. Rev. Stat. 60-4,143; Nebraska DMV CDL pages.","handbook":"","hbref":""},{"q":"A Nebraska CDL holder wants to drive a commercial vehicle across state lines (interstate). What is the minimum age to do so?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"While Nebraska issues an intrastate CDL at 18, a driver must be at least 21 years old to operate a commercial motor vehicle in interstate commerce. Source: Nebraska DMV CDL pages; 49 CFR 391.11 applied as the Nebraska rule.","handbook":"","hbref":""},{"q":"Which endorsement does a Nebraska driver need to transport hazardous materials in quantities requiring placards?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"answer":1,"explanation":"The H (Hazardous Materials) endorsement is required to haul placarded hazardous materials; it requires a knowledge test and a TSA security threat assessment. Source: Nebraska DMV, CDL Classes, Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"Before Nebraska issues a CDL with the HazMat (H) endorsement, the applicant must complete which additional federal background step?","options":["A TSA security threat assessment with fingerprinting","An FBI civil rights interview","A DEA controlled-substances registration","A USCIS naturalization review"],"answer":0,"explanation":"Beyond passing the HazMat knowledge test, Nebraska requires applicants to complete a Transportation Security Administration (TSA) security threat assessment, which includes pre-enrollment and fingerprinting, before the H endorsement is issued. Source: Nebraska DMV, CDL Classes, Endorsements and Restrictions; TSA HME program.","handbook":"","hbref":""},{"q":"How often must a Nebraska driver renew the HazMat (H) endorsement, including submitting new fingerprints for the TSA threat assessment?","options":["At least every 2 years","At least every 3 years","At least every 5 years","At least every 8 years"],"answer":2,"explanation":"The HazMat endorsement and its TSA security threat assessment must be renewed at least every five years, with new fingerprints submitted at renewal. Source: Nebraska DMV CDL pages; TSA HME program (49 CFR 1572).","handbook":"","hbref":""},{"q":"Which endorsement is required in Nebraska to drive a tank vehicle used to haul liquids or gases in bulk?","options":["T endorsement","N endorsement","H endorsement","P endorsement"],"answer":1,"explanation":"The N (Tank Vehicle) endorsement is required to operate a tank vehicle and requires passing a knowledge test. Source: Nebraska DMV, CDL Classes, Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"A Nebraska driver wants to pull double or triple trailers. Which endorsement is required?","options":["N endorsement","P endorsement","T endorsement","S endorsement"],"answer":2,"explanation":"The T (Doubles/Triples) endorsement is required to pull double and triple trailers and requires passing a knowledge test. Source: Nebraska DMV, CDL Classes, Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"Which endorsement must a Nebraska CDL holder have to drive a vehicle designed to carry 16 or more people, such as a passenger bus?","options":["S endorsement","P endorsement","N endorsement","H endorsement"],"answer":1,"explanation":"The P (Passenger) endorsement is required for vehicles designed to carry 16 or more people (including the driver) and requires a knowledge test plus a skills test in a representative vehicle. Source: Nebraska DMV, CDL Classes, Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"In Nebraska, the S (School Bus) endorsement may only be issued together with which other endorsement?","options":["The H (HazMat) endorsement","The N (Tank) endorsement","The P (Passenger) endorsement","The T (Doubles/Triples) endorsement"],"answer":2,"explanation":"Nebraska requires the S (School Bus) endorsement to accompany the P (Passenger) endorsement; a driver cannot hold S without P. Source: Nebraska DMV, CDL Classes, Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"What is the minimum period a Nebraska driver must hold a Commercial Learner's Permit (CLP) before taking the CDL skills test?","options":["7 days","10 days","14 days","30 days"],"answer":2,"explanation":"Nebraska, following the federal rule, requires a driver to hold a valid CLP for a minimum of 14 days before taking the CDL skills test. Source: Nebraska DMV, Commercial Learner's Permit; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"How long is a Nebraska Commercial Learner's Permit (CLP) valid?","options":["180 days","1 year","2 years","5 years"],"answer":1,"explanation":"A Nebraska CLP is valid for 1 year. If it expires before all three skills-test segments are passed, previously passed segments become invalid and all skills testing must be retaken. Source: Nebraska DMV, Commercial Learner's Permit.","handbook":"","hbref":""},{"q":"In which CDL classes does Nebraska issue a Commercial Learner's Permit (CLP)?","options":["Class A and Class B only","Class C only","Class A, B, and C","Class B and Class C only"],"answer":0,"explanation":"Nebraska issues CLPs in Class A and Class B only. Source: Nebraska DMV, Commercial Learner's Permit.","handbook":"","hbref":""},{"q":"Which set of endorsements may a Nebraska Commercial Learner's Permit (CLP) carry?","options":["H, T, and X","P, S, and N","H and N only","T and X only"],"answer":1,"explanation":"A Nebraska CLP may carry only the P (Passenger), S (School Bus), and N (Tank, restricted to empty/no cargo) endorsements; H, T, and X are not allowed on a CLP. Source: Nebraska DMV, Commercial Learner's Permit; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"How many documents proving a Nebraska principal address must a CDL/CLP applicant provide to establish residency?","options":["One document","Two documents from different sources","Three documents","No residency proof is required"],"answer":1,"explanation":"Nebraska requires two documents from different sources showing the applicant's Nebraska principal address; a P.O. Box is not accepted. The applicant must also provide proof of identity, a Social Security number, and proof of U.S. citizenship or lawful status. Source: Nebraska DMV, CDL Documentation Requirements.","handbook":"","hbref":""},{"q":"Under Nebraska's federal Entry-Level Driver Training (ELDT) requirement, where must a driver's training be completed and recorded?","options":["With a provider listed on the FMCSA Training Provider Registry","At any private driving school of the driver's choice","Through an on-the-job apprenticeship only","At a Nebraska DMV examining station"],"answer":0,"explanation":"ELDT, effective February 7, 2022, requires first-time Class A/B applicants, B-to-A upgrades, and first-time P, S, or H endorsement applicants to complete training with a provider listed on the FMCSA Training Provider Registry, which records the completion. Source: Nebraska DMV, Entry Level Driver Training (ELDT); 49 CFR Part 380.","handbook":"","hbref":""},{"q":"Which Nebraska CDL medical self-certification category applies to a driver who operates in interstate commerce and IS subject to federal medical (DOT physical) requirements?","options":["Interstate Non-Excepted (Category A)","Interstate Excepted (Category B)","Intrastate Non-Excepted (Category C)","Intrastate Excepted (Category D)"],"answer":0,"explanation":"Category A, Interstate Non-Excepted, applies to drivers subject to federal medical and vision requirements; they must provide and keep a current medical examiner's certificate from a provider on the National Registry on file with the DMV. Source: Nebraska DMV, CDL Self-Certification Categories; Neb. Rev. Stat. 60-4,144.01.","handbook":"","hbref":""},{"q":"While operating a commercial motor vehicle (CMV) in Nebraska, at what blood alcohol concentration (BAC) is a driver considered to be driving under the influence and committing a major disqualifying offense?","options":["0.02 or higher","0.04 or higher","0.08 or higher","0.10 or higher"],"answer":1,"explanation":"Nebraska, following 49 CFR 383.51 and the Nebraska CDL Manual, makes operating a CMV with a BAC of 0.04 or higher a major disqualifying offense. The 0.08 limit applies to non-commercial vehicles. Source: Nebraska DMV CDL Disqualification page; Nebraska CDL Manual.","handbook":"","hbref":""},{"q":"Under Nebraska's implied consent law, what is the consequence of a CDL holder refusing a chemical (breath, blood, or urine) test after operating a motor vehicle?","options":["A warning letter only, with no disqualification","It is treated as a major offense, disqualifying the CDL just like a DUI conviction","A 30-day suspension that does not affect the CDL","A $100 administrative fine with no license action"],"answer":1,"explanation":"Nebraska's implied consent law treats refusal of an alcohol/drug test as a major disqualifying offense, carrying the same CDL disqualification as a DUI (1 year first offense, lifetime for a second). Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Nebraska, how long is a CDL holder disqualified for a FIRST major offense (such as DUI or test refusal) when NOT transporting placarded hazardous materials?","options":["60 days","6 months","1 year","3 years"],"answer":2,"explanation":"A first major offense disqualifies a Nebraska CDL holder for 1 year. Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If a Nebraska driver commits a first major offense while operating a CMV that is required to be placarded for hazardous materials, how long is the disqualification?","options":["1 year","2 years","3 years","Lifetime"],"answer":2,"explanation":"A first major offense while transporting placarded hazardous materials raises the disqualification from 1 year to 3 years. Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification period for a Nebraska CDL holder who is convicted of a SECOND major offense?","options":["3 years","5 years","10 years","Lifetime"],"answer":3,"explanation":"A second major offense results in a lifetime CDL disqualification in Nebraska. Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is classified as a major disqualifying offense for a Nebraska CDL holder, rather than a serious traffic violation?","options":["Following another vehicle too closely","Leaving the scene of an accident","Improper or erratic lane changes","Speeding 15 mph or more over the limit"],"answer":1,"explanation":"Leaving the scene of an accident is a MAJOR offense (1-year/lifetime disqualification). Following too closely, erratic lane changes, and excessive speeding are SERIOUS traffic violations (60/120 days). Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How fast over the posted speed limit must a Nebraska CDL holder be driving for it to count as the 'excessive speeding' serious traffic violation?","options":["10 mph or more over","15 mph or more over","20 mph or more over","25 mph or more over"],"answer":1,"explanation":"Speeding 15 mph or more over the posted limit is the 'excessive speeding' serious traffic violation in Nebraska. Source: Nebraska CDL Manual; Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Nebraska, how long is a CDL holder disqualified for being convicted of TWO serious traffic violations in separate incidents within a 3-year period?","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"Two serious traffic violations within 3 years result in a 60-day CDL disqualification. Source: Nebraska DMV CDL Disqualification / MCSIA page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How long is a Nebraska CDL holder disqualified for committing THREE serious traffic violations in separate incidents within a 3-year period?","options":["60 days","90 days","120 days","180 days"],"answer":2,"explanation":"Three serious traffic violations within 3 years result in a 120-day CDL disqualification (which must follow any 60-day disqualification already imposed). Source: Nebraska DMV MCSIA page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is on Nebraska's list of SERIOUS traffic violations for CDL holders?","options":["Driving with a BAC of 0.04 or higher","Texting while driving a CMV","Refusing a chemical test","Using a CMV to commit a felony"],"answer":1,"explanation":"Texting while driving a CMV is a serious traffic violation in Nebraska. The other three listed are major offenses. Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Operating a CMV without the proper class of CDL or required endorsement for the vehicle being driven is classified in Nebraska as which type of violation?","options":["A minor equipment violation","A serious traffic violation","A major disqualifying offense","An out-of-service order violation"],"answer":1,"explanation":"Driving a CMV without the proper CDL class or endorsement is one of Nebraska's serious traffic violations, subject to 60-day/120-day disqualification when committed repeatedly. Source: Nebraska DMV MCSIA page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"For a FIRST conviction of a railroad-highway grade crossing violation, how long is a Nebraska CDL holder disqualified?","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"answer":1,"explanation":"A first railroad grade crossing violation results in a disqualification of at least 60 days. Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification period for a Nebraska CDL holder's SECOND railroad-highway grade crossing violation within a 3-year period?","options":["At least 60 days","At least 90 days","At least 120 days","At least 1 year"],"answer":2,"explanation":"A second railroad grade crossing violation within 3 years results in a disqualification of at least 120 days. Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification for a THIRD railroad-highway grade crossing violation within a 3-year period in Nebraska?","options":["At least 120 days","At least 180 days","At least 1 year","At least 3 years"],"answer":2,"explanation":"A third railroad grade crossing violation within 3 years results in a disqualification of at least 1 year. Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"For a FIRST conviction of violating an out-of-service (OOS) order while driving a standard CMV in Nebraska, what is the disqualification period?","options":["30 to 60 days","90 days","180 days to 1 year","2 to 5 years"],"answer":2,"explanation":"A first out-of-service order violation in a standard CMV results in a disqualification of 180 days to 1 year. Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification period for a SECOND out-of-service order violation within a 10-year period while driving a standard CMV in Nebraska?","options":["180 days to 1 year","1 to 2 years","2 to 5 years","Lifetime"],"answer":2,"explanation":"A second out-of-service order violation within 10 years results in a 2-to-5-year disqualification. Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"When the OUT-OF-SERVICE order violation involves a CMV transporting hazardous materials requiring placards or designed to carry 16 or more passengers, what is the FIRST-conviction disqualification in Nebraska?","options":["90 days to 1 year","180 days to 2 years","2 to 5 years","3 to 5 years"],"answer":1,"explanation":"A first out-of-service order violation involving placarded hazmat or a vehicle designed for 16+ passengers carries a heightened disqualification of 180 days to 2 years. Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Driving a CMV while your CDL is suspended, revoked, or while you are disqualified is treated by Nebraska as what kind of offense?","options":["A serious traffic violation (60/120 days)","A major disqualifying offense (1 year/lifetime)","An out-of-service violation (180 days)","A non-disqualifying paperwork violation"],"answer":1,"explanation":"Driving a CMV while one's CDL is revoked, suspended, cancelled, or while disqualified is a major offense, carrying a 1-year first-offense disqualification and lifetime for a second. Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Nebraska law (Neb. Rev. Stat. 60-6,179.01), what is the fine for a FIRST texting-while-driving violation?","options":["$100","$200","$300","$500"],"answer":1,"explanation":"Nebraska's anti-texting statute (Neb. Rev. Stat. 60-6,179.01) sets a $200 fine for a first offense, $300 for a second, and $500 for a third or subsequent offense, plus three points. For CDL drivers, repeated texting in a CMV is also a serious traffic violation. Source: Neb. Rev. Stat. 60-6,179.01.","handbook":"","hbref":""},{"q":"Using a CMV in the commission of a felony involving the manufacturing, distributing, or dispensing of a controlled substance results in what penalty for a Nebraska CDL holder?","options":["A 1-year disqualification","A 3-year disqualification","A 5-year disqualification","A lifetime disqualification with no reinstatement"],"answer":3,"explanation":"Using any motor vehicle to commit a felony involving manufacturing, distributing, or dispensing a controlled substance results in a lifetime disqualification that is not eligible for the 10-year reinstatement available for some other lifetime cases. Source: Nebraska DMV CDL Disqualification page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"On a Nebraska interstate, a tow truck is stopped on the shoulder with amber lights flashing. You are driving a CMV in the right lane and there is an open lane to your left. Under Nebraska's Move Over law, what must you do?","options":["Move into a lane at least one moving lane apart from the stopped vehicle when it is safe to do so","Maintain your speed but sound your horn as you pass","Come to a complete stop until the tow truck departs","Continue in the right lane as long as you are at or below the speed limit"],"answer":0,"explanation":"Nebraska's Move Over law (Neb. Rev. Stat. 60-6,378.01) requires drivers approaching a stopped vehicle with flashing lights to reduce speed and, when safe, move into a lane at least one moving lane apart from the stopped vehicle. Source: Neb. Rev. Stat. 60-6,378.01 / NDOT 'Move Over, Slow Down'.","handbook":"","hbref":""},{"q":"Nebraska's Move Over law was significantly expanded by LB 530 effective September 3, 2025. As of that change, drivers must slow down and move over for which of the following?","options":["Only authorized emergency vehicles displaying flashing red or blue lights","Only tow trucks and highway maintenance vehicles","All stopped vehicles and vulnerable road users on the side of the highway, including pedestrians, bicyclists, and agricultural equipment","Only vehicles stopped within an active construction work zone"],"answer":2,"explanation":"Under LB 530 (effective Sept. 3, 2025), Nebraska expanded the move-over requirement beyond emergency and roadside-assistance vehicles to ALL stopped vehicles and vulnerable road users on the side of the highway, including pedestrians, bicyclists, people in crosswalks, and agricultural vehicles or equipment. Source: Neb. LB 530 / NDOT press release 'Nebraska's Updated Move-Over Law Takes Effect Sept. 3'.","handbook":"","hbref":""},{"q":"Under Nebraska's Move Over law, when you cannot safely change lanes for a stopped vehicle displaying warning lights, what must you do instead?","options":["Stop completely on the roadway until traffic clears","Reduce your speed, maintain a safe speed for conditions, and proceed with due care and caution","Maintain the posted speed limit and pass normally","Accelerate to clear the area as quickly as possible"],"answer":1,"explanation":"Neb. Rev. Stat. 60-6,378.01 provides that if a lane change is not possible or safe, the driver must reduce speed, maintain a safe speed considering the stopped vehicle, weather, road, and traffic conditions, and proceed with due care and caution. Source: Neb. Rev. Stat. 60-6,378.01.","handbook":"","hbref":""},{"q":"What is the maximum speed limit for a commercial truck on a rural section of the National System of Interstate highways in Nebraska, unless otherwise posted?","options":["65 mph","70 mph","75 mph","80 mph"],"answer":2,"explanation":"Neb. Rev. Stat. 60-6,186 sets the maximum speed at 75 mph on rural interstate highways. Nebraska does not set a separate, lower statutory speed limit for trucks; CMVs follow the same posted maximums as other vehicles. Source: Neb. Rev. Stat. 60-6,186 / NDOT speed-limit information.","handbook":"","hbref":""},{"q":"On a Nebraska expressway or super-two highway that is part of the state highway system, what is the maximum speed limit unless otherwise posted?","options":["55 mph","65 mph","70 mph","75 mph"],"answer":2,"explanation":"Neb. Rev. Stat. 60-6,186 sets 70 mph on an expressway, super-two highway, or freeway that is part of the state highway system. (Rural interstate is 75 mph; other state highways are 65 mph.) Source: Neb. Rev. Stat. 60-6,186 / NDOT speed-limit brochure.","handbook":"","hbref":""},{"q":"Does Nebraska law set a separate, lower maximum statutory speed limit for commercial trucks compared with passenger cars?","options":["Yes, trucks are limited to 65 mph statewide","Yes, trucks must travel 10 mph below the posted limit","No, the statutory maximum speed limits in Neb. Rev. Stat. 60-6,186 apply uniformly to all vehicles","Yes, but only on the interstate system"],"answer":2,"explanation":"Neb. Rev. Stat. 60-6,186 establishes uniform statutory maximum speeds by road category with no separate truck speed limit; commercial vehicles must obey the same posted maximums as other traffic. Source: Neb. Rev. Stat. 60-6,186.","handbook":"","hbref":""},{"q":"On a Nebraska state highway that is NOT an expressway, super-two, or freeway, what is the maximum speed limit unless otherwise posted?","options":["55 mph","60 mph","65 mph","70 mph"],"answer":2,"explanation":"Neb. Rev. Stat. 60-6,186 sets 65 mph on any part of the state highway system other than an expressway, super-two highway, or freeway. Source: Neb. Rev. Stat. 60-6,186 / NDOT speed-limit brochure.","handbook":"","hbref":""},{"q":"A bus carrying passengers or a placarded hazardous-materials vehicle approaches a railroad grade crossing in Nebraska. Within what distance from the nearest rail must the driver stop?","options":["Between 5 and 25 feet","Between 15 and 50 feet","Between 25 and 75 feet","Between 50 and 100 feet"],"answer":1,"explanation":"Buses carrying passengers and placarded HazMat CMVs must stop between 15 and 50 feet from the nearest rail, then look and listen before crossing (49 CFR 392.10, as taught in the Nebraska CDL Manual). Source: Nebraska CDL Manual / 49 CFR 392.10.","handbook":"","hbref":""},{"q":"After stopping at a railroad crossing, a CDL driver in Nebraska begins to cross the tracks. What does the rule require regarding gear changes?","options":["Downshift once while on the tracks to maintain control","Cross in a gear that lets you finish without shifting; do not change gears while on the tracks","Shift to neutral while crossing to reduce engine strain","Shift up to the highest gear before reaching the rails"],"answer":1,"explanation":"The Nebraska CDL Manual and 49 CFR 392.10-392.11 require crossing in a gear that allows you to complete the crossing without changing gears; you must not shift gears while any part of the vehicle is on the tracks. Source: Nebraska CDL Manual / 49 CFR 392.10-392.11.","handbook":"","hbref":""},{"q":"When are placarded HazMat vehicles and passenger buses in Nebraska NOT required to stop at a railroad grade crossing?","options":["Whenever traffic behind them is heavy","At a crossing controlled by a functioning highway traffic signal showing green, or marked with an 'Exempt' sign","At any crossing in a residential district","Only on gravel roads"],"answer":1,"explanation":"Under 49 CFR 392.10 (taught in the Nebraska CDL Manual), the stop requirement does not apply at, among others, a crossing controlled by a functioning highway traffic signal showing green, a streetcar/spur crossing, or an industrial/spur grade crossing marked with an 'Exempt' sign. Source: Nebraska CDL Manual / 49 CFR 392.10.","handbook":"","hbref":""},{"q":"When meeting or overtaking a stopped Nebraska school bus with its flashing red lights on and stop arm extended, what must other drivers do (where no exception applies)?","options":["Slow to 25 mph and pass with caution","Come to a complete stop and remain stopped until the red lights are off, the stop arm is retracted, and the bus moves again","Stop only if children are visible crossing the road","Merge left and continue past the bus"],"answer":1,"explanation":"Neb. Rev. Stat. 60-6,175 requires a complete stop when a school bus is stopped with the stop signal arm extended and flashing red lights on, and the driver must remain stopped until the red lights are off, the arm is retracted, and the bus resumes motion. Source: Neb. Rev. Stat. 60-6,175.","handbook":"","hbref":""},{"q":"Nebraska law requires drivers to do what when a school bus first activates its YELLOW (amber) warning signal lights, before the red lights come on?","options":["Stop immediately, even before the red lights activate","Reduce speed to no more than 25 mph and prepare to stop","Maintain speed until the red lights flash","Reduce speed to no more than 40 mph"],"answer":1,"explanation":"Neb. Rev. Stat. 60-6,175 requires a driver meeting or overtaking a school bus flashing its yellow warning lights to reduce speed to not more than 25 mph and be prepared to bring the vehicle to a complete stop. Source: Neb. Rev. Stat. 60-6,175.","handbook":"","hbref":""},{"q":"Under Nebraska's school-bus stopping law, which divided-highway situation does NOT require an approaching driver to stop for a school bus with red lights flashing?","options":["Traffic following directly behind the bus in the same lane","Approaching traffic in the opposite direction on a divided highway","Traffic in an adjacent same-direction lane on an undivided two-lane road","Traffic approaching from a side street onto the same roadway"],"answer":1,"explanation":"Neb. Rev. Stat. 60-6,175 provides that the stop requirement does not apply to approaching traffic in the opposite direction on a divided highway (e.g., separated by a median); drivers on a different roadway of a divided highway need not stop. Vehicles following or meeting the bus on an undivided road must still stop. Source: Neb. Rev. Stat. 60-6,175.","handbook":"","hbref":""},{"q":"A CDL driver is stopped on the shoulder of a Nebraska two-lane, two-way highway for a breakdown. Within how many minutes must emergency warning devices (reflective triangles) be placed?","options":["Within 5 minutes","Within 10 minutes","Within 15 minutes","Within 30 minutes"],"answer":1,"explanation":"The Nebraska CDL Manual (following 49 CFR 392.22) requires warning devices to be placed within 10 minutes of stopping. Source: Nebraska CDL Manual / 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On a Nebraska two-lane, two-way road, where should a CDL driver place the three required warning triangles after stopping?","options":["About 10 ft behind, 100 ft behind, and 100 ft ahead of the vehicle","All three within 10 ft of the vehicle","At 50 ft, 150 ft, and 250 ft behind the vehicle","About 25 ft, 75 ft, and 200 ft to the rear only"],"answer":0,"explanation":"Per the Nebraska CDL Manual (49 CFR 392.22), on a two-lane two-way road place one triangle about 10 ft to the rear (traffic side), one about 100 ft to the rear, and one about 100 ft to the front of the vehicle. Source: Nebraska CDL Manual / 49 CFR 392.22.","handbook":"","hbref":""},{"q":"In Nebraska, what is the maximum legal width for a commercial vehicle before an oversize permit from NDOT is required?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"answer":1,"explanation":"Nebraska's legal maximum overall vehicle width is 8 feet 6 inches; anything wider requires an NDOT oversize permit (a farm-equipment daylight exception applies). Source: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska' / Neb. Rev. Stat. ch. 60.","handbook":"","hbref":""},{"q":"What is Nebraska's legal maximum overall vehicle height before a permit is required?","options":["13 feet 6 inches","14 feet 0 inches","14 feet 6 inches","15 feet 0 inches"],"answer":2,"explanation":"Nebraska's legal maximum overall height is 14 feet 6 inches. Note that operators of vehicles exceeding 12 feet 6 inches assume the risk for damage to overhead obstructions. Source: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'.","handbook":"","hbref":""},{"q":"Nebraska is distinctive in allowing a higher legal gross weight on US and State highway routes than on Interstate routes. What is the legal gross weight limit on Nebraska US and State routes (off the Interstate)?","options":["80,000 lbs","85,500 lbs","94,000 lbs","105,500 lbs"],"answer":2,"explanation":"Nebraska's legal gross weight is 80,000 lbs on Interstate-designated routes but 94,000 lbs on US and State routes (subject to axle and bridge-formula limits). Source: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'.","handbook":"","hbref":""},{"q":"What is the legal maximum gross weight for a CMV on Interstate-designated routes in Nebraska without a permit?","options":["73,280 lbs","80,000 lbs","88,000 lbs","94,000 lbs"],"answer":1,"explanation":"On Interstate-designated routes Nebraska's legal gross weight is 80,000 lbs, consistent with the federal limit, subject to single-axle (20,000 lbs), tandem-axle (34,000 lbs), and bridge-formula restrictions. Source: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'.","handbook":"","hbref":""},{"q":"Nebraska's left lane / keep-right rule (Neb. Rev. Stat. 60-6,131) requires a CMV traveling slower than normal traffic on a multilane highway to do what?","options":["Use the left lane so faster traffic can pass on the right","Drive in the right-hand lane available for traffic, using the left lane only to pass, turn left, or avoid an obstruction","Drive in the center lane at all times","Match the speed of the fastest vehicle present"],"answer":1,"explanation":"Neb. Rev. Stat. 60-6,131 requires vehicles, including CMVs, traveling slower than normal traffic to keep to the right-hand lane (or as near the right edge as practicable), reserving the left lane for passing, preparing for a left turn, or avoiding an obstruction. Source: Neb. Rev. Stat. 60-6,131.","handbook":"","hbref":""},{"q":"Which state agency issues Commercial Driver Licenses in Nebraska?","options":["The Nebraska Department of Motor Vehicles (DMV), through Driver Licensing Services","The Nebraska State Patrol","The Nebraska Department of Transportation","The Federal Motor Carrier Safety Administration"],"answer":0,"explanation":"In Nebraska, the Department of Motor Vehicles (DMV) issues CDLs through its Driver Licensing Services, and applicants apply and test at Driver Licensing Offices. Source: Nebraska DMV, CDL pages (dmv.nebraska.gov/cdl).","handbook":"","hbref":""},{"q":"Before taking the CDL skills test in Nebraska, an applicant must first obtain a Commercial Learner's Permit (CLP) and hold it for at least how long?","options":["14 days","7 days","30 days","60 days"],"answer":0,"explanation":"Nebraska requires a driver to have a valid CLP and hold it for a minimum of 14 days prior to taking the CDL skills test. This mirrors the federal CLP rule. Source: Nebraska DMV, CDL Testing page.","handbook":"","hbref":""},{"q":"The Nebraska CDL skills test is divided into which three parts?","options":["Pre-trip inspection, basic control skills, and on-road driving","Written knowledge, vision screening, and road sign identification","Coupling, backing, and air-brake bleed-down","Pre-trip inspection, hazmat handling, and night driving"],"answer":0,"explanation":"Nebraska's CDL skills examination evaluates three areas: the pre-trip inspection, basic control skills, and on-road driving. Source: Nebraska DMV, CDL Testing page.","handbook":"","hbref":""},{"q":"How long is a Commercial Learner's Permit (CLP) valid in Nebraska?","options":["1 year","180 days","90 days","5 years"],"answer":0,"explanation":"A Nebraska CLP is valid for 1 year. Source: Nebraska DMV, Commercial Learner's Permit page.","handbook":"","hbref":""},{"q":"Under Nebraska's self-certification system, which TWO categories require the driver to maintain a valid Medical Examiner's Certificate?","options":["Category A (Interstate Non-Excepted) and Category C (Intrastate Non-Excepted)","Category B (Interstate Excepted) and Category D (Intrastate Excepted)","Category A (Interstate Non-Excepted) and Category B (Interstate Excepted)","Category C (Intrastate Non-Excepted) and Category D (Intrastate Excepted)"],"answer":0,"explanation":"Drivers self-certifying as Category A (Interstate Non-Excepted) or Category C (Intrastate Non-Excepted) must have a valid medical examiner's certificate. The excepted categories (B and D) do not. Source: Nebraska DMV, CDL Documentation Requirements / Self-Certification chart.","handbook":"","hbref":""},{"q":"Effective May 19, 2025, how does Nebraska's DMV receive Medical Examiner's Certificate (MEC) information for CDL/CLP holders?","options":["Electronically from the FMCSA National Registry; drivers no longer submit paper copies to the DMV","By certified mail only, with a notarized paper copy of the medical card","In person at a Driver Licensing Office, where staff scan the paper card","By fax from the driver's employer within 10 days of the exam"],"answer":0,"explanation":"Beginning May 19, 2025, Nebraska CDL/CLP holders no longer supply the DMV with a paper copy of their MEC; the DMV receives the information electronically from FMCSA's National Registry. Source: Nebraska DMV news release on the federal Medical Examiner's Certification rule.","handbook":"","hbref":""},{"q":"What is the standard validity period of a Nebraska Commercial Driver License for a holder age 21 or older?","options":["5 years (expiring on the holder's birthday in the fifth year after issuance)","4 years","8 years","2 years"],"answer":0,"explanation":"Nebraska licenses issued to individuals 21 or older, including CDLs, expire on the holder's birthday in the fifth year after issuance (about a 5-year cycle). Source: Nebraska DMV, Renewals page.","handbook":"","hbref":""},{"q":"What is the minimum age to hold a Nebraska CDL for INTERSTATE commercial driving?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"Nebraska requires drivers to be at least 21 to operate in interstate commerce; intrastate-only CDL drivers may qualify at 18. Source: Nebraska DMV, CDL page (Class A/B/C age requirements).","handbook":"","hbref":""},{"q":"What is the minimum age to hold a Nebraska CDL for INTRASTATE-only commercial driving?","options":["18 years old","21 years old","16 years old","19 years old"],"answer":0,"explanation":"Nebraska allows a Class A, B, or C CDL at 18 for intrastate operation; interstate operation requires age 21. Source: Nebraska DMV, CDL page.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) became required in Nebraska for new CDL applicants on which date?","options":["February 7, 2022","May 19, 2025","January 1, 2020","July 1, 2021"],"answer":0,"explanation":"Beginning February 7, 2022, new CDL applicants, those upgrading class, and first-time hazmat applicants must complete ELDT before testing. Source: Nebraska DMV, CDL Testing page.","handbook":"","hbref":""},{"q":"How does the Nebraska DMV confirm that a CDL applicant has completed required Entry-Level Driver Training (ELDT)?","options":["The DMV verifies proof of ELDT electronically","The applicant mails a paper training certificate to the central DMV office","The applicant's employer signs an affidavit at the testing site","The training school faxes a roster to the local Driver Licensing Office"],"answer":0,"explanation":"Nebraska states the DMV will verify proof of ELDT completion electronically (via the FMCSA Training Provider Registry). Source: Nebraska DMV, CDL Testing page.","handbook":"","hbref":""},{"q":"Which screening must EVERY Nebraska CDL applicant pass, whether applying new, as a new resident, or renewing?","options":["A vision test","A hazardous materials knowledge test","An air-brake performance test","A drug and alcohol screening at the DMV"],"answer":0,"explanation":"A vision test is required for all CDL applicants in Nebraska, including new licenses, new residents, and renewals. Source: Nebraska DMV, CDL Testing page.","handbook":"","hbref":""},{"q":"If a Nebraska applicant fails a CDL written knowledge test or a skills test, how soon may they generally retest?","options":["After at least a one-day waiting period","Immediately, on the same day","After a 14-day waiting period","After a 30-day waiting period"],"answer":0,"explanation":"Nebraska requires at least a one-day wait before retesting when a written or skills test is failed. Source: Nebraska DMV, CDL Testing page.","handbook":"","hbref":""},{"q":"Which CDL knowledge test can NEVER be waived in Nebraska, even for a new resident transferring a valid out-of-state CDL?","options":["The hazardous materials (hazmat) knowledge test","The general knowledge test","The air-brakes knowledge test","The combination-vehicles knowledge test"],"answer":0,"explanation":"Nebraska may waive certain written tests for qualifying new residents or timely renewals, but the hazmat knowledge test cannot be waived. Source: Nebraska DMV, CDL Testing page.","handbook":"","hbref":""},{"q":"What happens to a Nebraska CLP holder's previously passed skills-test segments if the CLP expires before all three are completed?","options":["The previously passed segments become invalid and must be retaken","They remain valid for 90 more days as a grace period","They are automatically transferred to the renewed CLP","Only the on-road segment must be retaken"],"answer":0,"explanation":"In Nebraska, if a CLP expires before all three skills-test segments are completed, any previously passed tests become invalid and must be retaken. Source: Nebraska DMV, Commercial Learner's Permit page.","handbook":"","hbref":""},{"q":"Where are Nebraska CDL skills tests administered, in addition to DMV examiners?","options":["By DMV-authorized third-party testers","Only by FMCSA federal inspectors","Only by the applicant's CDL training school instructor","By any licensed CDL holder designated by the employer"],"answer":0,"explanation":"Nebraska allows DMV-authorized third-party testers to administer CDL skills tests; they must give the DMV two business days' advance notice. Source: Nebraska DMV, CDL Testing page and Third-Party Testers list.","handbook":"","hbref":""},{"q":"When applying for a Nebraska CDL or CLP, what is the rule on disclosing a Social Security number?","options":["Applicants must disclose a valid Social Security number; there is no exemption for CDL drivers","Disclosure is optional and may be replaced with a passport number","Only interstate drivers must disclose it","It is required only when adding a hazmat endorsement"],"answer":0,"explanation":"Nebraska requires CDL/CLP applicants to disclose a valid Social Security number, with no exemptions for commercial drivers. Source: Nebraska DMV, CDL Documentation Requirements.","handbook":"","hbref":""},{"q":"To prove a Nebraska principal address for a CDL application, what must the applicant provide?","options":["Two documents from different sources showing the Nebraska address; a P.O. Box is not acceptable","One utility bill, with a P.O. Box permitted","A single sworn statement of residency","A Nebraska voter registration card only"],"answer":0,"explanation":"Nebraska requires two proof-of-address documents from different sources (generally issued within 90 days); a P.O. Box is not acceptable. Source: Nebraska DMV, CDL Documentation Requirements.","handbook":"","hbref":""},{"q":"A Nebraska CDL holder who self-certifies as Category A or C risks what consequence if they fail to keep a current Medical Examiner's Certificate on the National Registry?","options":["Downgrade of their CDL/CLP commercial privileges","An automatic one-year license suspension","A mandatory retake of the on-road skills test","Conversion of the CDL to a hazmat-only license"],"answer":0,"explanation":"Non-excepted (Category A/C) drivers must maintain a current MEC, now transmitted electronically from the National Registry; failure to do so results in a downgrade of the CDL/CLP. Source: Nebraska DMV news release on the Medical Examiner's Certification rule.","handbook":"","hbref":""},{"q":"How is a Nebraska CDL skills-test appointment generally scheduled, and who must call?","options":["By appointment only, and the person actually taking the test must make the call","Walk-in only, with no appointment accepted","By the employer's safety director on the driver's behalf","Online only, with no phone option available"],"answer":0,"explanation":"Nebraska administers CDL skills tests by appointment only, and the applicant who will take the test must be the one calling to schedule. Source: Nebraska DMV, CDL Testing page.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная общая ширина, разрешённая для коммерческого транспортного средства на дорогах Небраски без специального разрешения?","options":["8 футов 6 дюймов","8 футов","9 футов","10 футов"],"explanation":"Небраска ограничивает максимальную общую ширину транспортного средства до 8 футов 6 дюймов (102 inches). Источник: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' пункт 1; в соответствии с Neb. Rev. Stat. 60-6,288."},"1":{"q":"Какова максимальная общая высота транспортного средства, разрешённая на дорогах Небраски без разрешения?","options":["14 футов 6 дюймов","13 футов 6 дюймов","14 футов","15 футов"],"explanation":"Максимальная общая высота транспортного средства в Небраске составляет 14 футов 6 дюймов. Источник: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' пункт 2."},"2":{"q":"Какова максимальная общая длина одиночного транспортного средства (не автопоезда) в Небраске?","options":["40 футов","45 футов","53 фута","35 футов"],"explanation":"Одиночное транспортное средство в Небраске может иметь общую длину не более 40 футов. Источник: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' пункт 3."},"3":{"q":"Какова максимальная разрешённая законом длина полуприцепа (без учёта седельного тягача) в Небраске?","options":["53 фута","48 футов","40 футов","57 футов"],"explanation":"Небраска допускает полуприцеп (без учёта седельного тягача) длиной до 53 футов. Источник: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' пункт 5."},"4":{"q":"Какова максимальная общая длина автопоезда (сцепки транспортных средств) в Небраске?","options":["65 футов","60 футов","75 футов","53 фута"],"explanation":"Небраска устанавливает максимальную общую длину автопоезда в 65 футов. Источник: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' пункт 4."},"5":{"q":"Какова максимальная нагрузка на одно колесо, допустимая на дороге Небраски?","options":["10,000 фунтов","12,000 фунтов","8,000 фунтов","20,000 фунтов"],"explanation":"Ни одно колесо не может нести полную нагрузку более 10,000 фунтов на любой дороге Небраски. Источник: NDOT 'Legal Sizes and Weights,' пункт 7; Neb. Rev. Stat. 60-6,294."},"6":{"q":"Какова максимальная нагрузка на одиночную ось, разрешённая на дорогах Небраски?","options":["20,000 фунтов","18,000 фунтов","22,400 фунтов","34,000 фунтов"],"explanation":"Небраска ограничивает нагрузку на одиночную ось до 20,000 фунтов. Источник: NDOT 'Legal Sizes and Weights,' пункт 8; Neb. Rev. Stat. 60-6,294."},"7":{"q":"Какова максимальная нагрузка на сдвоенную ось, допустимая на дорогах Небраски?","options":["34,000 фунтов","36,000 фунтов","40,000 фунтов","32,000 фунтов"],"explanation":"Полная масса, передаваемая через группу сдвоенных осей, не может превышать 34,000 фунтов в Небраске. Источник: NDOT 'Legal Sizes and Weights,' пункт 9; Neb. Rev. Stat. 60-6,294."},"8":{"q":"Какова максимальная полная масса транспортного средства, движущегося по маршрутам, отнесённым к системе Interstate, в Небраске без разрешения?","options":["80,000 фунтов","94,000 фунтов","84,000 фунтов","76,000 фунтов"],"explanation":"Разрешённая законом полная масса на маршрутах, отнесённых к системе Interstate, в Небраске составляет 80,000 фунтов. Источник: NDOT 'Legal Sizes and Weights,' примечание об исключениях по массе; Neb. Rev. Stat. 60-6,294."},"9":{"q":"Каков законный предел полной массы на дорогах U.S. и State (не Interstate) в Небраске?","options":["94,000 фунтов","80,000 фунтов","90,000 фунтов","100,000 фунтов"],"explanation":"Небраска допускает законную полную массу 94,000 фунтов на дорогах U.S. и State (с учётом ограничений по осям и мостовой формуле), против 80,000 фунтов на Interstate. Источник: NDOT 'Legal Sizes and Weights,' примечание об исключениях по массе."},"10":{"q":"Как Небраска определяет 'сдвоенную ось' (tandem axle) для целей ограничения массы?","options":["Две последовательные оси на расстоянии более 40 и не более 96 дюймов друг от друга","Две оси на расстоянии менее 40 дюймов друг от друга","Любые две оси в пределах 120 дюймов друг от друга","Две оси ровно на расстоянии 60 дюймов друг от друга"],"explanation":"Небраска определяет сдвоенную ось как любые две последовательные оси, центры которых находятся на расстоянии более 40 дюймов и не более 96 дюймов друг от друга. Источник: Neb. Rev. Stat. 60-6,294."},"11":{"q":"Согласно таблице массы по группам осей Небраски (федеральная мостовая формула), какова максимальная нагрузка для двух осей на расстоянии 8 футов друг от друга?","options":["34,000 фунтов","38,000 фунтов","40,000 фунтов","36,000 фунтов"],"explanation":"Таблица Небраски 'Maximum Load on Any Group of Two or More Axles' показывает 34,000 фунтов для двух осей на расстоянии 8 футов друг от друга. Источник: NDOT 'Legal Sizes and Weights' таблица групп осей; Neb. Rev. Stat. 60-6,294."},"12":{"q":"Согласно таблице массы по группам осей Небраски, какова максимальная нагрузка на пять осей на расстоянии 51 фут (между крайними осями)?","options":["80,000 фунтов","76,000 фунтов","84,000 фунтов","78,000 фунтов"],"explanation":"Таблица мостовой формулы Небраски указывает 80,000 фунтов для пяти осей на расстоянии 51 фут между крайними осями. Источник: NDOT 'Legal Sizes and Weights' таблица групп осей; Neb. Rev. Stat. 60-6,294."},"13":{"q":"Что определяет максимальную нагрузку, которую может нести группа из двух или более осей на дорогах Небраски?","options":["Расстояние между крайними осями группы согласно таблице мостовой формулы","Только количество шин на транспортном средстве","Мощность двигателя","Только ширина прицепа"],"explanation":"Небраска ограничивает нагрузку на любую группу осей на основе расстояния между крайними осями группы, применяя федеральную таблицу мостовой формулы. Источник: NDOT 'Legal Sizes and Weights'; Neb. Rev. Stat. 60-6,294."},"14":{"q":"Какое ведомство выдаёт разрешения на негабаритный/сверхтяжёлый груз для движения по дорогам штата Небраска?","options":["Nebraska Department of Transportation (NDOT)","Nebraska Department of Motor Vehicles","Nebraska State Patrol","Управление шерифа округа"],"explanation":"Nebraska Department of Transportation (NDOT) выдаёт разрешения на негабаритный/сверхтяжёлый груз для дорог штата; DMV направляет заявителей в NDOT. Источник: Nebraska DMV FAQ; NDOT Permits / Automated Truck Permit System."},"15":{"q":"Каким образом перевозчик чаще всего может получить разрешение на негабаритный/сверхтяжёлый груз от DOT Небраски?","options":["Через онлайн-систему NDOT Automated Truck Permit System","Отправив бумажную форму по почте в DMV","Позвонив в местное отделение полиции","Разрешения нельзя получить заранее"],"explanation":"Разрешения на негабаритный/сверхтяжёлый груз в Небраске получают через онлайн-систему NDOT Automated Truck Permit System (dottruckpermits.nebraska.gov). Источник: NDOT Permits; Nebraska DMV FAQ."},"16":{"q":"Когда требуется разрешение на негабаритный или сверхтяжёлый груз для движения по дорогам Небраски?","options":["Когда транспортное средство или груз превышает законные максимальные пределы по размеру или массе","Только при пересечении границы другого штата","Только на гравийных дорогах","Только для транспортных средств, перевозящих опасные материалы"],"explanation":"Специальное разрешение NDOT требуется для перемещения транспортного средства или груза, превышающего законные максимальные размеры или массу; разрешение не выдаётся на груз, который можно уменьшить или разобрать без больших затруднений. Источник: NDOT 'Legal Sizes and Weights' (Excess Size or Weight); Neb. Rev. Stat. 60-6,294."},"17":{"q":"При какой высоте в Небраске водитель принимает на себя риск убытков и ответственность за столкновение с надземными препятствиями?","options":["Свыше 12 футов 6 дюймов","Свыше 13 футов 6 дюймов","Свыше 14 футов 6 дюймов","Свыше 11 футов"],"explanation":"Закон Небраски предусматривает, что владельцы/водители транспортного средства высотой более 12 футов 6 дюймов принимают на себя риск и несут ответственность за ущерб надземным препятствиям. Источник: NDOT 'Legal Sizes and Weights,' исключение по высоте."},"18":{"q":"Какое специальное исключение Небраска предоставляет из ограничения ширины в 8 футов 6 дюймов?","options":["Сельскохозяйственная техника, перемещаемая в светлое время суток в ходе обычных сельскохозяйственных работ","Любой бортовой прицеп, перевозящий сталь","Все рефрижераторные прицепы","Транспортные средства, зарегистрированные в другом штате"],"explanation":"Ограничение ширины Небраски в 8'6\" не применяется к сельскохозяйственной технике при временном перемещении в светлое время суток в ходе обычных сельскохозяйственных работ. Источник: NDOT 'Legal Sizes and Weights,' исключение по ширине."},"19":{"q":"Согласно установленным законом правилам Небраски о массе, что происходит, если грузовик пересекает мост с полной нагрузкой, превышающей указанную грузоподъёмность моста, и причиняет ущерб?","options":["Владелец транспортного средства несёт ответственность за весь ущерб","Ответственность делится поровну с NDOT","Ответственности нет, если было приобретено разрешение","Ответственность несёт только водитель, но не владелец"],"explanation":"Закон Небраски возлагает на владельца грузовика ответственность за весь ущерб, возникший в результате пересечения моста с нагрузкой, превышающей его указанную грузоподъёмность. Источник: NDOT 'Legal Sizes and Weights' (положение о мостах); Neb. Rev. Stat. 60-6,294."},"20":{"q":"В Небраске какой класс CDL требуется для управления автопоездом с полной массой автопоезда (GCWR) 26,001 фунтов или более, при условии, что GVWR буксируемого узла (узлов) превышает 10,000 фунтов?","options":["Class A","Class B","Class C","Class D"],"explanation":"Небраска определяет CDL Class A как автопоезд с GCWR 26,001 фунтов или более, где буксируемый узел (узлы) имеет GVWR более 10,000 фунтов. Источник: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"21":{"q":"Согласно правилам Небраски, какой класс CDL охватывает одиночное транспортное средство с GVWR 26,001 фунтов или более (или такое транспортное средство, буксирующее узел не более 10,000 фунтов)?","options":["Class A","Class B","Class C","Class M"],"explanation":"Небраска определяет CDL Class B как одиночное транспортное средство с GVWR 26,001 фунтов или более, или любое такое транспортное средство, буксирующее узел не более 10,000 фунтов. Источник: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"22":{"q":"Водитель в Небраске управляет одиночным транспортным средством с GVWR менее 26,001 фунтов, на которое требуется размещение знаков опасных материалов (плакардов). Какой класс CDL применяется?","options":["Class A","Class B","Class C","Class O"],"explanation":"CDL Class C в Небраске охватывает одиночное транспортное средство с GVWR менее 26,001 фунтов (или буксирующее узел до 10,000 фунтов), на которое требуется размещение знаков опасных материалов (плакардов) или которое является автобусом, рассчитанным на перевозку 16 или более пассажиров, включая водителя. Источник: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"23":{"q":"Согласно определению Class C в Небраске, для автобуса требуется CDL, когда он рассчитан на перевозку какого количества пассажиров?","options":["8 или более, включая водителя","11 или более, включая водителя","16 или более, включая водителя","24 или более, включая водителя"],"explanation":"Определение Class C в Небраске включает любой автобус, рассчитанный на перевозку 16 или более пассажиров, включая водителя. Источник: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"24":{"q":"Каков минимальный возраст для выдачи коммерческих водительских прав Небраски (CDL) для внутриштатных перевозок (только в пределах Небраски)?","options":["16 лет","17 лет","18 лет","21 год"],"explanation":"Небраска не выдаёт CDL или CLP лицам, не достигшим возраста 18 лет; 18 лет — минимальный возраст для внутриштатной работы по CDL. Источник: Neb. Rev. Stat. 60-4,143; страницы Nebraska DMV CDL."},"25":{"q":"Держатель CDL Небраски хочет управлять коммерческим транспортным средством через границы штатов (межштатные перевозки). Каков минимальный возраст для этого?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Хотя Небраска выдаёт внутриштатный CDL в 18 лет, водитель должен быть не моложе 21 года, чтобы управлять коммерческим автотранспортным средством в межштатной торговле. Источник: страницы Nebraska DMV CDL; 49 CFR 391.11, применяемый как правило Небраски."},"26":{"q":"Какое подтверждение (endorsement) нужно водителю в Небраске для перевозки опасных материалов в количествах, требующих размещения плакардов?","options":["Подтверждение N","Подтверждение H","Подтверждение T","Подтверждение X"],"explanation":"Подтверждение H (Hazardous Materials) требуется для перевозки опасных материалов с плакардами; оно требует сдачи теоретического теста и проверки угрозы безопасности TSA. Источник: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"27":{"q":"Прежде чем Небраска выдаст CDL с подтверждением HazMat (H), заявитель должен пройти какой дополнительный федеральный этап проверки благонадёжности?","options":["Проверку угрозы безопасности TSA со снятием отпечатков пальцев","Собеседование по гражданским правам с FBI","Регистрацию контролируемых веществ в DEA","Проверку натурализации в USCIS"],"explanation":"Помимо сдачи теоретического теста HazMat, Небраска требует от заявителей пройти проверку угрозы безопасности Transportation Security Administration (TSA), которая включает предварительную регистрацию и снятие отпечатков пальцев, до выдачи подтверждения H. Источник: Nebraska DMV, CDL Classes, Endorsements and Restrictions; программа TSA HME."},"28":{"q":"Как часто водитель в Небраске должен продлевать подтверждение HazMat (H), включая повторное предоставление отпечатков пальцев для проверки угрозы TSA?","options":["Не реже чем каждые 2 года","Не реже чем каждые 3 года","Не реже чем каждые 5 лет","Не реже чем каждые 8 лет"],"explanation":"Подтверждение HazMat и связанная с ним проверка угрозы безопасности TSA должны продлеваться не реже чем каждые пять лет, с повторным предоставлением отпечатков пальцев при продлении. Источник: страницы Nebraska DMV CDL; программа TSA HME (49 CFR 1572)."},"29":{"q":"Какое подтверждение требуется в Небраске для управления автоцистерной, используемой для перевозки жидкостей или газов наливом?","options":["Подтверждение T","Подтверждение N","Подтверждение H","Подтверждение P"],"explanation":"Подтверждение N (Tank Vehicle) требуется для управления автоцистерной и требует сдачи теоретического теста. Источник: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"30":{"q":"Водитель в Небраске хочет буксировать сдвоенные или строенные прицепы. Какое подтверждение требуется?","options":["Подтверждение N","Подтверждение P","Подтверждение T","Подтверждение S"],"explanation":"Подтверждение T (Doubles/Triples) требуется для буксировки сдвоенных и строенных прицепов и требует сдачи теоретического теста. Источник: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"31":{"q":"Какое подтверждение должен иметь держатель CDL Небраски, чтобы управлять транспортным средством, рассчитанным на перевозку 16 или более человек, например пассажирским автобусом?","options":["Подтверждение S","Подтверждение P","Подтверждение N","Подтверждение H"],"explanation":"Подтверждение P (Passenger) требуется для транспортных средств, рассчитанных на перевозку 16 или более человек (включая водителя), и требует сдачи теоретического теста плюс практического теста на представительном транспортном средстве. Источник: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"32":{"q":"В Небраске подтверждение S (School Bus) может быть выдано только вместе с каким другим подтверждением?","options":["Подтверждением H (HazMat)","Подтверждением N (Tank)","Подтверждением P (Passenger)","Подтверждением T (Doubles/Triples)"],"explanation":"Небраска требует, чтобы подтверждение S (School Bus) сопровождало подтверждение P (Passenger); водитель не может иметь S без P. Источник: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"33":{"q":"Каков минимальный срок, в течение которого водитель в Небраске должен иметь Commercial Learner's Permit (CLP), прежде чем сдавать практический тест CDL?","options":["7 дней","10 дней","14 дней","30 дней"],"explanation":"Небраска, следуя федеральному правилу, требует, чтобы водитель имел действующий CLP минимум 14 дней, прежде чем сдавать практический тест CDL. Источник: Nebraska DMV, Commercial Learner's Permit; 49 CFR 383.25."},"34":{"q":"Сколько времени действует Commercial Learner's Permit (CLP) Небраски?","options":["180 дней","1 год","2 года","5 лет"],"explanation":"CLP Небраски действителен в течение 1 года. Если он истекает до того, как сданы все три сегмента практического теста, ранее сданные сегменты становятся недействительными, и всё практическое тестирование нужно проходить заново. Источник: Nebraska DMV, Commercial Learner's Permit."},"35":{"q":"В каких классах CDL Небраска выдаёт Commercial Learner's Permit (CLP)?","options":["Только Class A и Class B","Только Class C","Class A, B и C","Только Class B и Class C"],"explanation":"Небраска выдаёт CLP только в Class A и Class B. Источник: Nebraska DMV, Commercial Learner's Permit."},"36":{"q":"Какой набор подтверждений может иметь Commercial Learner's Permit (CLP) Небраски?","options":["H, T и X","P, S и N","Только H и N","Только T и X"],"explanation":"CLP Небраски может иметь только подтверждения P (Passenger), S (School Bus) и N (Tank, с ограничением — пустая/без груза); H, T и X не допускаются на CLP. Источник: Nebraska DMV, Commercial Learner's Permit; 49 CFR 383.25."},"37":{"q":"Сколько документов, подтверждающих основной адрес в Небраске, должен предоставить заявитель на CDL/CLP для подтверждения проживания?","options":["Один документ","Два документа из разных источников","Три документа","Подтверждение проживания не требуется"],"explanation":"Небраска требует два документа из разных источников, подтверждающих основной адрес заявителя в Небраске; абонентский ящик (P.O. Box) не принимается. Заявитель также должен предоставить подтверждение личности, номер Social Security и подтверждение гражданства U.S. или законного статуса. Источник: Nebraska DMV, CDL Documentation Requirements."},"38":{"q":"Согласно федеральному требованию Небраски о начальной подготовке водителей (ELDT), где должна быть пройдена и зарегистрирована подготовка водителя?","options":["У провайдера, указанного в FMCSA Training Provider Registry","В любой частной автошколе по выбору водителя","Только через стажировку на рабочем месте","На экзаменационной станции Nebraska DMV"],"explanation":"ELDT, вступившее в силу 7 февраля 2022 года, требует, чтобы впервые подающие заявление на Class A/B, при повышении с B до A, а также впервые подающие заявление на подтверждения P, S или H прошли подготовку у провайдера, указанного в FMCSA Training Provider Registry, который регистрирует её завершение. Источник: Nebraska DMV, Entry Level Driver Training (ELDT); 49 CFR Part 380."},"39":{"q":"Какая категория медицинской самосертификации CDL Небраски применяется к водителю, который работает в межштатной торговле И подпадает под федеральные медицинские требования (DOT physical)?","options":["Interstate Non-Excepted (Category A)","Interstate Excepted (Category B)","Intrastate Non-Excepted (Category C)","Intrastate Excepted (Category D)"],"explanation":"Category A, Interstate Non-Excepted, применяется к водителям, подпадающим под федеральные медицинские требования и требования к зрению; они должны предоставить и поддерживать действующий сертификат медицинского эксперта от провайдера из National Registry, хранящийся в DMV. Источник: Nebraska DMV, CDL Self-Certification Categories; Neb. Rev. Stat. 60-4,144.01."},"40":{"q":"При управлении коммерческим автотранспортным средством (CMV) в Небраске, при какой концентрации алкоголя в крови (BAC) водитель считается управляющим в состоянии опьянения и совершающим серьёзное (major) дисквалифицирующее нарушение?","options":["0.02 или выше","0.04 или выше","0.08 или выше","0.10 или выше"],"explanation":"Небраска, следуя 49 CFR 383.51 и Nebraska CDL Manual, делает управление CMV с BAC 0.04 или выше серьёзным (major) дисквалифицирующим нарушением. Предел 0.08 применяется к некоммерческим транспортным средствам. Источник: страница Nebraska DMV CDL Disqualification; Nebraska CDL Manual."},"41":{"q":"Согласно закону Небраски о подразумеваемом согласии, каковы последствия отказа держателя CDL от химического анализа (дыхания, крови или мочи) после управления автотранспортным средством?","options":["Только письменное предупреждение, без дисквалификации","Это рассматривается как серьёзное (major) нарушение, дисквалифицирующее CDL так же, как осуждение за DUI","30-дневное приостановление, не затрагивающее CDL","Административный штраф $100 без действий в отношении прав"],"explanation":"Закон Небраски о подразумеваемом согласии рассматривает отказ от анализа на алкоголь/наркотики как серьёзное (major) дисквалифицирующее нарушение, влекущее ту же дисквалификацию CDL, что и DUI (1 год за первое нарушение, пожизненно за второе). Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"42":{"q":"В Небраске на какой срок дисквалифицируется держатель CDL за ПЕРВОЕ серьёзное (major) нарушение (например, DUI или отказ от анализа), когда он НЕ перевозит опасные материалы с плакардами?","options":["60 дней","6 месяцев","1 год","3 года"],"explanation":"Первое серьёзное (major) нарушение дисквалифицирует держателя CDL Небраски на 1 год. Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"43":{"q":"Если водитель в Небраске совершает первое серьёзное (major) нарушение при управлении CMV, на котором требуется размещение плакардов опасных материалов, на какой срок производится дисквалификация?","options":["1 год","2 года","3 года","Пожизненно"],"explanation":"Первое серьёзное (major) нарушение при перевозке опасных материалов с плакардами увеличивает дисквалификацию с 1 года до 3 лет. Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"44":{"q":"Каков срок дисквалификации для держателя CDL Небраски, осуждённого за ВТОРОЕ серьёзное (major) нарушение?","options":["3 года","5 лет","10 лет","Пожизненно"],"explanation":"Второе серьёзное (major) нарушение влечёт пожизненную дисквалификацию CDL в Небраске. Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"45":{"q":"Что из перечисленного классифицируется как серьёзное (major) дисквалифицирующее нарушение для держателя CDL Небраски, а не как серьёзное нарушение ПДД (serious traffic violation)?","options":["Слишком близкое следование за другим транспортным средством","Оставление места ДТП","Неправильная или беспорядочная смена полос","Превышение скорости на 15 mph или более сверх предела"],"explanation":"Оставление места ДТП является серьёзным (major) нарушением (дисквалификация на 1 год/пожизненно). Слишком близкое следование, беспорядочная смена полос и чрезмерное превышение скорости являются серьёзными нарушениями ПДД (serious traffic violations) (60/120 дней). Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"46":{"q":"Насколько выше установленного предела скорости должен ехать держатель CDL Небраски, чтобы это засчиталось как серьёзное нарушение ПДД 'чрезмерное превышение скорости' (excessive speeding)?","options":["На 10 mph или более","На 15 mph или более","На 20 mph или более","На 25 mph или более"],"explanation":"Превышение скорости на 15 mph или более сверх установленного предела является серьёзным нарушением ПДД 'чрезмерное превышение скорости' (excessive speeding) в Небраске. Источник: Nebraska CDL Manual; страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"47":{"q":"В Небраске на какой срок дисквалифицируется держатель CDL за осуждение за ДВА серьёзных нарушения ПДД в отдельных случаях в течение 3-летнего периода?","options":["30 дней","60 дней","120 дней","1 год"],"explanation":"Два серьёзных нарушения ПДД в течение 3 лет влекут 60-дневную дисквалификацию CDL. Источник: страница Nebraska DMV CDL Disqualification / MCSIA; 49 CFR 383.51."},"48":{"q":"На какой срок дисквалифицируется держатель CDL Небраски за совершение ТРЁХ серьёзных нарушений ПДД в отдельных случаях в течение 3-летнего периода?","options":["60 дней","90 дней","120 дней","180 дней"],"explanation":"Три серьёзных нарушения ПДД в течение 3 лет влекут 120-дневную дисквалификацию CDL (которая должна следовать за любой уже наложенной 60-дневной дисквалификацией). Источник: страница Nebraska DMV MCSIA; 49 CFR 383.51."},"49":{"q":"Что из перечисленного входит в список СЕРЬЁЗНЫХ нарушений ПДД (serious traffic violations) для держателей CDL в Небраске?","options":["Управление с BAC 0.04 или выше","Набор текстовых сообщений за рулём CMV","Отказ от химического анализа","Использование CMV для совершения тяжкого преступления (felony)"],"explanation":"Набор текстовых сообщений за рулём CMV является серьёзным нарушением ПДД в Небраске. Три остальных перечисленных являются серьёзными (major) нарушениями. Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"50":{"q":"Управление CMV без надлежащего класса CDL или требуемого подтверждения для управляемого транспортного средства классифицируется в Небраске как какой вид нарушения?","options":["Незначительное нарушение по оборудованию","Серьёзное нарушение ПДД (serious traffic violation)","Серьёзное (major) дисквалифицирующее нарушение","Нарушение предписания о выводе из эксплуатации (out-of-service order)"],"explanation":"Управление CMV без надлежащего класса CDL или подтверждения является одним из серьёзных нарушений ПДД Небраски, влекущим дисквалификацию на 60 дней/120 дней при повторном совершении. Источник: страница Nebraska DMV MCSIA; 49 CFR 383.51."},"51":{"q":"За ПЕРВОЕ осуждение за нарушение на железнодорожном переезде на какой срок дисквалифицируется держатель CDL Небраски?","options":["Не менее 30 дней","Не менее 60 дней","Не менее 120 дней","Не менее 1 года"],"explanation":"Первое нарушение на железнодорожном переезде влечёт дисквалификацию не менее чем на 60 дней. Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"52":{"q":"Каков срок дисквалификации для держателя CDL Небраски за ВТОРОЕ нарушение на железнодорожном переезде в течение 3-летнего периода?","options":["Не менее 60 дней","Не менее 90 дней","Не менее 120 дней","Не менее 1 года"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет влечёт дисквалификацию не менее чем на 120 дней. Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"53":{"q":"Какова дисквалификация за ТРЕТЬЕ нарушение на железнодорожном переезде в течение 3-летнего периода в Небраске?","options":["Не менее 120 дней","Не менее 180 дней","Не менее 1 года","Не менее 3 лет"],"explanation":"Третье нарушение на железнодорожном переезде в течение 3 лет влечёт дисквалификацию не менее чем на 1 год. Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"54":{"q":"За ПЕРВОЕ осуждение за нарушение предписания о выводе из эксплуатации (out-of-service, OOS) при управлении стандартным CMV в Небраске, каков срок дисквалификации?","options":["От 30 до 60 дней","90 дней","От 180 дней до 1 года","От 2 до 5 лет"],"explanation":"Первое нарушение предписания о выводе из эксплуатации на стандартном CMV влечёт дисквалификацию от 180 дней до 1 года. Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"55":{"q":"Каков срок дисквалификации за ВТОРОЕ нарушение предписания о выводе из эксплуатации в течение 10-летнего периода при управлении стандартным CMV в Небраске?","options":["От 180 дней до 1 года","От 1 до 2 лет","От 2 до 5 лет","Пожизненно"],"explanation":"Второе нарушение предписания о выводе из эксплуатации в течение 10 лет влечёт дисквалификацию от 2 до 5 лет. Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"56":{"q":"Когда нарушение предписания о выводе из эксплуатации (out-of-service) связано с CMV, перевозящим опасные материалы, требующие плакардов, или рассчитанным на перевозку 16 или более пассажиров, какова дисквалификация за ПЕРВОЕ осуждение в Небраске?","options":["От 90 дней до 1 года","От 180 дней до 2 лет","От 2 до 5 лет","От 3 до 5 лет"],"explanation":"Первое нарушение предписания о выводе из эксплуатации, связанное с hazmat с плакардами или транспортным средством, рассчитанным на 16+ пассажиров, влечёт повышенную дисквалификацию от 180 дней до 2 лет. Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"57":{"q":"Управление CMV в то время, когда ваш CDL приостановлен, отозван, или когда вы дисквалифицированы, рассматривается Небраской как какой вид нарушения?","options":["Серьёзное нарушение ПДД (60/120 дней)","Серьёзное (major) дисквалифицирующее нарушение (1 год/пожизненно)","Нарушение предписания о выводе из эксплуатации (180 дней)","Недисквалифицирующее нарушение по документам"],"explanation":"Управление CMV в то время, когда CDL отозван, приостановлен, аннулирован, или когда лицо дисквалифицировано, является серьёзным (major) нарушением, влекущим дисквалификацию на 1 год за первое нарушение и пожизненно за второе. Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"58":{"q":"Согласно закону Небраски (Neb. Rev. Stat. 60-6,179.01), каков штраф за ПЕРВОЕ нарушение, связанное с набором текстовых сообщений за рулём?","options":["$100","$200","$300","$500"],"explanation":"Закон Небраски против набора текстовых сообщений (Neb. Rev. Stat. 60-6,179.01) устанавливает штраф $200 за первое нарушение, $300 за второе и $500 за третье или последующее нарушение, плюс три штрафных балла. Для водителей CDL повторный набор текстовых сообщений в CMV также является серьёзным нарушением ПДД. Источник: Neb. Rev. Stat. 60-6,179.01."},"59":{"q":"Использование CMV при совершении тяжкого преступления (felony), связанного с производством, распространением или сбытом контролируемого вещества, влечёт какое наказание для держателя CDL Небраски?","options":["1-летнюю дисквалификацию","3-летнюю дисквалификацию","5-летнюю дисквалификацию","Пожизненную дисквалификацию без права восстановления"],"explanation":"Использование любого автотранспортного средства для совершения тяжкого преступления (felony), связанного с производством, распространением или сбытом контролируемого вещества, влечёт пожизненную дисквалификацию, не подлежащую 10-летнему восстановлению, доступному для некоторых других пожизненных случаев. Источник: страница Nebraska DMV CDL Disqualification; 49 CFR 383.51."},"60":{"q":"На автомагистрали в Небраске на обочине стоит эвакуатор с включёнными мигающими жёлтыми огнями. Вы ведёте коммерческое транспортное средство (CMV) в правой полосе, и слева от вас есть свободная полоса. Что вы обязаны сделать согласно закону Небраски «Move Over»?","options":["Перестроиться в полосу, отделённую от стоящего транспортного средства не менее чем одной полосой движения, когда это безопасно","Сохранять скорость, но подать звуковой сигнал при проезде","Полностью остановиться, пока эвакуатор не уедет","Продолжать движение в правой полосе, пока ваша скорость не превышает разрешённый предел"],"explanation":"Закон Небраски «Move Over» (Neb. Rev. Stat. 60-6,378.01) требует, чтобы водители, приближающиеся к стоящему транспортному средству с мигающими огнями, снижали скорость и, когда это безопасно, перестраивались в полосу, отделённую от стоящего транспортного средства не менее чем одной полосой движения. Источник: Neb. Rev. Stat. 60-6,378.01 / NDOT «Move Over, Slow Down»."},"61":{"q":"Закон Небраски «Move Over» был существенно расширен законом LB 530, вступившим в силу 3 сентября 2025 года. После этого изменения водители обязаны снижать скорость и перестраиваться при приближении к чему из перечисленного?","options":["Только к специальным транспортным средствам экстренных служб с мигающими красными или синими огнями","Только к эвакуаторам и транспортным средствам дорожного обслуживания","Ко всем стоящим транспортным средствам и уязвимым участникам дорожного движения на обочине автомагистрали, включая пешеходов, велосипедистов и сельскохозяйственную технику","Только к транспортным средствам, остановившимся в действующей зоне дорожных работ"],"explanation":"Согласно LB 530 (вступил в силу 3 сентября 2025 года), Небраска расширила требование о перестроении за пределы транспортных средств экстренных служб и дорожной помощи — теперь оно распространяется на ВСЕ стоящие транспортные средства и уязвимых участников дорожного движения на обочине автомагистрали, включая пешеходов, велосипедистов, людей на пешеходных переходах, а также сельскохозяйственные транспортные средства и технику. Источник: Neb. LB 530 / пресс-релиз NDOT «Nebraska's Updated Move-Over Law Takes Effect Sept. 3»."},"62":{"q":"Согласно закону Небраски «Move Over», что вы обязаны сделать, если не можете безопасно сменить полосу при приближении к стоящему транспортному средству с включёнными предупредительными огнями?","options":["Полностью остановиться на проезжей части, пока движение не освободится","Снизить скорость, поддерживать безопасную для условий скорость и продолжать движение с надлежащей осторожностью и вниманием","Сохранять установленную разрешённую скорость и проезжать как обычно","Разогнаться, чтобы как можно быстрее покинуть этот участок"],"explanation":"Neb. Rev. Stat. 60-6,378.01 предусматривает, что если смена полосы невозможна или небезопасна, водитель обязан снизить скорость, поддерживать безопасную скорость с учётом стоящего транспортного средства, погодных, дорожных условий и условий движения, и продолжать движение с надлежащей осторожностью и вниманием. Источник: Neb. Rev. Stat. 60-6,378.01."},"63":{"q":"Каков максимальный предел скорости для грузового коммерческого автомобиля на сельском участке Национальной системы межштатных автомагистралей (Interstate) в Небраске, если иное не указано на знаках?","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"Neb. Rev. Stat. 60-6,186 устанавливает максимальную скорость 75 mph на сельских межштатных автомагистралях. В Небраске нет отдельного, более низкого установленного законом предела скорости для грузовиков; CMV подчиняются тем же максимальным значениям на знаках, что и другие транспортные средства. Источник: Neb. Rev. Stat. 60-6,186 / информация NDOT о пределах скорости."},"64":{"q":"Каков максимальный предел скорости на скоростной автомагистрали (expressway) или «супердвухполосной» (super-two) автодороге в Небраске, входящей в систему дорог штата, если иное не указано на знаках?","options":["55 mph","65 mph","70 mph","75 mph"],"explanation":"Neb. Rev. Stat. 60-6,186 устанавливает 70 mph на скоростной автомагистрали (expressway), «супердвухполосной» (super-two) дороге или фривее, входящих в систему дорог штата. (На сельских межштатных автомагистралях — 75 mph; на прочих дорогах штата — 65 mph.) Источник: Neb. Rev. Stat. 60-6,186 / брошюра NDOT о пределах скорости."},"65":{"q":"Устанавливает ли законодательство Небраски отдельный, более низкий максимальный установленный законом предел скорости для грузовых коммерческих автомобилей по сравнению с легковыми автомобилями?","options":["Да, грузовики ограничены 65 mph по всему штату","Да, грузовики должны двигаться на 10 mph ниже установленного предела","Нет, установленные законом максимальные пределы скорости в Neb. Rev. Stat. 60-6,186 единообразно применяются ко всем транспортным средствам","Да, но только на системе межштатных автомагистралей"],"explanation":"Neb. Rev. Stat. 60-6,186 устанавливает единообразные законные максимальные скорости по категориям дорог без отдельного предела скорости для грузовиков; коммерческие транспортные средства обязаны соблюдать те же максимальные значения на знаках, что и остальной поток. Источник: Neb. Rev. Stat. 60-6,186."},"66":{"q":"Каков максимальный предел скорости на дороге системы штата Небраска, которая НЕ является скоростной автомагистралью (expressway), «супердвухполосной» (super-two) или фривеем, если иное не указано на знаках?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Neb. Rev. Stat. 60-6,186 устанавливает 65 mph на любой части системы дорог штата, кроме скоростной автомагистрали (expressway), «супердвухполосной» (super-two) дороги или фривея. Источник: Neb. Rev. Stat. 60-6,186 / брошюра NDOT о пределах скорости."},"67":{"q":"Автобус с пассажирами или транспортное средство с табличками об опасных грузах приближается к железнодорожному переезду в одном уровне в Небраске. В пределах какого расстояния от ближайшего рельса водитель обязан остановиться?","options":["Между 5 и 25 футами","Между 15 и 50 футами","Между 25 и 75 футами","Между 50 и 100 футами"],"explanation":"Автобусы с пассажирами и CMV с табличками HazMat обязаны остановиться на расстоянии между 15 и 50 футами от ближайшего рельса, затем посмотреть и прислушаться перед пересечением (49 CFR 392.10, как изложено в руководстве Nebraska CDL Manual). Источник: Nebraska CDL Manual / 49 CFR 392.10."},"68":{"q":"После остановки на железнодорожном переезде водитель с правами CDL в Небраске начинает пересекать пути. Что требует правило в отношении переключения передач?","options":["Понизить передачу один раз на путях для сохранения контроля","Пересекать на такой передаче, которая позволяет завершить проезд без переключения; не переключать передачи, находясь на путях","Перейти на нейтраль во время пересечения, чтобы снизить нагрузку на двигатель","Перейти на высшую передачу перед тем, как достичь рельсов"],"explanation":"Руководство Nebraska CDL Manual и 49 CFR 392.10-392.11 требуют пересекать переезд на такой передаче, которая позволяет завершить проезд без переключения; нельзя переключать передачи, пока какая-либо часть транспортного средства находится на путях. Источник: Nebraska CDL Manual / 49 CFR 392.10-392.11."},"69":{"q":"В каких случаях транспортные средства с табличками об опасных грузах и пассажирские автобусы в Небраске НЕ обязаны останавливаться на железнодорожном переезде в одном уровне?","options":["Всякий раз, когда движение позади них плотное","На переезде, регулируемом исправным дорожным светофором с зелёным сигналом, или обозначенном знаком «Exempt»","На любом переезде в жилом районе","Только на гравийных дорогах"],"explanation":"Согласно 49 CFR 392.10 (как изложено в руководстве Nebraska CDL Manual), требование об остановке не применяется, в частности, на переезде, регулируемом исправным дорожным светофором с зелёным сигналом, на переезде трамвайной/тупиковой ветки, а также на промышленном/тупиковом переезде в одном уровне, обозначенном знаком «Exempt». Источник: Nebraska CDL Manual / 49 CFR 392.10."},"70":{"q":"Что обязаны делать другие водители при встрече или обгоне остановившегося в Небраске школьного автобуса с включёнными мигающими красными огнями и выдвинутым знаком «STOP» (там, где не действует исключение)?","options":["Снизить скорость до 25 mph и проехать с осторожностью","Полностью остановиться и оставаться на месте, пока красные огни не погаснут, знак «STOP» не уберётся, а автобус снова не тронется","Останавливаться только если видно, что дети переходят дорогу","Перестроиться влево и продолжить движение мимо автобуса"],"explanation":"Neb. Rev. Stat. 60-6,175 требует полной остановки, когда школьный автобус остановился с выдвинутым знаком «STOP» и включёнными мигающими красными огнями, и водитель обязан оставаться на месте, пока красные огни не погаснут, знак не уберётся, а автобус не возобновит движение. Источник: Neb. Rev. Stat. 60-6,175."},"71":{"q":"Что требует законодательство Небраски от водителей, когда школьный автобус впервые включает ЖЁЛТЫЕ (янтарные) предупредительные сигнальные огни, до того как загорятся красные?","options":["Немедленно остановиться, даже до включения красных огней","Снизить скорость не более чем до 25 mph и приготовиться к остановке","Сохранять скорость, пока не замигают красные огни","Снизить скорость не более чем до 40 mph"],"explanation":"Neb. Rev. Stat. 60-6,175 требует, чтобы водитель, встречающий или обгоняющий школьный автобус с мигающими жёлтыми предупредительными огнями, снизил скорость не более чем до 25 mph и был готов полностью остановить транспортное средство. Источник: Neb. Rev. Stat. 60-6,175."},"72":{"q":"Согласно закону Небраски об остановке для школьных автобусов, в какой ситуации на разделённой автодороге приближающийся водитель НЕ обязан останавливаться для школьного автобуса с мигающими красными огнями?","options":["Движение непосредственно позади автобуса в той же полосе","Встречное движение в противоположном направлении на разделённой автодороге","Движение в соседней полосе того же направления на неразделённой двухполосной дороге","Движение, выезжающее с боковой улицы на ту же проезжую часть"],"explanation":"Neb. Rev. Stat. 60-6,175 предусматривает, что требование об остановке не применяется к встречному движению в противоположном направлении на разделённой автодороге (например, разделённой полосой-разделителем); водители на другой проезжей части разделённой автодороги останавливаться не обязаны. Транспортные средства, следующие за автобусом или встречающие его на неразделённой дороге, всё равно обязаны остановиться. Источник: Neb. Rev. Stat. 60-6,175."},"73":{"q":"Водитель с правами CDL остановился на обочине двухполосной двусторонней автодороги в Небраске из-за поломки. В течение скольких минут должны быть выставлены аварийные предупредительные устройства (светоотражающие треугольники)?","options":["В течение 5 минут","В течение 10 минут","В течение 15 минут","В течение 30 минут"],"explanation":"Руководство Nebraska CDL Manual (в соответствии с 49 CFR 392.22) требует выставить предупредительные устройства в течение 10 минут после остановки. Источник: Nebraska CDL Manual / 49 CFR 392.22."},"74":{"q":"На двухполосной двусторонней дороге в Небраске, где водитель с правами CDL должен разместить три обязательных предупредительных треугольника после остановки?","options":["Примерно в 10 футах позади, в 100 футах позади и в 100 футах впереди транспортного средства","Все три в пределах 10 футов от транспортного средства","В 50 футах, 150 футах и 250 футах позади транспортного средства","Примерно в 25 футах, 75 футах и 200 футах только сзади"],"explanation":"Согласно руководству Nebraska CDL Manual (49 CFR 392.22), на двухполосной двусторонней дороге следует разместить один треугольник примерно в 10 футах сзади (со стороны движения), один примерно в 100 футах сзади и один примерно в 100 футах спереди транспортного средства. Источник: Nebraska CDL Manual / 49 CFR 392.22."},"75":{"q":"Какова максимально допустимая по закону ширина коммерческого транспортного средства в Небраске, прежде чем потребуется разрешение на негабарит от NDOT?","options":["8 футов 0 дюймов","8 футов 6 дюймов","9 футов 0 дюймов","10 футов 0 дюймов"],"explanation":"Законная максимальная общая ширина транспортного средства в Небраске составляет 8 футов 6 дюймов; всё, что шире, требует разрешения на негабарит от NDOT (действует исключение для сельхозтехники при движении в светлое время суток). Источник: NDOT «Legal Sizes and Weights for Vehicles in Nebraska» / Neb. Rev. Stat. ch. 60."},"76":{"q":"Какова законная максимальная общая высота транспортного средства в Небраске, прежде чем потребуется разрешение?","options":["13 футов 6 дюймов","14 футов 0 дюймов","14 футов 6 дюймов","15 футов 0 дюймов"],"explanation":"Законная максимальная общая высота в Небраске составляет 14 футов 6 дюймов. Обратите внимание, что водители транспортных средств высотой более 12 футов 6 дюймов берут на себя риск ущерба от столкновения с надземными препятствиями. Источник: NDOT «Legal Sizes and Weights for Vehicles in Nebraska»."},"77":{"q":"Небраска выделяется тем, что допускает более высокую законную полную массу на дорогах системы US и системы штата, чем на межштатных автомагистралях (Interstate). Каков предел законной полной массы на дорогах US и штата в Небраске (вне Interstate)?","options":["80,000 lbs","85,500 lbs","94,000 lbs","105,500 lbs"],"explanation":"Законная полная масса в Небраске составляет 80,000 lbs на маршрутах, отнесённых к Interstate, но 94,000 lbs на дорогах US и штата (с учётом ограничений по осям и формуле мостовых нагрузок). Источник: NDOT «Legal Sizes and Weights for Vehicles in Nebraska»."},"78":{"q":"Какова законная максимальная полная масса CMV на маршрутах, отнесённых к Interstate, в Небраске без разрешения?","options":["73,280 lbs","80,000 lbs","88,000 lbs","94,000 lbs"],"explanation":"На маршрутах, отнесённых к Interstate, законная полная масса в Небраске составляет 80,000 lbs, что соответствует федеральному пределу, с учётом ограничений по одиночной оси (20,000 lbs), сдвоенной оси (34,000 lbs) и формуле мостовых нагрузок. Источник: NDOT «Legal Sizes and Weights for Vehicles in Nebraska»."},"79":{"q":"Правило Небраски о левой полосе / движении по правой стороне (Neb. Rev. Stat. 60-6,131) требует от CMV, движущегося медленнее обычного потока на многополосной автодороге, делать что?","options":["Использовать левую полосу, чтобы более быстрый поток мог обгонять справа","Двигаться по правой полосе, доступной для движения, используя левую полосу только для обгона, поворота налево или объезда препятствия","Двигаться по центральной полосе всё время","Подстраиваться под скорость самого быстрого присутствующего транспортного средства"],"explanation":"Neb. Rev. Stat. 60-6,131 требует, чтобы транспортные средства, включая CMV, движущиеся медленнее обычного потока, держались правой полосы (или как можно ближе к правому краю), оставляя левую полосу для обгона, подготовки к повороту налево или объезда препятствия. Источник: Neb. Rev. Stat. 60-6,131."},"80":{"q":"Какое ведомство штата выдаёт коммерческие водительские удостоверения (CDL) в Небраске?","options":["Департамент транспортных средств Небраски (Nebraska DMV) через службу Driver Licensing Services","Полиция штата Небраска (Nebraska State Patrol)","Департамент транспорта Небраски (Nebraska Department of Transportation)","Федеральное управление безопасности автоперевозчиков (Federal Motor Carrier Safety Administration)"],"explanation":"В Небраске Департамент транспортных средств (DMV) выдаёт CDL через свою службу Driver Licensing Services, и заявители подают документы и сдают экзамены в офисах Driver Licensing Offices. Источник: Nebraska DMV, страницы CDL (dmv.nebraska.gov/cdl)."},"81":{"q":"Прежде чем сдавать экзамен по навыкам вождения CDL в Небраске, заявитель должен сначала получить коммерческое ученическое разрешение (CLP) и владеть им не менее какого срока?","options":["14 days","7 days","30 days","60 days"],"explanation":"Небраска требует, чтобы водитель имел действующее CLP и владел им минимум 14 days до сдачи экзамена по навыкам вождения CDL. Это соответствует федеральному правилу о CLP. Источник: Nebraska DMV, страница CDL Testing."},"82":{"q":"На какие три части делится экзамен по навыкам вождения CDL в Небраске?","options":["Предрейсовый осмотр, базовые навыки управления и вождение по дороге","Письменный теоретический экзамен, проверка зрения и распознавание дорожных знаков","Сцепка, движение задним ходом и стравливание воздуха в тормозах","Предрейсовый осмотр, обращение с опасными грузами и ночное вождение"],"explanation":"Экзамен по навыкам вождения CDL в Небраске оценивает три области: предрейсовый осмотр, базовые навыки управления и вождение по дороге. Источник: Nebraska DMV, страница CDL Testing."},"83":{"q":"Как долго действует коммерческое ученическое разрешение (CLP) в Небраске?","options":["1 year","180 days","90 days","5 years"],"explanation":"CLP в Небраске действует 1 year. Источник: Nebraska DMV, страница Commercial Learner's Permit."},"84":{"q":"Согласно системе самосертификации Небраски, какие ДВЕ категории требуют от водителя наличия действующего медицинского заключения (Medical Examiner's Certificate)?","options":["Категория A (Interstate Non-Excepted) и Категория C (Intrastate Non-Excepted)","Категория B (Interstate Excepted) и Категория D (Intrastate Excepted)","Категория A (Interstate Non-Excepted) и Категория B (Interstate Excepted)","Категория C (Intrastate Non-Excepted) и Категория D (Intrastate Excepted)"],"explanation":"Водители, самосертифицирующиеся как Категория A (Interstate Non-Excepted) или Категория C (Intrastate Non-Excepted), должны иметь действующее медицинское заключение. Категории-исключения (B и D) этого не требуют. Источник: Nebraska DMV, CDL Documentation Requirements / таблица самосертификации."},"85":{"q":"Начиная с 19 мая 2025 года, как DMV Небраски получает информацию о медицинском заключении (MEC) для держателей CDL/CLP?","options":["Электронно из National Registry FMCSA; водители больше не подают бумажные копии в DMV","Только заказным письмом, с нотариально заверенной бумажной копией медицинской карты","Лично в офисе Driver Licensing Office, где сотрудники сканируют бумажную карту","По факсу от работодателя водителя в течение 10 дней после обследования"],"explanation":"Начиная с 19 мая 2025 года держатели CDL/CLP в Небраске больше не предоставляют DMV бумажную копию своего MEC; DMV получает информацию электронно из National Registry FMCSA. Источник: пресс-релиз Nebraska DMV о федеральном правиле о медицинском заключении (Medical Examiner's Certification)."},"86":{"q":"Каков стандартный срок действия коммерческого водительского удостоверения (CDL) Небраски для держателя в возрасте 21 года и старше?","options":["5 лет (истекает в день рождения держателя на пятый год после выдачи)","4 года","8 лет","2 года"],"explanation":"Удостоверения, выданные в Небраске лицам 21 года и старше, включая CDL, истекают в день рождения держателя на пятый год после выдачи (примерно 5-летний цикл). Источник: Nebraska DMV, страница Renewals."},"87":{"q":"Каков минимальный возраст для получения CDL Небраски для МЕЖШТАТНОГО (interstate) коммерческого вождения?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Небраска требует, чтобы водителям было не менее 21 года для работы в межштатном сообщении (interstate commerce); водители с CDL только для внутриштатного сообщения могут получить право с 18 лет. Источник: Nebraska DMV, страница CDL (возрастные требования для классов A/B/C)."},"88":{"q":"Каков минимальный возраст для получения CDL Небраски для коммерческого вождения ТОЛЬКО в пределах штата (intrastate)?","options":["18 лет","21 год","16 лет","19 лет"],"explanation":"Небраска допускает CDL класса A, B или C с 18 лет для внутриштатного сообщения; межштатное сообщение требует возраста 21 год. Источник: Nebraska DMV, страница CDL."},"89":{"q":"С какой даты обучение водителей начального уровня (ELDT) стало обязательным в Небраске для новых заявителей на CDL?","options":["7 февраля 2022 года","19 мая 2025 года","1 января 2020 года","1 июля 2021 года"],"explanation":"Начиная с 7 февраля 2022 года новые заявители на CDL, лица, повышающие класс, и впервые подающие заявку на эндорсмент по опасным грузам (hazmat) должны пройти ELDT до сдачи экзамена. Источник: Nebraska DMV, страница CDL Testing."},"90":{"q":"Как DMV Небраски подтверждает, что заявитель на CDL прошёл обязательное обучение водителей начального уровня (ELDT)?","options":["DMV проверяет подтверждение прохождения ELDT электронно","Заявитель отправляет бумажный сертификат об обучении почтой в центральный офис DMV","Работодатель заявителя подписывает аффидевит на месте сдачи экзамена","Учебная школа отправляет список по факсу в местный офис Driver Licensing Office"],"explanation":"Небраска указывает, что DMV проверяет подтверждение прохождения ELDT электронно (через FMCSA Training Provider Registry). Источник: Nebraska DMV, страница CDL Testing."},"91":{"q":"Какую проверку обязан пройти КАЖДЫЙ заявитель на CDL в Небраске — при подаче нового заявления, как новый житель или при продлении?","options":["Проверку зрения","Теоретический экзамен по опасным грузам","Проверку работы пневматических тормозов","Скрининг на наркотики и алкоголь в DMV"],"explanation":"Проверка зрения обязательна для всех заявителей на CDL в Небраске, включая новые удостоверения, новых жителей и продления. Источник: Nebraska DMV, страница CDL Testing."},"92":{"q":"Если заявитель в Небраске не сдал письменный теоретический экзамен или экзамен по навыкам вождения CDL, как скоро он, как правило, может пересдать?","options":["После периода ожидания не менее одного дня","Немедленно, в тот же день","После 14-дневного периода ожидания","После 30-дневного периода ожидания"],"explanation":"Небраска требует не менее одного дня ожидания перед пересдачей, если письменный экзамен или экзамен по навыкам не сдан. Источник: Nebraska DMV, страница CDL Testing."},"93":{"q":"Какой теоретический экзамен CDL НИКОГДА не может быть отменён (waived) в Небраске, даже для нового жителя, переводящего действующее CDL из другого штата?","options":["Теоретический экзамен по опасным грузам (hazmat)","Экзамен по общим знаниям","Теоретический экзамен по пневматическим тормозам","Теоретический экзамен по составным транспортным средствам"],"explanation":"Небраска может отменить некоторые письменные экзамены для соответствующих требованиям новых жителей или своевременных продлений, но теоретический экзамен по hazmat отменить нельзя. Источник: Nebraska DMV, страница CDL Testing."},"94":{"q":"Что происходит с ранее сданными частями экзамена по навыкам вождения у держателя CLP в Небраске, если CLP истекает до завершения всех трёх частей?","options":["Ранее сданные части становятся недействительными и должны быть пересданы","Они остаются действительными ещё 90 дней в качестве льготного периода","Они автоматически переносятся на продлённое CLP","Должна быть пересдана только дорожная часть"],"explanation":"В Небраске, если CLP истекает до завершения всех трёх частей экзамена по навыкам вождения, любые ранее сданные части становятся недействительными и должны быть пересданы. Источник: Nebraska DMV, страница Commercial Learner's Permit."},"95":{"q":"Кем, помимо экзаменаторов DMV, проводятся экзамены по навыкам вождения CDL в Небраске?","options":["Авторизованными DMV сторонними экзаменаторами (third-party testers)","Только федеральными инспекторами FMCSA","Только инструктором учебной школы CDL заявителя","Любым лицензированным держателем CDL, назначенным работодателем"],"explanation":"Небраска разрешает авторизованным DMV сторонним экзаменаторам (third-party testers) проводить экзамены по навыкам вождения CDL; они должны уведомить DMV за два рабочих дня. Источник: Nebraska DMV, страница CDL Testing и список Third-Party Testers."},"96":{"q":"При подаче заявления на CDL или CLP в Небраске каково правило в отношении раскрытия номера социального страхования (Social Security number)?","options":["Заявители обязаны раскрыть действующий номер социального страхования; исключений для водителей CDL нет","Раскрытие необязательно и может быть заменено номером паспорта","Раскрывать его обязаны только водители межштатного сообщения","Он требуется только при добавлении эндорсмента по hazmat"],"explanation":"Небраска требует, чтобы заявители на CDL/CLP раскрывали действующий номер социального страхования, без исключений для коммерческих водителей. Источник: Nebraska DMV, CDL Documentation Requirements."},"97":{"q":"Чтобы подтвердить основной адрес в Небраске для заявления на CDL, что должен предоставить заявитель?","options":["Два документа из разных источников, подтверждающих адрес в Небраске; абонентский ящик (P.O. Box) не принимается","Один счёт за коммунальные услуги, при этом абонентский ящик (P.O. Box) допускается","Одно заявление о месте жительства под присягой","Только карточку регистрации избирателя в Небраске"],"explanation":"Небраска требует два документа, подтверждающих адрес, из разных источников (как правило, выданных в течение 90 дней); абонентский ящик (P.O. Box) не принимается. Источник: Nebraska DMV, CDL Documentation Requirements."},"98":{"q":"Чем рискует держатель CDL в Небраске, самосертифицировавшийся как Категория A или C, если он не поддерживает актуальное медицинское заключение (Medical Examiner's Certificate) в National Registry?","options":["Понижением (downgrade) коммерческих привилегий по его CDL/CLP","Автоматическим приостановлением действия удостоверения на один год","Обязательной пересдачей дорожного экзамена по навыкам вождения","Преобразованием CDL в удостоверение только для hazmat"],"explanation":"Водители категорий без исключения (A/C) должны поддерживать актуальное MEC, которое теперь передаётся электронно из National Registry; невыполнение этого приводит к понижению (downgrade) CDL/CLP. Источник: пресс-релиз Nebraska DMV о правиле о медицинском заключении (Medical Examiner's Certification)."},"99":{"q":"Как, как правило, назначается запись на экзамен по навыкам вождения CDL в Небраске и кто должен звонить?","options":["Только по предварительной записи, и звонить должен именно тот, кто будет сдавать экзамен","Только без записи, запись не принимается","Директор по безопасности работодателя от имени водителя","Только онлайн, без возможности записи по телефону"],"explanation":"Небраска проводит экзамены по навыкам вождения CDL только по предварительной записи, и звонить для записи должен именно тот заявитель, который будет сдавать экзамен. Источник: Nebraska DMV, страница CDL Testing."}},"tr":{"0":{"q":"Nebraska karayollarında, özel bir izin olmaksızın ticari bir araç için izin verilen maksimum toplam genişlik nedir?","options":["8 fit 6 inç","8 fit","9 fit","10 fit"],"explanation":"Nebraska, maksimum toplam araç genişliğini 8 fit 6 inç (102 inç) ile sınırlar. Kaynak: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' madde 1; Neb. Rev. Stat. 60-6,288 ile uyumludur."},"1":{"q":"Nebraska karayollarında izin olmaksızın izin verilen maksimum toplam araç yüksekliği nedir?","options":["14 fit 6 inç","13 fit 6 inç","14 fit","15 fit"],"explanation":"Nebraska'nın maksimum toplam araç yüksekliği 14 fit 6 inçtir. Kaynak: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' madde 2."},"2":{"q":"Nebraska'da, tek bir araç (kombinasyon değil) için maksimum toplam uzunluk nedir?","options":["40 fit","45 fit","53 fit","35 fit"],"explanation":"Nebraska'da tek bir araç toplamda 40 fitten uzun olamaz. Kaynak: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' madde 3."},"3":{"q":"Nebraska'da bir yarı römorkun (çekici hariç) maksimum yasal uzunluğu nedir?","options":["53 fit","48 fit","40 fit","57 fit"],"explanation":"Nebraska, bir yarı römorka (çekici hariç) 53 fite kadar izin verir. Kaynak: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' madde 5."},"4":{"q":"Nebraska'da bir araç kombinasyonu için maksimum toplam uzunluk nedir?","options":["65 fit","60 fit","75 fit","53 fit"],"explanation":"Nebraska, bir araç kombinasyonu için maksimum toplam uzunluğu 65 fit olarak belirler. Kaynak: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' madde 4."},"5":{"q":"Bir Nebraska karayolunda izin verilen maksimum tek tekerlek yükü nedir?","options":["10,000 pound","12,000 pound","8,000 pound","20,000 pound"],"explanation":"Herhangi bir Nebraska karayolunda hiçbir tekerlek 10,000 pounddan fazla brüt yük taşıyamaz. Kaynak: NDOT 'Legal Sizes and Weights,' madde 7; Neb. Rev. Stat. 60-6,294."},"6":{"q":"Nebraska karayollarında izin verilen maksimum tek aks yükü nedir?","options":["20,000 pound","18,000 pound","22,400 pound","34,000 pound"],"explanation":"Nebraska, tek bir aksı 20,000 pound ile sınırlar. Kaynak: NDOT 'Legal Sizes and Weights,' madde 8; Neb. Rev. Stat. 60-6,294."},"7":{"q":"Nebraska karayollarında izin verilen maksimum tandem aks yükü nedir?","options":["34,000 pound","36,000 pound","40,000 pound","32,000 pound"],"explanation":"Nebraska'da bir tandem aks grubundan iletilen brüt ağırlık 34,000 poundu aşamaz. Kaynak: NDOT 'Legal Sizes and Weights,' madde 9; Neb. Rev. Stat. 60-6,294."},"8":{"q":"Nebraska'da izin olmaksızın Interstate olarak belirlenmiş güzergahlarda çalışan bir araç için maksimum brüt ağırlık nedir?","options":["80,000 pound","94,000 pound","84,000 pound","76,000 pound"],"explanation":"Nebraska'da Interstate olarak belirlenmiş güzergahlarda yasal brüt ağırlık 80,000 pounddur. Kaynak: NDOT 'Legal Sizes and Weights,' Ağırlık istisnaları notu; Neb. Rev. Stat. 60-6,294."},"9":{"q":"Nebraska'da U.S. ve Eyalet güzergahlarında (Interstate dışı), yasal brüt ağırlık sınırı nedir?","options":["94,000 pound","80,000 pound","90,000 pound","100,000 pound"],"explanation":"Nebraska, U.S. ve Eyalet güzergahlarında (aks ve köprü formülü sınırlarına tabi olmak üzere) 94,000 poundluk yasal brüt ağırlığa izin verir; Interstate'te ise bu 80,000 pounddur. Kaynak: NDOT 'Legal Sizes and Weights,' Ağırlık istisnaları notu."},"10":{"q":"Nebraska, ağırlık sınırı amaçları için bir 'tandem aks'ı nasıl tanımlar?","options":["Merkezleri 40 inçten fazla ve 96 inçten fazla olmayacak şekilde aralıklı iki ardışık aks","40 inçten daha yakın iki aks","Birbirinden 120 inç içinde olan herhangi iki aks","Tam olarak 60 inç aralıklı iki aks"],"explanation":"Nebraska bir tandem aksı, merkezleri 40 inçten fazla ve 96 inçten fazla olmayacak şekilde aralıklı herhangi iki ardışık aks olarak tanımlar. Kaynak: Neb. Rev. Stat. 60-6,294."},"11":{"q":"Nebraska'nın aks grubu ağırlık tablosuna (federal köprü formülü) göre, 8 fit aralıklı iki aks için maksimum yük nedir?","options":["34,000 pound","38,000 pound","40,000 pound","36,000 pound"],"explanation":"Nebraska'nın 'İki veya Daha Fazla Aks Grubuna İzin Verilen Maksimum Yük' tablosu, 8 fit aralıklı iki aks için 34,000 pound gösterir. Kaynak: NDOT 'Legal Sizes and Weights' aks grubu tablosu; Neb. Rev. Stat. 60-6,294."},"12":{"q":"Nebraska'nın aks grubu ağırlık tablosuna göre, 51 fit aralıklı (uç akslar arası) beş aks üzerindeki maksimum yük nedir?","options":["80,000 pound","76,000 pound","84,000 pound","78,000 pound"],"explanation":"Nebraska'nın köprü formülü tablosu, uç akslar arası 51 fit aralıklı beş aks için 80,000 pound listeler. Kaynak: NDOT 'Legal Sizes and Weights' aks grubu tablosu; Neb. Rev. Stat. 60-6,294."},"13":{"q":"Nebraska karayollarında iki veya daha fazla akstan oluşan bir grubun taşıyabileceği maksimum yükü ne belirler?","options":["Köprü formülü tablosuna göre grubun uç aksları arasındaki aralık mesafesi","Yalnızca araçtaki lastik sayısı","Motorun beygir gücü","Yalnızca römorkun genişliği"],"explanation":"Nebraska, herhangi bir aks grubundaki yükü, federal köprü formülü tablosunu uygulayarak grubun uç aksları arasındaki mesafeye göre sınırlar. Kaynak: NDOT 'Legal Sizes and Weights'; Neb. Rev. Stat. 60-6,294."},"14":{"q":"Nebraska eyalet karayollarında seyahat için aşırı boyut/aşırı ağırlık izinlerini hangi kurum verir?","options":["Nebraska Department of Transportation (NDOT)","Nebraska Department of Motor Vehicles","Nebraska State Patrol","İlçe şerif ofisi"],"explanation":"Nebraska Department of Transportation (NDOT), eyalet karayolları için aşırı boyut/aşırı ağırlık izinlerini verir; DMV başvuru sahiplerini NDOT'a yönlendirir. Kaynak: Nebraska DMV FAQ; NDOT Permits / Automated Truck Permit System."},"15":{"q":"Bir taşıyıcı, Nebraska'nın DOT'undan aşırı boyut/aşırı ağırlık iznini en yaygın olarak nasıl alabilir?","options":["NDOT'un çevrimiçi Automated Truck Permit System aracılığıyla","DMV'ye kağıt bir form posta ile göndererek","Yerel polis departmanını arayarak","İzinler önceden alınamaz"],"explanation":"Nebraska aşırı boyut/aşırı ağırlık izinleri, NDOT'un çevrimiçi Automated Truck Permit System (dottruckpermits.nebraska.gov) aracılığıyla alınır. Kaynak: NDOT Permits; Nebraska DMV FAQ."},"16":{"q":"Nebraska karayollarında çalışmak için aşırı boyut veya aşırı ağırlık izni ne zaman gereklidir?","options":["Araç veya yük, yasal maksimum boyut veya ağırlık sınırlarını aştığında","Yalnızca başka bir eyalete geçerken","Yalnızca çakıl yollarda","Yalnızca tehlikeli madde taşıyan araçlar için"],"explanation":"Yasal maksimum boyut veya ağırlığı aşan bir aracı veya yükü hareket ettirmek için özel bir NDOT izni gereklidir; büyük zorluk olmadan azaltılabilecek veya parçalara ayrılabilecek bir yük için izin verilmez. Kaynak: NDOT 'Legal Sizes and Weights' (Aşırı Boyut veya Ağırlık); Neb. Rev. Stat. 60-6,294."},"17":{"q":"Nebraska'da, hangi yüksekliğin üzerinde operatör, üstteki engellere çarpma kaybı ve sorumluluğu riskini üstlenir?","options":["12 fit 6 inç üzerinde","13 fit 6 inç üzerinde","14 fit 6 inç üzerinde","11 fit üzerinde"],"explanation":"Nebraska yasası, yüksekliği 12 fit 6 inçi aşan bir aracın sahiplerinin/operatörlerinin riski üstlendiğini ve üstteki engellere verilen hasardan sorumlu olduğunu öngörür. Kaynak: NDOT 'Legal Sizes and Weights,' Yükseklik istisnası."},"18":{"q":"Nebraska, 8 fit 6 inçlik genişlik sınırından hangi özel istisnayı tanır?","options":["Normal çiftlik faaliyeti seyrinde gündüz saatlerinde hareket ettirilen çiftlik ekipmanı","Çelik taşıyan herhangi bir düz platformlu römork","Tüm soğutmalı römorklar","Eyalet dışında kayıtlı araçlar"],"explanation":"Nebraska'nın 8'6\" genişlik sınırı, normal çiftlik faaliyeti seyrinde gündüz saatlerinde geçici hareket halindeki çiftlik ekipmanı için geçerli değildir. Kaynak: NDOT 'Legal Sizes and Weights,' Genişlik istisnası."},"19":{"q":"Nebraska'nın yasal ağırlık kuralları kapsamında, bir kamyon, köprünün ilan edilen kapasitesini aşan bir brüt yükle bir köprüyü geçer ve hasara neden olursa ne olur?","options":["Aracın sahibi tüm hasardan sorumludur","Sorumluluk NDOT ile eşit olarak paylaşılır","Bir izin satın alındıysa sorumluluk yoktur","Yalnızca sürücü sorumludur, sahibi değil"],"explanation":"Nebraska yasası, ilan edilen kapasitesinin üzerinde bir yükle bir köprüyü geçmekten kaynaklanan tüm hasardan kamyon sahibini sorumlu tutar. Kaynak: NDOT 'Legal Sizes and Weights' (köprü hükmü); Neb. Rev. Stat. 60-6,294."},"20":{"q":"Nebraska'da, çekilen ünitenin/ünitelerin GVWR'si 10,000 poundu aşması koşuluyla, 26,001 pound veya daha fazla Gross Combination Weight Rating (GCWR) değerine sahip bir araç kombinasyonunu kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Nebraska, Class A CDL'i, çekilen ünitenin/ünitelerin GVWR'si 10,000 poundun üzerinde olduğunda 26,001 pound veya daha fazla GCWR değerine sahip bir araç kombinasyonu olarak tanımlar. Kaynak: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"21":{"q":"Nebraska kurallarına göre, 26,001 pound veya daha fazla GVWR değerine sahip tek bir aracı (veya 10,000 poundu aşmayan bir ünite çeken böyle bir aracı) hangi CDL sınıfı kapsar?","options":["Class A","Class B","Class C","Class M"],"explanation":"Nebraska, Class B CDL'i, 26,001 pound veya daha fazla GVWR değerine sahip tek bir araç veya 10,000 poundu aşmayan bir ünite çeken böyle herhangi bir araç olarak tanımlar. Kaynak: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"22":{"q":"Bir Nebraska sürücüsü, tehlikeli maddeler için plaka takılması gereken, 26,001 poundun altında GVWR değerine sahip tek bir aracı kullanıyor. Hangi CDL sınıfı geçerlidir?","options":["Class A","Class B","Class C","Class O"],"explanation":"Nebraska'nın Class C CDL'i, tehlikeli maddeler için plaka takılması gereken veya sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış bir otobüs olan, 26,001 poundun altında GVWR değerine sahip tek bir aracı (veya 10,000 pounda kadar bir ünite çeken aracı) kapsar. Kaynak: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"23":{"q":"Nebraska'nın Class C tanımına göre, bir otobüs, kaç yolcu taşımak üzere tasarlandığında bir CDL gerektirir?","options":["Sürücü dahil 8 veya daha fazla","Sürücü dahil 11 veya daha fazla","Sürücü dahil 16 veya daha fazla","Sürücü dahil 24 veya daha fazla"],"explanation":"Nebraska'nın Class C tanımı, sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış herhangi bir otobüsü içerir. Kaynak: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"24":{"q":"Eyalet içi (yalnızca Nebraska içinde) operasyon için Nebraska ticari sürücü ehliyetinin verilmesi için minimum yaş nedir?","options":["16 yaş","17 yaş","18 yaş","21 yaş"],"explanation":"Nebraska, 18 yaşına ulaşmamış kimseye CDL veya CLP vermez; 18, eyalet içi CDL operasyonu için minimum yaştır. Kaynak: Neb. Rev. Stat. 60-4,143; Nebraska DMV CDL sayfaları."},"25":{"q":"Bir Nebraska CDL sahibi, eyalet sınırları arasında (eyaletler arası) ticari bir araç kullanmak istiyor. Bunu yapmak için minimum yaş nedir?","options":["18 yaş","19 yaş","20 yaş","21 yaş"],"explanation":"Nebraska 18 yaşında eyalet içi bir CDL verirken, bir sürücünün eyaletler arası ticarette ticari bir motorlu araç kullanması için en az 21 yaşında olması gerekir. Kaynak: Nebraska DMV CDL sayfaları; Nebraska kuralı olarak uygulanan 49 CFR 391.11."},"26":{"q":"Bir Nebraska sürücüsünün, plaka gerektiren miktarlarda tehlikeli madde taşıması için hangi onaya (endorsement) ihtiyacı vardır?","options":["N onayı","H onayı","T onayı","X onayı"],"explanation":"Plaka takılmış tehlikeli maddeleri taşımak için H (Hazardous Materials) onayı gereklidir; bilgi testi ve bir TSA güvenlik tehdidi değerlendirmesi gerektirir. Kaynak: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"27":{"q":"Nebraska, HazMat (H) onayı olan bir CDL vermeden önce, başvuru sahibinin hangi ek federal arka plan adımını tamamlaması gerekir?","options":["Parmak izi alınmasını içeren bir TSA güvenlik tehdidi değerlendirmesi","Bir FBI medeni haklar görüşmesi","Bir DEA kontrollü madde kaydı","Bir USCIS vatandaşlık incelemesi"],"explanation":"HazMat bilgi testini geçmenin ötesinde, Nebraska, H onayı verilmeden önce başvuru sahiplerinin ön kayıt ve parmak izi alınmasını içeren bir Transportation Security Administration (TSA) güvenlik tehdidi değerlendirmesini tamamlamasını gerektirir. Kaynak: Nebraska DMV, CDL Classes, Endorsements and Restrictions; TSA HME programı."},"28":{"q":"Bir Nebraska sürücüsünün, TSA tehdidi değerlendirmesi için yeni parmak izlerini sunmak da dahil olmak üzere, HazMat (H) onayını ne sıklıkla yenilemesi gerekir?","options":["En az her 2 yılda bir","En az her 3 yılda bir","En az her 5 yılda bir","En az her 8 yılda bir"],"explanation":"HazMat onayı ve TSA güvenlik tehdidi değerlendirmesi, yenilemede yeni parmak izleri sunularak en az her beş yılda bir yenilenmelidir. Kaynak: Nebraska DMV CDL sayfaları; TSA HME programı (49 CFR 1572)."},"29":{"q":"Nebraska'da, dökme halinde sıvı veya gaz taşımak için kullanılan bir tanker aracı kullanmak için hangi onay gereklidir?","options":["T onayı","N onayı","H onayı","P onayı"],"explanation":"Bir tanker aracı kullanmak için N (Tank Vehicle) onayı gereklidir ve bir bilgi testini geçmeyi gerektirir. Kaynak: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"30":{"q":"Bir Nebraska sürücüsü çift veya üçlü römork çekmek istiyor. Hangi onay gereklidir?","options":["N onayı","P onayı","T onayı","S onayı"],"explanation":"Çift ve üçlü römork çekmek için T (Doubles/Triples) onayı gereklidir ve bir bilgi testini geçmeyi gerektirir. Kaynak: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"31":{"q":"Bir Nebraska CDL sahibinin, bir yolcu otobüsü gibi 16 veya daha fazla kişi taşımak üzere tasarlanmış bir aracı kullanmak için hangi onaya sahip olması gerekir?","options":["S onayı","P onayı","N onayı","H onayı"],"explanation":"16 veya daha fazla kişi taşımak üzere tasarlanmış araçlar (sürücü dahil) için P (Passenger) onayı gereklidir ve bir bilgi testi ile temsili bir araçta bir beceri testi gerektirir. Kaynak: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"32":{"q":"Nebraska'da, S (School Bus) onayı yalnızca hangi diğer onayla birlikte verilebilir?","options":["H (HazMat) onayı","N (Tank) onayı","P (Passenger) onayı","T (Doubles/Triples) onayı"],"explanation":"Nebraska, S (School Bus) onayının P (Passenger) onayına eşlik etmesini gerektirir; bir sürücü P olmadan S'ye sahip olamaz. Kaynak: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"33":{"q":"Bir Nebraska sürücüsünün, CDL beceri testine girmeden önce bir Commercial Learner's Permit (CLP) tutması gereken minimum süre nedir?","options":["7 gün","10 gün","14 gün","30 gün"],"explanation":"Nebraska, federal kuralı izleyerek, bir sürücünün CDL beceri testine girmeden önce geçerli bir CLP'yi en az 14 gün tutmasını gerektirir. Kaynak: Nebraska DMV, Commercial Learner's Permit; 49 CFR 383.25."},"34":{"q":"Bir Nebraska Commercial Learner's Permit (CLP) ne kadar süre geçerlidir?","options":["180 gün","1 yıl","2 yıl","5 yıl"],"explanation":"Bir Nebraska CLP'si 1 yıl geçerlidir. Üç beceri testi bölümünün tümü geçilmeden önce süresi dolarsa, daha önce geçilen bölümler geçersiz hale gelir ve tüm beceri testi yeniden yapılmalıdır. Kaynak: Nebraska DMV, Commercial Learner's Permit."},"35":{"q":"Nebraska, hangi CDL sınıflarında bir Commercial Learner's Permit (CLP) verir?","options":["Yalnızca Class A ve Class B","Yalnızca Class C","Class A, B ve C","Yalnızca Class B ve Class C"],"explanation":"Nebraska, yalnızca Class A ve Class B'de CLP verir. Kaynak: Nebraska DMV, Commercial Learner's Permit."},"36":{"q":"Bir Nebraska Commercial Learner's Permit (CLP), hangi onay setini taşıyabilir?","options":["H, T ve X","P, S ve N","Yalnızca H ve N","Yalnızca T ve X"],"explanation":"Bir Nebraska CLP'si yalnızca P (Passenger), S (School Bus) ve N (Tank, boş/kargosuz ile sınırlı) onaylarını taşıyabilir; H, T ve X bir CLP'de izin verilmez. Kaynak: Nebraska DMV, Commercial Learner's Permit; 49 CFR 383.25."},"37":{"q":"Bir CDL/CLP başvuru sahibinin ikametgahını kanıtlamak için kaç tane Nebraska asıl adresini kanıtlayan belge sunması gerekir?","options":["Bir belge","Farklı kaynaklardan iki belge","Üç belge","İkametgah kanıtı gerekmez"],"explanation":"Nebraska, başvuru sahibinin Nebraska asıl adresini gösteren farklı kaynaklardan iki belge gerektirir; bir posta kutusu kabul edilmez. Başvuru sahibi ayrıca kimlik kanıtı, bir Social Security numarası ve U.S. vatandaşlığı veya yasal statü kanıtı sunmalıdır. Kaynak: Nebraska DMV, CDL Documentation Requirements."},"38":{"q":"Nebraska'nın federal Entry-Level Driver Training (ELDT) gerekliliği kapsamında, bir sürücünün eğitimi nerede tamamlanmalı ve kaydedilmelidir?","options":["FMCSA Training Provider Registry'de listelenen bir sağlayıcıyla","Sürücünün seçtiği herhangi bir özel sürücü kursunda","Yalnızca iş başında bir çıraklık aracılığıyla","Bir Nebraska DMV sınav istasyonunda"],"explanation":"7 Şubat 2022'de yürürlüğe giren ELDT, ilk kez Class A/B başvuru sahiplerinin, B'den A'ya yükseltmelerin ve ilk kez P, S veya H onayı başvuru sahiplerinin, tamamlanmayı kaydeden FMCSA Training Provider Registry'de listelenen bir sağlayıcıyla eğitimi tamamlamasını gerektirir. Kaynak: Nebraska DMV, Entry Level Driver Training (ELDT); 49 CFR Part 380."},"39":{"q":"Hangi Nebraska CDL tıbbi öz-sertifikasyon kategorisi, eyaletler arası ticarette çalışan ve federal tıbbi (DOT muayenesi) gerekliliklerine TABİ olan bir sürücü için geçerlidir?","options":["Interstate Non-Excepted (Kategori A)","Interstate Excepted (Kategori B)","Intrastate Non-Excepted (Kategori C)","Intrastate Excepted (Kategori D)"],"explanation":"Kategori A, Interstate Non-Excepted, federal tıbbi ve görme gerekliliklerine tabi sürücüler için geçerlidir; National Registry'deki bir sağlayıcıdan güncel bir tıbbi muayene sertifikası sunmaları ve DMV'de dosyada güncel tutmaları gerekir. Kaynak: Nebraska DMV, CDL Self-Certification Categories; Neb. Rev. Stat. 60-4,144.01."},"40":{"q":"Nebraska'da bir ticari motorlu araç (CMV) kullanırken, bir sürücü hangi kan alkol konsantrasyonunda (BAC) etki altında araç kullanıyor ve büyük bir diskalifiye edici suç işliyor sayılır?","options":["0.02 veya daha yüksek","0.04 veya daha yüksek","0.08 veya daha yüksek","0.10 veya daha yüksek"],"explanation":"Nebraska, 49 CFR 383.51 ve Nebraska CDL Manual'i izleyerek, 0.04 veya daha yüksek bir BAC ile bir CMV kullanmayı büyük bir diskalifiye edici suç sayar. 0.08 sınırı ticari olmayan araçlar için geçerlidir. Kaynak: Nebraska DMV CDL Disqualification sayfası; Nebraska CDL Manual."},"41":{"q":"Nebraska'nın zımni rıza yasası kapsamında, bir CDL sahibinin bir motorlu araç kullandıktan sonra kimyasal (nefes, kan veya idrar) testini reddetmesinin sonucu nedir?","options":["Diskalifiye olmadan yalnızca bir uyarı mektubu","Bir DUI mahkumiyeti gibi CDL'i diskalifiye eden büyük bir suç olarak değerlendirilir","CDL'i etkilemeyen 30 günlük bir askıya alma","Ehliyet işlemi olmaksızın $100 idari para cezası"],"explanation":"Nebraska'nın zımni rıza yasası, bir alkol/uyuşturucu testini reddetmeyi, bir DUI ile aynı CDL diskalifikasyonunu taşıyan büyük bir diskalifiye edici suç olarak değerlendirir (ilk suç için 1 yıl, ikinci için ömür boyu). Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"42":{"q":"Nebraska'da, plaka takılmış tehlikeli madde TAŞIMAZKEN bir İLK büyük suç (DUI veya test reddi gibi) için bir CDL sahibi ne kadar süre diskalifiye edilir?","options":["60 gün","6 ay","1 yıl","3 yıl"],"explanation":"İlk büyük suç, bir Nebraska CDL sahibini 1 yıl diskalifiye eder. Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"43":{"q":"Bir Nebraska sürücüsü, tehlikeli maddeler için plaka takılması gereken bir CMV kullanırken bir ilk büyük suç işlerse, diskalifikasyon ne kadar sürer?","options":["1 yıl","2 yıl","3 yıl","Ömür boyu"],"explanation":"Plaka takılmış tehlikeli madde taşırken işlenen bir ilk büyük suç, diskalifikasyonu 1 yıldan 3 yıla yükseltir. Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"44":{"q":"Bir İKİNCİ büyük suçtan mahkum olan bir Nebraska CDL sahibi için diskalifikasyon süresi nedir?","options":["3 yıl","5 yıl","10 yıl","Ömür boyu"],"explanation":"Bir ikinci büyük suç, Nebraska'da ömür boyu CDL diskalifikasyonuyla sonuçlanır. Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"45":{"q":"Aşağıdakilerden hangisi bir Nebraska CDL sahibi için ciddi bir trafik ihlali yerine büyük bir diskalifiye edici suç olarak sınıflandırılır?","options":["Başka bir aracı çok yakından takip etmek","Kaza yerinden ayrılmak","Uygunsuz veya düzensiz şerit değişiklikleri","Limitin 15 mph veya daha fazla üzerinde hız yapmak"],"explanation":"Kaza yerinden ayrılmak BÜYÜK bir suçtur (1 yıl/ömür boyu diskalifikasyon). Çok yakından takip, düzensiz şerit değişiklikleri ve aşırı hız CİDDİ trafik ihlalleridir (60/120 gün). Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"46":{"q":"Bir Nebraska CDL sahibinin, 'aşırı hız' ciddi trafik ihlali olarak sayılması için ilan edilen hız limitinin ne kadar üzerinde araç kullanması gerekir?","options":["10 mph veya daha fazla üzerinde","15 mph veya daha fazla üzerinde","20 mph veya daha fazla üzerinde","25 mph veya daha fazla üzerinde"],"explanation":"İlan edilen limitin 15 mph veya daha fazla üzerinde hız yapmak, Nebraska'daki 'aşırı hız' ciddi trafik ihlalidir. Kaynak: Nebraska CDL Manual; Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"47":{"q":"Nebraska'da, 3 yıllık bir süre içinde ayrı olaylarda İKİ ciddi trafik ihlalinden mahkum olan bir CDL sahibi ne kadar süre diskalifiye edilir?","options":["30 gün","60 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde iki ciddi trafik ihlali, 60 günlük bir CDL diskalifikasyonuyla sonuçlanır. Kaynak: Nebraska DMV CDL Disqualification / MCSIA sayfası; 49 CFR 383.51."},"48":{"q":"Bir Nebraska CDL sahibi, 3 yıllık bir süre içinde ayrı olaylarda ÜÇ ciddi trafik ihlali işlerse ne kadar süre diskalifiye edilir?","options":["60 gün","90 gün","120 gün","180 gün"],"explanation":"3 yıl içinde üç ciddi trafik ihlali, 120 günlük bir CDL diskalifikasyonuyla sonuçlanır (bu, zaten uygulanmış herhangi bir 60 günlük diskalifikasyonu takip etmelidir). Kaynak: Nebraska DMV MCSIA sayfası; 49 CFR 383.51."},"49":{"q":"Aşağıdakilerden hangisi CDL sahipleri için Nebraska'nın CİDDİ trafik ihlalleri listesindedir?","options":["0.04 veya daha yüksek bir BAC ile araç kullanmak","Bir CMV kullanırken mesaj yazmak","Bir kimyasal testi reddetmek","Bir suç işlemek için bir CMV kullanmak"],"explanation":"Bir CMV kullanırken mesaj yazmak, Nebraska'da ciddi bir trafik ihlalidir. Listelenen diğer üçü büyük suçlardır. Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"50":{"q":"Kullanılan araç için uygun CDL sınıfı veya gerekli onay olmadan bir CMV kullanmak, Nebraska'da hangi tür ihlal olarak sınıflandırılır?","options":["Küçük bir ekipman ihlali","Ciddi bir trafik ihlali","Büyük bir diskalifiye edici suç","Bir hizmet dışı bırakma emri ihlali"],"explanation":"Uygun CDL sınıfı veya onayı olmadan bir CMV kullanmak, tekrarlanan şekilde işlendiğinde 60 gün/120 gün diskalifikasyona tabi olan Nebraska'nın ciddi trafik ihlallerinden biridir. Kaynak: Nebraska DMV MCSIA sayfası; 49 CFR 383.51."},"51":{"q":"Bir demiryolu-karayolu hemzemin geçiş ihlalinin İLK mahkumiyeti için, bir Nebraska CDL sahibi ne kadar süre diskalifiye edilir?","options":["En az 30 gün","En az 60 gün","En az 120 gün","En az 1 yıl"],"explanation":"İlk demiryolu hemzemin geçiş ihlali, en az 60 günlük bir diskalifikasyonla sonuçlanır. Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"52":{"q":"Bir Nebraska CDL sahibinin 3 yıllık bir süre içindeki İKİNCİ demiryolu-karayolu hemzemin geçiş ihlali için diskalifikasyon süresi nedir?","options":["En az 60 gün","En az 90 gün","En az 120 gün","En az 1 yıl"],"explanation":"3 yıl içinde ikinci bir demiryolu hemzemin geçiş ihlali, en az 120 günlük bir diskalifikasyonla sonuçlanır. Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"53":{"q":"Nebraska'da 3 yıllık bir süre içindeki bir ÜÇÜNCÜ demiryolu-karayolu hemzemin geçiş ihlali için diskalifikasyon nedir?","options":["En az 120 gün","En az 180 gün","En az 1 yıl","En az 3 yıl"],"explanation":"3 yıl içinde üçüncü bir demiryolu hemzemin geçiş ihlali, en az 1 yıllık bir diskalifikasyonla sonuçlanır. Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"54":{"q":"Nebraska'da standart bir CMV kullanırken bir hizmet dışı bırakma (OOS) emrini ihlal etmenin İLK mahkumiyeti için diskalifikasyon süresi nedir?","options":["30 ila 60 gün","90 gün","180 gün ila 1 yıl","2 ila 5 yıl"],"explanation":"Standart bir CMV'de ilk hizmet dışı bırakma emri ihlali, 180 gün ila 1 yıllık bir diskalifikasyonla sonuçlanır. Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"55":{"q":"Nebraska'da standart bir CMV kullanırken 10 yıllık bir süre içindeki bir İKİNCİ hizmet dışı bırakma emri ihlali için diskalifikasyon süresi nedir?","options":["180 gün ila 1 yıl","1 ila 2 yıl","2 ila 5 yıl","Ömür boyu"],"explanation":"10 yıl içinde ikinci bir hizmet dışı bırakma emri ihlali, 2 ila 5 yıllık bir diskalifikasyonla sonuçlanır. Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"56":{"q":"HİZMET DIŞI BIRAKMA emri ihlali, plaka gerektiren tehlikeli madde taşıyan veya 16 ya da daha fazla yolcu taşımak üzere tasarlanmış bir CMV'yi içerdiğinde, Nebraska'daki İLK mahkumiyet diskalifikasyonu nedir?","options":["90 gün ila 1 yıl","180 gün ila 2 yıl","2 ila 5 yıl","3 ila 5 yıl"],"explanation":"Plaka takılmış tehlikeli madde veya 16+ yolcu için tasarlanmış bir aracı içeren ilk hizmet dışı bırakma emri ihlali, 180 gün ila 2 yıllık yükseltilmiş bir diskalifikasyon taşır. Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"57":{"q":"CDL'iniz askıya alınmış, iptal edilmişken veya siz diskalifiye edilmişken bir CMV kullanmak, Nebraska tarafından ne tür bir suç olarak değerlendirilir?","options":["Ciddi bir trafik ihlali (60/120 gün)","Büyük bir diskalifiye edici suç (1 yıl/ömür boyu)","Bir hizmet dışı bırakma ihlali (180 gün)","Diskalifiye etmeyen bir evrak ihlali"],"explanation":"CDL'i iptal edilmiş, askıya alınmış, geçersiz kılınmışken veya diskalifiye edilmişken bir CMV kullanmak, ilk suç için 1 yıllık diskalifikasyon ve ikinci için ömür boyu diskalifikasyon taşıyan büyük bir suçtur. Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"58":{"q":"Nebraska yasası (Neb. Rev. Stat. 60-6,179.01) kapsamında, bir İLK araç kullanırken mesaj yazma ihlali için para cezası nedir?","options":["$100","$200","$300","$500"],"explanation":"Nebraska'nın mesaj yazma karşıtı yasası (Neb. Rev. Stat. 60-6,179.01), ilk suç için $200, ikinci için $300 ve üçüncü veya sonraki suç için $500 para cezası ile birlikte üç puan belirler. CDL sürücüleri için, bir CMV'de tekrarlanan mesaj yazma da ciddi bir trafik ihlalidir. Kaynak: Neb. Rev. Stat. 60-6,179.01."},"59":{"q":"Bir kontrollü maddenin üretimini, dağıtımını veya temin edilmesini içeren bir suçun işlenmesinde bir CMV kullanmak, bir Nebraska CDL sahibi için hangi cezayla sonuçlanır?","options":["1 yıllık diskalifikasyon","3 yıllık diskalifikasyon","5 yıllık diskalifikasyon","Yeniden alma olanağı olmayan ömür boyu diskalifikasyon"],"explanation":"Bir kontrollü maddenin üretimini, dağıtımını veya temin edilmesini içeren bir suçu işlemek için herhangi bir motorlu aracı kullanmak, diğer bazı ömür boyu durumlar için mevcut olan 10 yıllık yeniden alma hakkına uygun olmayan ömür boyu bir diskalifikasyonla sonuçlanır. Kaynak: Nebraska DMV CDL Disqualification sayfası; 49 CFR 383.51."},"60":{"q":"Nebraska eyaletinde bir eyaletler arası otoyolda (interstate), bir çekici banketteüzerinde sarı ışıkları yanıp sönerek durmuş durumda. Siz sağ şeritte bir CMV kullanıyorsunuz ve solunuzda açık bir şerit var. Nebraska'nın Şerit Değiştir (Move Over) yasası uyarınca ne yapmalısınız?","options":["Güvenli olduğunda, duran araçtan en az bir hareketli şerit uzakta olan bir şeride geçin","Hızınızı koruyun ancak geçerken kornanızı çalın","Çekici ayrılana kadar tamamen durun","Hız sınırında veya altında olduğunuz sürece sağ şeritte devam edin"],"explanation":"Nebraska'nın Şerit Değiştir (Move Over) yasası (Neb. Rev. Stat. 60-6,378.01), yanıp sönen ışıkları olan duran bir araca yaklaşan sürücülerin hızlarını azaltmasını ve güvenli olduğunda duran araçtan en az bir hareketli şerit uzakta olan bir şeride geçmesini gerektirir. Kaynak: Neb. Rev. Stat. 60-6,378.01 / NDOT 'Move Over, Slow Down'."},"61":{"q":"Nebraska'nın Şerit Değiştir (Move Over) yasası, 3 Eylül 2025 tarihinde yürürlüğe giren LB 530 ile önemli ölçüde genişletildi. Bu değişiklikle birlikte, sürücüler aşağıdakilerden hangisi için yavaşlamalı ve şerit değiştirmelidir?","options":["Yalnızca yanıp sönen kırmızı veya mavi ışıklar gösteren yetkili acil durum araçları","Yalnızca çekiciler ve karayolu bakım araçları","Yayalar, bisikletliler ve tarım ekipmanları dahil olmak üzere otoyol kenarındaki tüm duran araçlar ve savunmasız yol kullanıcıları","Yalnızca aktif bir inşaat çalışma alanı içinde duran araçlar"],"explanation":"LB 530 (3 Eylül 2025'te yürürlüğe girdi) uyarınca, Nebraska şerit değiştirme zorunluluğunu acil durum ve yol kenarı yardım araçlarının ötesine genişleterek otoyol kenarındaki TÜM duran araçları ve savunmasız yol kullanıcılarını -yayalar, bisikletliler, yaya geçitlerindeki kişiler ve tarım araçları veya ekipmanları dahil- kapsamına aldı. Kaynak: Neb. LB 530 / NDOT basın açıklaması 'Nebraska's Updated Move-Over Law Takes Effect Sept. 3'."},"62":{"q":"Nebraska'nın Şerit Değiştir (Move Over) yasası uyarınca, uyarı ışıkları gösteren duran bir araç için güvenli bir şekilde şerit değiştiremediğinizde bunun yerine ne yapmalısınız?","options":["Trafik açılana kadar yolda tamamen durun","Hızınızı azaltın, koşullara uygun güvenli bir hızı koruyun ve gereken özen ve dikkatle ilerleyin","Belirtilen hız sınırını koruyun ve normal şekilde geçin","Bölgeyi mümkün olduğunca çabuk geçmek için hızlanın"],"explanation":"Neb. Rev. Stat. 60-6,378.01, bir şerit değişikliği mümkün veya güvenli değilse, sürücünün hızını azaltması, duran aracı, hava durumunu, yolu ve trafik koşullarını dikkate alarak güvenli bir hızı koruması ve gereken özen ve dikkatle ilerlemesi gerektiğini öngörür. Kaynak: Neb. Rev. Stat. 60-6,378.01."},"63":{"q":"Aksi belirtilmedikçe, Nebraska'da Ulusal Eyaletler Arası Otoyol Sistemi'nin (National System of Interstate highways) kırsal bir kesiminde ticari bir kamyon için maksimum hız sınırı nedir?","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"Neb. Rev. Stat. 60-6,186, kırsal eyaletler arası otoyollarda maksimum hızı 75 mph olarak belirler. Nebraska, kamyonlar için ayrı, daha düşük bir yasal hız sınırı belirlemez; CMV'ler diğer araçlarla aynı belirtilen maksimumlara uyar. Kaynak: Neb. Rev. Stat. 60-6,186 / NDOT hız sınırı bilgisi."},"64":{"q":"Eyalet karayolu sisteminin bir parçası olan bir Nebraska ekspres yolunda (expressway) veya süper-iki (super-two) karayolunda, aksi belirtilmedikçe maksimum hız sınırı nedir?","options":["55 mph","65 mph","70 mph","75 mph"],"explanation":"Neb. Rev. Stat. 60-6,186, eyalet karayolu sisteminin bir parçası olan bir ekspres yolda, süper-iki karayolunda veya otoyolda (freeway) 70 mph belirler. (Kırsal eyaletler arası otoyol 75 mph'dir; diğer eyalet karayolları 65 mph'dir.) Kaynak: Neb. Rev. Stat. 60-6,186 / NDOT hız sınırı broşürü."},"65":{"q":"Nebraska yasası, ticari kamyonlar için binek otomobillere kıyasla ayrı, daha düşük bir maksimum yasal hız sınırı belirler mi?","options":["Evet, kamyonlar eyalet genelinde 65 mph ile sınırlıdır","Evet, kamyonlar belirtilen sınırın 10 mph altında seyretmelidir","Hayır, Neb. Rev. Stat. 60-6,186'daki yasal maksimum hız sınırları tüm araçlara aynı şekilde uygulanır","Evet, ancak yalnızca eyaletler arası otoyol sisteminde"],"explanation":"Neb. Rev. Stat. 60-6,186, kamyonlar için ayrı bir hız sınırı olmaksızın yol kategorisine göre tek tip yasal maksimum hızlar belirler; ticari araçlar diğer trafikle aynı belirtilen maksimumlara uymak zorundadır. Kaynak: Neb. Rev. Stat. 60-6,186."},"66":{"q":"Bir ekspres yol, süper-iki veya otoyol (freeway) OLMAYAN bir Nebraska eyalet karayolunda, aksi belirtilmedikçe maksimum hız sınırı nedir?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Neb. Rev. Stat. 60-6,186, eyalet karayolu sisteminin bir ekspres yol, süper-iki karayolu veya otoyol (freeway) dışındaki herhangi bir bölümünde 65 mph belirler. Kaynak: Neb. Rev. Stat. 60-6,186 / NDOT hız sınırı broşürü."},"67":{"q":"Yolcu taşıyan bir otobüs veya plakart (tehlike levhası) takılmış bir tehlikeli madde aracı, Nebraska'da bir hemzemin demiryolu geçidine yaklaşıyor. Sürücü, en yakın raydan ne kadar mesafe içinde durmalıdır?","options":["5 ile 25 feet arası","15 ile 50 feet arası","25 ile 75 feet arası","50 ile 100 feet arası"],"explanation":"Yolcu taşıyan otobüsler ve plakart takılmış HazMat CMV'leri en yakın raydan 15 ile 50 feet arasında durmalı, ardından geçmeden önce bakıp dinlemelidir (Nebraska CDL El Kitabı'nda öğretildiği üzere 49 CFR 392.10). Kaynak: Nebraska CDL El Kitabı / 49 CFR 392.10."},"68":{"q":"Bir demiryolu geçidinde durduktan sonra, Nebraska'daki bir CDL sürücüsü rayları geçmeye başlar. Kural, vites değişimleri konusunda ne gerektirir?","options":["Kontrolü sağlamak için raylar üzerindeyken bir kez küçük vitese geçin","Vites değiştirmeden bitirmenize olanak tanıyan bir viteste geçin; raylar üzerindeyken vites değiştirmeyin","Motor zorlanmasını azaltmak için geçerken boşa alın","Raylara ulaşmadan önce en yüksek vitese çıkın"],"explanation":"Nebraska CDL El Kitabı ve 49 CFR 392.10-392.11, geçişi vites değiştirmeden tamamlamanıza olanak tanıyan bir viteste geçmeyi gerektirir; aracın herhangi bir parçası raylar üzerindeyken vites değiştirmemelisiniz. Kaynak: Nebraska CDL El Kitabı / 49 CFR 392.10-392.11."},"69":{"q":"Nebraska'daki plakart takılmış HazMat araçları ve yolcu otobüsleri, bir hemzemin demiryolu geçidinde ne zaman durmak zorunda DEĞİLDİR?","options":["Arkalarındaki trafik yoğun olduğunda her zaman","Yeşil gösteren çalışır durumda bir karayolu trafik sinyaliyle kontrol edilen veya 'Exempt' (Muaf) tabelasıyla işaretlenmiş bir geçitte","Yerleşim bölgesindeki herhangi bir geçitte","Yalnızca çakıl yollarda"],"explanation":"49 CFR 392.10 (Nebraska CDL El Kitabı'nda öğretildiği üzere) uyarınca, durma zorunluluğu, diğerlerinin yanı sıra, yeşil gösteren çalışır durumda bir karayolu trafik sinyaliyle kontrol edilen bir geçitte, bir tramvay/yan hat geçidinde veya 'Exempt' (Muaf) tabelasıyla işaretlenmiş bir sanayi/yan hat hemzemin geçidinde uygulanmaz. Kaynak: Nebraska CDL El Kitabı / 49 CFR 392.10."},"70":{"q":"Yanıp sönen kırmızı ışıkları açık ve dur kolu uzatılmış, durmuş bir Nebraska okul otobüsüyle karşılaşırken veya onu geçerken, diğer sürücüler (hiçbir istisna geçerli olmadığında) ne yapmalıdır?","options":["25 mph'ye yavaşlayın ve dikkatle geçin","Tamamen durun ve kırmızı ışıklar sönene, dur kolu geri çekilene ve otobüs tekrar hareket edene kadar durmuş halde kalın","Yalnızca yolu geçerken görünen çocuklar varsa durun","Sola geçin ve otobüsü geçerek devam edin"],"explanation":"Neb. Rev. Stat. 60-6,175, bir okul otobüsü dur sinyal kolu uzatılmış ve yanıp sönen kırmızı ışıkları açık halde durduğunda tamamen durmayı gerektirir ve sürücü, kırmızı ışıklar sönene, kol geri çekilene ve otobüs harekete geçene kadar durmuş halde kalmalıdır. Kaynak: Neb. Rev. Stat. 60-6,175."},"71":{"q":"Nebraska yasası, bir okul otobüsü kırmızı ışıklar yanmadan önce SARI (amber) uyarı sinyal ışıklarını ilk kez yaktığında sürücülerin ne yapmasını gerektirir?","options":["Kırmızı ışıklar yanmadan önce bile derhal durun","Hızı en fazla 25 mph'ye düşürün ve durmaya hazırlanın","Kırmızı ışıklar yanıp sönene kadar hızı koruyun","Hızı en fazla 40 mph'ye düşürün"],"explanation":"Neb. Rev. Stat. 60-6,175, sarı uyarı ışıklarını yanıp söndüren bir okul otobüsüyle karşılaşan veya onu geçen bir sürücünün hızı en fazla 25 mph'ye düşürmesini ve aracı tamamen durdurmaya hazır olmasını gerektirir. Kaynak: Neb. Rev. Stat. 60-6,175."},"72":{"q":"Nebraska'nın okul otobüsünde durma yasası uyarınca, hangi bölünmüş karayolu durumu, yaklaşan bir sürücünün kırmızı ışıkları yanıp sönen bir okul otobüsü için durmasını gerektirmez?","options":["Aynı şeritte otobüsün hemen arkasından gelen trafik","Bölünmüş bir karayolunda ters yönden yaklaşan trafik","Bölünmemiş iki şeritli bir yolda bitişik aynı yönlü şeritteki trafik","Bir yan sokaktan aynı yola yaklaşan trafik"],"explanation":"Neb. Rev. Stat. 60-6,175, durma zorunluluğunun bölünmüş bir karayolunda (örneğin bir refüjle ayrılmış) ters yönden yaklaşan trafiğe uygulanmadığını öngörür; bölünmüş bir karayolunun farklı bir yolundaki sürücülerin durması gerekmez. Bölünmemiş bir yolda otobüsü takip eden veya onunla karşılaşan araçların yine de durması gerekir. Kaynak: Neb. Rev. Stat. 60-6,175."},"73":{"q":"Bir CDL sürücüsü, bir arıza nedeniyle Nebraska iki şeritli, çift yönlü bir karayolunun banketinde durmuş durumda. Acil durum uyarı cihazları (yansıtıcı üçgenler) kaç dakika içinde yerleştirilmelidir?","options":["5 dakika içinde","10 dakika içinde","15 dakika içinde","30 dakika içinde"],"explanation":"Nebraska CDL El Kitabı (49 CFR 392.22'yi izleyerek), uyarı cihazlarının durduktan sonra 10 dakika içinde yerleştirilmesini gerektirir. Kaynak: Nebraska CDL El Kitabı / 49 CFR 392.22."},"74":{"q":"Nebraska iki şeritli, çift yönlü bir yolda, bir CDL sürücüsü durduktan sonra gerekli üç uyarı üçgenini nereye yerleştirmelidir?","options":["Aracın yaklaşık 10 ft arkasına, 100 ft arkasına ve 100 ft önüne","Üçünü de aracın 10 ft içinde","Aracın 50 ft, 150 ft ve 250 ft arkasına","Yalnızca arkaya doğru yaklaşık 25 ft, 75 ft ve 200 ft mesafeye"],"explanation":"Nebraska CDL El Kitabı'na (49 CFR 392.22) göre, iki şeritli çift yönlü bir yolda bir üçgeni yaklaşık 10 ft arkaya (trafik tarafına), bir üçgeni yaklaşık 100 ft arkaya ve bir üçgeni aracın yaklaşık 100 ft önüne yerleştirin. Kaynak: Nebraska CDL El Kitabı / 49 CFR 392.22."},"75":{"q":"Nebraska'da, NDOT'tan bir gabari (oversize) izni gerekmeden önce ticari bir araç için maksimum yasal genişlik nedir?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Nebraska'nın yasal maksimum toplam araç genişliği 8 feet 6 inches'tır; bundan daha geniş olan herhangi bir şey bir NDOT gabari izni gerektirir (tarım ekipmanları için bir gündüz istisnası geçerlidir). Kaynak: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska' / Neb. Rev. Stat. ch. 60."},"76":{"q":"Bir izin gerekmeden önce Nebraska'nın yasal maksimum toplam araç yüksekliği nedir?","options":["13 feet 6 inches","14 feet 0 inches","14 feet 6 inches","15 feet 0 inches"],"explanation":"Nebraska'nın yasal maksimum toplam yüksekliği 14 feet 6 inches'tır. 12 feet 6 inches'ı aşan araçların sürücülerinin, üstteki engellere verilen hasarın riskini üstlendiğini unutmayın. Kaynak: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'."},"77":{"q":"Nebraska, US ve Eyalet karayolu güzergahlarında Eyaletler Arası (Interstate) güzergahlardan daha yüksek bir yasal brüt ağırlığa izin vermesiyle ayırt edicidir. Nebraska US ve Eyalet güzergahlarındaki (Eyaletler Arası dışında) yasal brüt ağırlık sınırı nedir?","options":["80,000 lbs","85,500 lbs","94,000 lbs","105,500 lbs"],"explanation":"Nebraska'nın yasal brüt ağırlığı, Eyaletler Arası olarak belirlenmiş güzergahlarda 80,000 lbs, ancak US ve Eyalet güzergahlarında 94,000 lbs'tır (aks ve köprü formülü sınırlarına tabidir). Kaynak: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'."},"78":{"q":"Nebraska'da Eyaletler Arası (Interstate) olarak belirlenmiş güzergahlarda izin olmadan bir CMV için yasal maksimum brüt ağırlık nedir?","options":["73,280 lbs","80,000 lbs","88,000 lbs","94,000 lbs"],"explanation":"Eyaletler Arası olarak belirlenmiş güzergahlarda Nebraska'nın yasal brüt ağırlığı, federal sınırla tutarlı olarak 80,000 lbs'tır; tek aks (20,000 lbs), tandem aks (34,000 lbs) ve köprü formülü kısıtlamalarına tabidir. Kaynak: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'."},"79":{"q":"Nebraska'nın sol şerit / sağda kal kuralı (Neb. Rev. Stat. 60-6,131), çok şeritli bir karayolunda normal trafikten daha yavaş seyreden bir CMV'nin ne yapmasını gerektirir?","options":["Daha hızlı trafiğin sağdan geçebilmesi için sol şeridi kullanın","Yalnızca geçmek, sola dönmek veya bir engelden kaçınmak için sol şeridi kullanarak, trafik için mevcut olan sağ şeritte sürün","Her zaman orta şeritte sürün","Mevcut en hızlı aracın hızına uyun"],"explanation":"Neb. Rev. Stat. 60-6,131, CMV'ler dahil olmak üzere normal trafikten daha yavaş seyreden araçların sol şeridi geçiş yapmak, sola dönüşe hazırlanmak veya bir engelden kaçınmak için ayırarak sağ şeritte (veya mümkün olduğunca sağ kenara yakın) kalmasını gerektirir. Kaynak: Neb. Rev. Stat. 60-6,131."},"80":{"q":"Nebraska'da Ticari Sürücü Belgelerini (Commercial Driver License) hangi eyalet kurumu düzenler?","options":["Sürücü Belgelendirme Hizmetleri (Driver Licensing Services) aracılığıyla Nebraska Motorlu Taşıtlar Dairesi (DMV)","Nebraska Eyalet Devriyesi (Nebraska State Patrol)","Nebraska Ulaştırma Dairesi (Department of Transportation)","Federal Motorlu Taşıyıcı Güvenliği İdaresi (Federal Motor Carrier Safety Administration)"],"explanation":"Nebraska'da Motorlu Taşıtlar Dairesi (DMV), Sürücü Belgelendirme Hizmetleri aracılığıyla CDL'leri düzenler ve başvuru sahipleri Sürücü Belgelendirme Ofislerinde (Driver Licensing Offices) başvuru yapar ve sınava girer. Kaynak: Nebraska DMV, CDL sayfaları (dmv.nebraska.gov/cdl)."},"81":{"q":"Nebraska'da CDL beceri sınavına girmeden önce, bir başvuru sahibinin önce bir Ticari Öğrenci İzni (Commercial Learner's Permit, CLP) alması ve onu en az ne kadar süre elinde bulundurması gerekir?","options":["14 days","7 days","30 days","60 days"],"explanation":"Nebraska, bir sürücünün CDL beceri sınavına girmeden önce geçerli bir CLP'ye sahip olmasını ve onu en az 14 days süreyle elinde bulundurmasını gerektirir. Bu, federal CLP kuralını yansıtır. Kaynak: Nebraska DMV, CDL Testing sayfası."},"82":{"q":"Nebraska CDL beceri sınavı hangi üç bölüme ayrılır?","options":["Sefer öncesi muayene (pre-trip inspection), temel kontrol becerileri ve yolda sürüş","Yazılı bilgi, görme taraması ve yol işareti tanımlama","Bağlama (coupling), geri gitme (backing) ve hava freni boşaltma (air-brake bleed-down)","Sefer öncesi muayene, hazmat taşıma ve gece sürüşü"],"explanation":"Nebraska'nın CDL beceri sınavı üç alanı değerlendirir: sefer öncesi muayene, temel kontrol becerileri ve yolda sürüş. Kaynak: Nebraska DMV, CDL Testing sayfası."},"83":{"q":"Nebraska'da bir Ticari Öğrenci İzni (CLP) ne kadar süre geçerlidir?","options":["1 year","180 days","90 days","5 years"],"explanation":"Bir Nebraska CLP'si 1 year geçerlidir. Kaynak: Nebraska DMV, Commercial Learner's Permit sayfası."},"84":{"q":"Nebraska'nın öz-belgelendirme (self-certification) sistemi kapsamında, hangi İKİ kategori sürücünün geçerli bir Sağlık Muayenesi Sertifikası (Medical Examiner's Certificate) bulundurmasını gerektirir?","options":["Kategori A (Eyaletler Arası İstisna Dışı / Interstate Non-Excepted) ve Kategori C (Eyalet İçi İstisna Dışı / Intrastate Non-Excepted)","Kategori B (Eyaletler Arası İstisnalı / Interstate Excepted) ve Kategori D (Eyalet İçi İstisnalı / Intrastate Excepted)","Kategori A (Eyaletler Arası İstisna Dışı / Interstate Non-Excepted) ve Kategori B (Eyaletler Arası İstisnalı / Interstate Excepted)","Kategori C (Eyalet İçi İstisna Dışı / Intrastate Non-Excepted) ve Kategori D (Eyalet İçi İstisnalı / Intrastate Excepted)"],"explanation":"Kategori A (Eyaletler Arası İstisna Dışı) veya Kategori C (Eyalet İçi İstisna Dışı) olarak öz-belgelendirme yapan sürücülerin geçerli bir sağlık muayenesi sertifikası bulunması gerekir. İstisnalı kategorilerin (B ve D) bulunması gerekmez. Kaynak: Nebraska DMV, CDL Documentation Requirements / Self-Certification çizelgesi."},"85":{"q":"19 Mayıs 2025 tarihinden itibaren, Nebraska DMV, CDL/CLP sahipleri için Sağlık Muayenesi Sertifikası (MEC) bilgilerini nasıl alır?","options":["FMCSA National Registry'den elektronik olarak; sürücüler artık DMV'ye kağıt kopya sunmaz","Yalnızca taahhütlü posta yoluyla, sağlık kartının noter onaylı bir kağıt kopyasıyla","Bir Sürücü Belgelendirme Ofisinde şahsen, personelin kağıt kartı taradığı yerde","Muayeneden sonra 10 gün içinde sürücünün işvereninden faks yoluyla"],"explanation":"19 Mayıs 2025 tarihinden itibaren, Nebraska CDL/CLP sahipleri artık DMV'ye MEC'lerinin kağıt kopyasını sunmaz; DMV bilgileri FMCSA'nın National Registry'sinden elektronik olarak alır. Kaynak: Nebraska DMV'nin federal Sağlık Muayenesi Sertifikalandırma kuralına ilişkin haber bülteni."},"86":{"q":"21 yaşında veya daha büyük bir sahip için bir Nebraska Ticari Sürücü Belgesinin standart geçerlilik süresi nedir?","options":["5 years (düzenlendikten sonraki beşinci yılda sahibin doğum gününde sona erer)","4 years","8 years","2 years"],"explanation":"Nebraska'da, CDL'ler dahil olmak üzere 21 yaşında veya daha büyük kişilere düzenlenen belgeler, düzenlendikten sonraki beşinci yılda sahibin doğum gününde sona erer (yaklaşık 5 yıllık bir döngü). Kaynak: Nebraska DMV, Renewals sayfası."},"87":{"q":"EYALETLER ARASI (INTERSTATE) ticari sürüş için bir Nebraska CDL'sine sahip olmanın asgari yaşı nedir?","options":["21 years old","18 years old","19 years old","25 years old"],"explanation":"Nebraska, eyaletler arası ticarette çalışmak için sürücülerin en az 21 yaşında olmasını gerektirir; yalnızca eyalet içi CDL sürücüleri 18 yaşında uygun olabilir. Kaynak: Nebraska DMV, CDL sayfası (Sınıf A/B/C yaş gereksinimleri)."},"88":{"q":"YALNIZCA EYALET İÇİ (INTRASTATE) ticari sürüş için bir Nebraska CDL'sine sahip olmanın asgari yaşı nedir?","options":["18 years old","21 years old","16 years old","19 years old"],"explanation":"Nebraska, eyalet içi çalışma için 18 yaşında bir Sınıf A, B veya C CDL'sine izin verir; eyaletler arası çalışma 21 yaş gerektirir. Kaynak: Nebraska DMV, CDL sayfası."},"89":{"q":"Giriş Düzeyi Sürücü Eğitimi (Entry-Level Driver Training, ELDT), Nebraska'da yeni CDL başvuru sahipleri için hangi tarihte zorunlu hale geldi?","options":["February 7, 2022","May 19, 2025","January 1, 2020","July 1, 2021"],"explanation":"7 Şubat 2022 tarihinden itibaren, yeni CDL başvuru sahipleri, sınıf yükseltenler ve ilk kez hazmat başvuru sahipleri, sınava girmeden önce ELDT'yi tamamlamalıdır. Kaynak: Nebraska DMV, CDL Testing sayfası."},"90":{"q":"Nebraska DMV, bir CDL başvuru sahibinin gerekli Giriş Düzeyi Sürücü Eğitimini (ELDT) tamamladığını nasıl doğrular?","options":["DMV, ELDT kanıtını elektronik olarak doğrular","Başvuru sahibi, merkezi DMV ofisine bir kağıt eğitim sertifikası gönderir","Başvuru sahibinin işvereni, sınav yerinde bir yeminli beyan imzalar","Eğitim okulu, yerel Sürücü Belgelendirme Ofisine bir liste faksla gönderir"],"explanation":"Nebraska, DMV'nin ELDT tamamlama kanıtını (FMCSA Training Provider Registry aracılığıyla) elektronik olarak doğrulayacağını belirtir. Kaynak: Nebraska DMV, CDL Testing sayfası."},"91":{"q":"İster yeni başvuru, ister yeni mukim, ister yenileme olsun, HER Nebraska CDL başvuru sahibinin hangi taramayı geçmesi gerekir?","options":["Bir görme testi","Bir tehlikeli maddeler bilgi testi","Bir hava freni performans testi","DMV'de bir uyuşturucu ve alkol taraması"],"explanation":"Yeni belgeler, yeni mukimler ve yenilemeler dahil olmak üzere Nebraska'daki tüm CDL başvuru sahipleri için bir görme testi gereklidir. Kaynak: Nebraska DMV, CDL Testing sayfası."},"92":{"q":"Bir Nebraska başvuru sahibi bir CDL yazılı bilgi testinde veya bir beceri testinde başarısız olursa, genellikle ne kadar süre sonra yeniden sınava girebilir?","options":["En az bir günlük bekleme süresinden sonra","Hemen, aynı gün","14 günlük bekleme süresinden sonra","30 günlük bekleme süresinden sonra"],"explanation":"Nebraska, bir yazılı veya beceri testinde başarısız olunduğunda yeniden sınava girmeden önce en az bir günlük bir bekleme süresi gerektirir. Kaynak: Nebraska DMV, CDL Testing sayfası."},"93":{"q":"Nebraska'da, geçerli bir eyalet dışı CDL'sini transfer eden bir yeni mukim için bile, hangi CDL bilgi testi ASLA muaf tutulamaz?","options":["Tehlikeli maddeler (hazmat) bilgi testi","Genel bilgi testi","Hava frenleri bilgi testi","Kombinasyon araçları bilgi testi"],"explanation":"Nebraska, uygun yeni mukimler veya zamanında yenilemeler için belirli yazılı testleri muaf tutabilir, ancak hazmat bilgi testi muaf tutulamaz. Kaynak: Nebraska DMV, CDL Testing sayfası."},"94":{"q":"Üç bölümün tümü tamamlanmadan önce CLP süresi dolarsa, bir Nebraska CLP sahibinin daha önce geçtiği beceri testi bölümlerine ne olur?","options":["Daha önce geçilen bölümler geçersiz hale gelir ve yeniden alınmalıdır","Bir ek süre olarak 90 gün daha geçerli kalırlar","Yenilenen CLP'ye otomatik olarak aktarılırlar","Yalnızca yolda sürüş bölümü yeniden alınmalıdır"],"explanation":"Nebraska'da, üç beceri testi bölümünün tümü tamamlanmadan önce bir CLP'nin süresi dolarsa, daha önce geçilen testler geçersiz hale gelir ve yeniden alınmalıdır. Kaynak: Nebraska DMV, Commercial Learner's Permit sayfası."},"95":{"q":"Nebraska CDL beceri testleri, DMV sınav görevlilerine ek olarak nerede uygulanır?","options":["DMV tarafından yetkilendirilmiş üçüncü taraf sınav görevlileri tarafından","Yalnızca FMCSA federal müfettişleri tarafından","Yalnızca başvuru sahibinin CDL eğitim okulu eğitmeni tarafından","İşveren tarafından belirlenen herhangi bir lisanslı CDL sahibi tarafından"],"explanation":"Nebraska, DMV tarafından yetkilendirilmiş üçüncü taraf sınav görevlilerinin CDL beceri testlerini uygulamasına izin verir; bunların DMV'ye iki iş günü önceden bildirimde bulunması gerekir. Kaynak: Nebraska DMV, CDL Testing sayfası ve Third-Party Testers listesi."},"96":{"q":"Bir Nebraska CDL veya CLP için başvururken, Sosyal Güvenlik numarasının (Social Security number) açıklanmasına ilişkin kural nedir?","options":["Başvuru sahipleri geçerli bir Sosyal Güvenlik numarasını açıklamalıdır; CDL sürücüleri için herhangi bir muafiyet yoktur","Açıklama isteğe bağlıdır ve bir pasaport numarasıyla değiştirilebilir","Yalnızca eyaletler arası sürücüler açıklamak zorundadır","Yalnızca bir hazmat onayı eklenirken gereklidir"],"explanation":"Nebraska, CDL/CLP başvuru sahiplerinin geçerli bir Sosyal Güvenlik numarasını açıklamasını gerektirir; ticari sürücüler için herhangi bir muafiyet yoktur. Kaynak: Nebraska DMV, CDL Documentation Requirements."},"97":{"q":"Bir CDL başvurusu için bir Nebraska asıl adresini kanıtlamak için, başvuru sahibinin ne sunması gerekir?","options":["Nebraska adresini gösteren, farklı kaynaklardan iki belge; bir P.O. Box kabul edilemez","Bir P.O. Box'a izin verilen tek bir fatura","Tek bir yeminli ikamet beyanı","Yalnızca bir Nebraska seçmen kayıt kartı"],"explanation":"Nebraska, farklı kaynaklardan iki adres kanıtı belgesi gerektirir (genellikle 90 gün içinde düzenlenmiş); bir P.O. Box kabul edilemez. Kaynak: Nebraska DMV, CDL Documentation Requirements."},"98":{"q":"Kategori A veya C olarak öz-belgelendirme yapan bir Nebraska CDL sahibi, National Registry'de güncel bir Sağlık Muayenesi Sertifikası bulundurmazsa hangi sonuçla karşı karşıya kalır?","options":["CDL/CLP ticari ayrıcalıklarının düşürülmesi (downgrade)","Otomatik bir yıllık belge askıya alınması","Yolda sürüş beceri testinin zorunlu olarak yeniden alınması","CDL'nin yalnızca hazmat belgesine dönüştürülmesi"],"explanation":"İstisna dışı (Kategori A/C) sürücüler, artık National Registry'den elektronik olarak iletilen güncel bir MEC bulundurmalıdır; bunu yapmamak CDL/CLP'nin düşürülmesiyle (downgrade) sonuçlanır. Kaynak: Nebraska DMV'nin Sağlık Muayenesi Sertifikalandırma kuralına ilişkin haber bülteni."},"99":{"q":"Bir Nebraska CDL beceri testi randevusu genellikle nasıl ayarlanır ve kim aramak zorundadır?","options":["Yalnızca randevuyla ve testi gerçekten alacak kişinin aramayı yapması gerekir","Yalnızca randevusuz (walk-in), randevu kabul edilmez","İşverenin güvenlik direktörü tarafından sürücü adına","Yalnızca çevrimiçi, telefon seçeneği bulunmaz"],"explanation":"Nebraska, CDL beceri testlerini yalnızca randevuyla uygular ve testi alacak olan başvuru sahibinin, randevu almak için arayan kişi olması gerekir. Kaynak: Nebraska DMV, CDL Testing sayfası."}},"es":{"0":{"q":"En las carreteras de Nebraska, ¿cuál es el ancho total máximo permitido para un vehículo comercial sin un permiso especial?","options":["8 pies 6 pulgadas","8 pies","9 pies","10 pies"],"explanation":"Nebraska limita el ancho total máximo del vehículo a 8 pies 6 pulgadas (102 inches). Fuente: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska', ítem 1; en concordancia con Neb. Rev. Stat. 60-6,288."},"1":{"q":"¿Cuál es la altura total máxima del vehículo permitida en las carreteras de Nebraska sin un permiso?","options":["14 pies 6 pulgadas","13 pies 6 pulgadas","14 pies","15 pies"],"explanation":"La altura total máxima del vehículo en Nebraska es de 14 pies 6 pulgadas. Fuente: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska', ítem 2."},"2":{"q":"En Nebraska, ¿cuál es la longitud total máxima para un vehículo individual (no una combinación)?","options":["40 pies","45 pies","53 pies","35 pies"],"explanation":"Un vehículo individual en Nebraska no puede tener más de 40 pies de longitud total. Fuente: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska', ítem 3."},"3":{"q":"¿Cuál es la longitud máxima legal de un semirremolque (excluyendo el camión tractor) en Nebraska?","options":["53 pies","48 pies","40 pies","57 pies"],"explanation":"Nebraska permite un semirremolque (excluyendo el camión tractor) de hasta 53 pies. Fuente: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska', ítem 5."},"4":{"q":"¿Cuál es la longitud total máxima para una combinación de vehículos en Nebraska?","options":["65 pies","60 pies","75 pies","53 pies"],"explanation":"Nebraska establece la longitud total máxima para una combinación de vehículos en 65 pies. Fuente: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska', ítem 4."},"5":{"q":"¿Cuál es la carga máxima por rueda individual permitida en una carretera de Nebraska?","options":["10,000 libras","12,000 libras","8,000 libras","20,000 libras"],"explanation":"Ninguna rueda puede soportar una carga bruta mayor a 10,000 libras en ninguna carretera de Nebraska. Fuente: NDOT 'Legal Sizes and Weights', ítem 7; Neb. Rev. Stat. 60-6,294."},"6":{"q":"¿Cuál es la carga máxima por eje individual permitida en las carreteras de Nebraska?","options":["20,000 libras","18,000 libras","22,400 libras","34,000 libras"],"explanation":"Nebraska limita un eje individual a 20,000 libras. Fuente: NDOT 'Legal Sizes and Weights', ítem 8; Neb. Rev. Stat. 60-6,294."},"7":{"q":"¿Cuál es la carga máxima por eje tándem permitida en las carreteras de Nebraska?","options":["34,000 libras","36,000 libras","40,000 libras","32,000 libras"],"explanation":"El peso bruto transmitido a través de un grupo de ejes tándem no puede exceder las 34,000 libras en Nebraska. Fuente: NDOT 'Legal Sizes and Weights', ítem 9; Neb. Rev. Stat. 60-6,294."},"8":{"q":"¿Cuál es el peso bruto máximo para un vehículo que circula en rutas designadas como Interestatales en Nebraska sin un permiso?","options":["80,000 libras","94,000 libras","84,000 libras","76,000 libras"],"explanation":"El peso bruto legal en rutas designadas como Interestatales en Nebraska es de 80,000 libras. Fuente: NDOT 'Legal Sizes and Weights', nota sobre excepciones de peso; Neb. Rev. Stat. 60-6,294."},"9":{"q":"En las rutas de los EE. UU. y estatales (no Interestatales) en Nebraska, ¿cuál es el límite legal de peso bruto?","options":["94,000 libras","80,000 libras","90,000 libras","100,000 libras"],"explanation":"Nebraska permite un peso bruto legal de 94,000 libras en las rutas de los EE. UU. y estatales (sujeto a los límites de eje y de la fórmula de puentes), frente a las 80,000 libras en la Interestatal. Fuente: NDOT 'Legal Sizes and Weights', nota sobre excepciones de peso."},"10":{"q":"¿Cómo define Nebraska un 'eje tándem' para efectos de los límites de peso?","options":["Dos ejes consecutivos separados por más de 40 y no más de 96 pulgadas","Dos ejes separados por menos de 40 pulgadas","Cualquier par de ejes a no más de 120 pulgadas entre sí","Dos ejes separados exactamente por 60 pulgadas"],"explanation":"Nebraska define un eje tándem como cualquier par de ejes consecutivos cuyos centros están separados por más de 40 pulgadas y no más de 96 pulgadas. Fuente: Neb. Rev. Stat. 60-6,294."},"11":{"q":"Según la tabla de pesos por grupo de ejes de Nebraska (fórmula federal de puentes), ¿cuál es la carga máxima para dos ejes separados por 8 pies?","options":["34,000 libras","38,000 libras","40,000 libras","36,000 libras"],"explanation":"La tabla de 'Carga Máxima en Cualquier Grupo de Dos o Más Ejes' de Nebraska muestra 34,000 libras para dos ejes separados por 8 pies. Fuente: tabla de grupo de ejes de NDOT 'Legal Sizes and Weights'; Neb. Rev. Stat. 60-6,294."},"12":{"q":"Según la tabla de pesos por grupo de ejes de Nebraska, ¿cuál es la carga máxima en cinco ejes separados por 51 pies (extremos)?","options":["80,000 libras","76,000 libras","84,000 libras","78,000 libras"],"explanation":"La tabla de la fórmula de puentes de Nebraska indica 80,000 libras para cinco ejes separados por 51 pies entre los extremos. Fuente: tabla de grupo de ejes de NDOT 'Legal Sizes and Weights'; Neb. Rev. Stat. 60-6,294."},"13":{"q":"¿Qué determina la carga máxima que puede soportar un grupo de dos o más ejes en las carreteras de Nebraska?","options":["La distancia de separación entre los ejes extremos del grupo, según la tabla de la fórmula de puentes","Únicamente el número de neumáticos del vehículo","La potencia del motor","Únicamente el ancho del remolque"],"explanation":"Nebraska limita la carga en cualquier grupo de ejes según la distancia entre los ejes extremos del grupo, aplicando la tabla de la fórmula federal de puentes. Fuente: NDOT 'Legal Sizes and Weights'; Neb. Rev. Stat. 60-6,294."},"14":{"q":"¿Qué agencia emite los permisos de exceso de tamaño/peso para circular por las carreteras estatales de Nebraska?","options":["Nebraska Department of Transportation (NDOT)","Nebraska Department of Motor Vehicles","Nebraska State Patrol","La oficina del alguacil del condado"],"explanation":"El Nebraska Department of Transportation (NDOT) emite los permisos de exceso de tamaño/peso para las carreteras estatales; el DMV remite a los solicitantes al NDOT. Fuente: Preguntas frecuentes del Nebraska DMV; NDOT Permits / Automated Truck Permit System."},"15":{"q":"¿Cómo puede un transportista obtener con mayor frecuencia un permiso de exceso de tamaño/peso del DOT de Nebraska?","options":["A través del Automated Truck Permit System en línea del NDOT","Enviando por correo un formulario en papel al DMV","Llamando al departamento de policía local","Los permisos no se pueden obtener con anticipación"],"explanation":"Los permisos de exceso de tamaño/peso de Nebraska se obtienen a través del Automated Truck Permit System en línea del NDOT (dottruckpermits.nebraska.gov). Fuente: NDOT Permits; Preguntas frecuentes del Nebraska DMV."},"16":{"q":"¿Cuándo se requiere un permiso de exceso de tamaño o peso para circular por las carreteras de Nebraska?","options":["Cuando el vehículo o la carga excede los límites legales máximos de tamaño o peso","Solo al cruzar a otro estado","Solo en caminos de grava","Solo para vehículos que transportan materiales peligrosos"],"explanation":"Se requiere un permiso especial del NDOT para mover un vehículo o carga que exceda el tamaño o peso legal máximo; no se emite ningún permiso para una carga que podría reducirse o desmontarse sin gran dificultad. Fuente: NDOT 'Legal Sizes and Weights' (Excess Size or Weight); Neb. Rev. Stat. 60-6,294."},"17":{"q":"En Nebraska, ¿por encima de qué altura asume el operador el riesgo de pérdida y la responsabilidad por golpear obstrucciones elevadas?","options":["Más de 12 pies 6 pulgadas","Más de 13 pies 6 pulgadas","Más de 14 pies 6 pulgadas","Más de 11 pies"],"explanation":"La ley de Nebraska establece que los propietarios/operadores de un vehículo que exceda los 12 pies 6 pulgadas de altura asumen el riesgo y son responsables de los daños a las obstrucciones elevadas. Fuente: NDOT 'Legal Sizes and Weights', excepción de altura."},"18":{"q":"¿Qué excepción especial otorga Nebraska al límite de ancho de 8 pies 6 pulgadas?","options":["Maquinaria agrícola movida durante las horas de luz del día en el curso normal de las operaciones agrícolas","Cualquier remolque de plataforma que transporte acero","Todos los remolques refrigerados","Vehículos registrados fuera del estado"],"explanation":"El límite de ancho de 8'6\" de Nebraska no aplica a la maquinaria agrícola en movimiento temporal durante las horas de luz del día en el curso normal de las operaciones agrícolas. Fuente: NDOT 'Legal Sizes and Weights', excepción de ancho."},"19":{"q":"Según las reglas estatutarias de peso de Nebraska, ¿qué sucede si un camión cruza un puente con una carga bruta que excede la capacidad publicada del puente y causa daños?","options":["El propietario del vehículo es responsable de todos los daños","La responsabilidad se comparte por igual con el NDOT","No hay responsabilidad si se compró un permiso","Solo el conductor, no el propietario, es responsable"],"explanation":"La ley de Nebraska responsabiliza al propietario del camión de todos los daños resultantes de cruzar un puente con una carga superior a su capacidad publicada. Fuente: NDOT 'Legal Sizes and Weights' (disposición sobre puentes); Neb. Rev. Stat. 60-6,294."},"20":{"q":"En Nebraska, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una Clasificación de Peso Bruto Combinado (GCWR) de 26,001 libras o más, siempre que el GVWR de la(s) unidad(es) remolcada(s) exceda las 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Nebraska define una CDL Clase A como una combinación de vehículos con un GCWR de 26,001 libras o más donde la(s) unidad(es) remolcada(s) tienen un GVWR superior a 10,000 libras. Fuente: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"21":{"q":"Según las reglas de Nebraska, ¿qué clase de CDL cubre un vehículo individual con un GVWR de 26,001 libras o más (o tal vehículo remolcando una unidad de no más de 10,000 libras)?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"Nebraska define una CDL Clase B como un vehículo individual con un GVWR de 26,001 libras o más, o cualquier vehículo de ese tipo que remolque una unidad que no exceda las 10,000 libras. Fuente: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"22":{"q":"Un conductor de Nebraska opera un vehículo individual de menos de 26,001 libras de GVWR que requiere llevar carteles (placards) por materiales peligrosos. ¿Qué clase de CDL aplica?","options":["Clase A","Clase B","Clase C","Clase O"],"explanation":"La CDL Clase C de Nebraska cubre un vehículo individual de menos de 26,001 libras de GVWR (o que remolca una unidad de hasta 10,000 libras) que requiere llevar carteles (placards) por materiales peligrosos o que es un autobús diseñado para transportar 16 o más pasajeros incluyendo al conductor. Fuente: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"23":{"q":"Según la definición de Clase C de Nebraska, ¿para cuántos pasajeros debe estar diseñado un autobús para que requiera una CDL?","options":["8 o más incluyendo al conductor","11 o más incluyendo al conductor","16 o más incluyendo al conductor","24 o más incluyendo al conductor"],"explanation":"La definición de Clase C de Nebraska incluye cualquier autobús diseñado para transportar 16 o más pasajeros incluyendo al conductor. Fuente: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"24":{"q":"¿Cuál es la edad mínima para que se expida una licencia de conducir comercial de Nebraska para operación intraestatal (solo dentro de Nebraska)?","options":["16 años","17 años","18 años","21 años"],"explanation":"Nebraska no expide una CDL ni un CLP a ninguna persona que no haya cumplido los 18 años de edad; 18 es la edad mínima para la operación intraestatal de CDL. Fuente: Neb. Rev. Stat. 60-4,143; páginas de CDL del Nebraska DMV."},"25":{"q":"Un titular de CDL de Nebraska quiere conducir un vehículo comercial a través de las fronteras estatales (interestatal). ¿Cuál es la edad mínima para hacerlo?","options":["18 años","19 años","20 años","21 años"],"explanation":"Si bien Nebraska expide una CDL intraestatal a los 18 años, un conductor debe tener al menos 21 años para operar un vehículo motorizado comercial en el comercio interestatal. Fuente: páginas de CDL del Nebraska DMV; 49 CFR 391.11 aplicado como la regla de Nebraska."},"26":{"q":"¿Qué endoso necesita un conductor de Nebraska para transportar materiales peligrosos en cantidades que requieren carteles (placards)?","options":["Endoso N","Endoso H","Endoso T","Endoso X"],"explanation":"El endoso H (Materiales Peligrosos) se requiere para transportar materiales peligrosos con carteles (placards); requiere un examen de conocimientos y una evaluación de amenaza de seguridad de la TSA. Fuente: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"27":{"q":"Antes de que Nebraska expida una CDL con el endoso de HazMat (H), el solicitante debe completar ¿cuál paso federal adicional de verificación de antecedentes?","options":["Una evaluación de amenaza de seguridad de la TSA con toma de huellas dactilares","Una entrevista de derechos civiles del FBI","Un registro de sustancias controladas de la DEA","Una revisión de naturalización de USCIS"],"explanation":"Además de aprobar el examen de conocimientos de HazMat, Nebraska exige que los solicitantes completen una evaluación de amenaza de seguridad de la Transportation Security Administration (TSA), que incluye preinscripción y toma de huellas dactilares, antes de que se expida el endoso H. Fuente: Nebraska DMV, CDL Classes, Endorsements and Restrictions; programa HME de la TSA."},"28":{"q":"¿Con qué frecuencia debe un conductor de Nebraska renovar el endoso de HazMat (H), incluyendo la presentación de nuevas huellas dactilares para la evaluación de amenaza de la TSA?","options":["Al menos cada 2 años","Al menos cada 3 años","Al menos cada 5 años","Al menos cada 8 años"],"explanation":"El endoso de HazMat y su evaluación de amenaza de seguridad de la TSA deben renovarse al menos cada cinco años, presentando nuevas huellas dactilares en la renovación. Fuente: páginas de CDL del Nebraska DMV; programa HME de la TSA (49 CFR 1572)."},"29":{"q":"¿Qué endoso se requiere en Nebraska para conducir un vehículo cisterna usado para transportar líquidos o gases a granel?","options":["Endoso T","Endoso N","Endoso H","Endoso P"],"explanation":"El endoso N (Vehículo Cisterna) se requiere para operar un vehículo cisterna y requiere aprobar un examen de conocimientos. Fuente: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"30":{"q":"Un conductor de Nebraska quiere arrastrar remolques dobles o triples. ¿Qué endoso se requiere?","options":["Endoso N","Endoso P","Endoso T","Endoso S"],"explanation":"El endoso T (Dobles/Triples) se requiere para arrastrar remolques dobles y triples y requiere aprobar un examen de conocimientos. Fuente: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"31":{"q":"¿Qué endoso debe tener un titular de CDL de Nebraska para conducir un vehículo diseñado para transportar 16 o más personas, como un autobús de pasajeros?","options":["Endoso S","Endoso P","Endoso N","Endoso H"],"explanation":"El endoso P (Pasajeros) se requiere para vehículos diseñados para transportar 16 o más personas (incluyendo al conductor) y requiere un examen de conocimientos más un examen de habilidades en un vehículo representativo. Fuente: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"32":{"q":"En Nebraska, el endoso S (Autobús Escolar) solo puede expedirse junto con ¿cuál otro endoso?","options":["El endoso H (HazMat)","El endoso N (Cisterna)","El endoso P (Pasajeros)","El endoso T (Dobles/Triples)"],"explanation":"Nebraska exige que el endoso S (Autobús Escolar) acompañe al endoso P (Pasajeros); un conductor no puede tener S sin P. Fuente: Nebraska DMV, CDL Classes, Endorsements and Restrictions."},"33":{"q":"¿Cuál es el período mínimo que un conductor de Nebraska debe mantener un Permiso de Aprendiz Comercial (CLP) antes de presentar el examen de habilidades de la CDL?","options":["7 días","10 días","14 días","30 días"],"explanation":"Nebraska, siguiendo la regla federal, exige que un conductor mantenga un CLP válido durante un mínimo de 14 días antes de presentar el examen de habilidades de la CDL. Fuente: Nebraska DMV, Commercial Learner's Permit; 49 CFR 383.25."},"34":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Nebraska?","options":["180 días","1 año","2 años","5 años"],"explanation":"Un CLP de Nebraska es válido por 1 año. Si vence antes de que se aprueben los tres segmentos del examen de habilidades, los segmentos previamente aprobados quedan inválidos y se debe volver a presentar todo el examen de habilidades. Fuente: Nebraska DMV, Commercial Learner's Permit."},"35":{"q":"¿En qué clases de CDL expide Nebraska un Permiso de Aprendiz Comercial (CLP)?","options":["Solo Clase A y Clase B","Solo Clase C","Clase A, B y C","Solo Clase B y Clase C"],"explanation":"Nebraska expide CLP solo en Clase A y Clase B. Fuente: Nebraska DMV, Commercial Learner's Permit."},"36":{"q":"¿Qué conjunto de endosos puede llevar un Permiso de Aprendiz Comercial (CLP) de Nebraska?","options":["H, T y X","P, S y N","Solo H y N","Solo T y X"],"explanation":"Un CLP de Nebraska solo puede llevar los endosos P (Pasajeros), S (Autobús Escolar) y N (Cisterna, restringido a vacío/sin carga); H, T y X no se permiten en un CLP. Fuente: Nebraska DMV, Commercial Learner's Permit; 49 CFR 383.25."},"37":{"q":"¿Cuántos documentos que comprueben una dirección principal en Nebraska debe proporcionar un solicitante de CDL/CLP para establecer la residencia?","options":["Un documento","Dos documentos de fuentes diferentes","Tres documentos","No se requiere comprobante de residencia"],"explanation":"Nebraska exige dos documentos de fuentes diferentes que muestren la dirección principal del solicitante en Nebraska; no se acepta un apartado postal (P.O. Box). El solicitante también debe proporcionar comprobante de identidad, un número de Seguro Social y comprobante de ciudadanía estadounidense o estatus legal. Fuente: Nebraska DMV, CDL Documentation Requirements."},"38":{"q":"Según el requisito federal de Capacitación para Conductores de Nivel Inicial (ELDT) de Nebraska, ¿dónde debe completarse y registrarse la capacitación de un conductor?","options":["Con un proveedor incluido en el FMCSA Training Provider Registry","En cualquier escuela de conducción privada que el conductor elija","Únicamente a través de un aprendizaje en el trabajo","En una estación de examen del Nebraska DMV"],"explanation":"La ELDT, vigente desde el 7 de febrero de 2022, exige que los solicitantes de Clase A/B por primera vez, las actualizaciones de B a A y los solicitantes por primera vez de los endosos P, S o H completen la capacitación con un proveedor incluido en el FMCSA Training Provider Registry, que registra la finalización. Fuente: Nebraska DMV, Entry Level Driver Training (ELDT); 49 CFR Part 380."},"39":{"q":"¿Qué categoría de autocertificación médica de CDL de Nebraska aplica a un conductor que opera en el comercio interestatal y SÍ está sujeto a los requisitos médicos federales (examen físico del DOT)?","options":["Interestatal No Exento (Categoría A)","Interestatal Exento (Categoría B)","Intraestatal No Exento (Categoría C)","Intraestatal Exento (Categoría D)"],"explanation":"La Categoría A, Interestatal No Exento, aplica a los conductores sujetos a los requisitos médicos y de visión federales; deben proporcionar y mantener archivado en el DMV un certificado vigente de examinador médico de un proveedor que figure en el National Registry. Fuente: Nebraska DMV, CDL Self-Certification Categories; Neb. Rev. Stat. 60-4,144.01."},"40":{"q":"Al operar un vehículo motorizado comercial (CMV) en Nebraska, ¿con qué concentración de alcohol en sangre (BAC) se considera que un conductor conduce bajo los efectos del alcohol y comete una infracción mayor que conlleva descalificación?","options":["0.02 o más","0.04 o más","0.08 o más","0.10 o más"],"explanation":"Nebraska, siguiendo el 49 CFR 383.51 y el Manual de CDL de Nebraska, considera que operar un CMV con un BAC de 0.04 o más es una infracción mayor que conlleva descalificación. El límite de 0.08 aplica a los vehículos no comerciales. Fuente: página de Descalificación de CDL del Nebraska DMV; Manual de CDL de Nebraska."},"41":{"q":"Según la ley de consentimiento implícito de Nebraska, ¿cuál es la consecuencia de que un titular de CDL rechace una prueba química (de aliento, sangre u orina) después de operar un vehículo motorizado?","options":["Solo una carta de advertencia, sin descalificación","Se trata como una infracción mayor, descalificando la CDL igual que una condena por DUI","Una suspensión de 30 días que no afecta la CDL","Una multa administrativa de $100 sin acción sobre la licencia"],"explanation":"La ley de consentimiento implícito de Nebraska trata el rechazo de una prueba de alcohol/drogas como una infracción mayor que conlleva descalificación, con la misma descalificación de CDL que un DUI (1 año por la primera infracción, de por vida por la segunda). Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"42":{"q":"En Nebraska, ¿por cuánto tiempo se descalifica a un titular de CDL por una PRIMERA infracción mayor (como DUI o rechazo de prueba) cuando NO se transportan materiales peligrosos con carteles (placards)?","options":["60 días","6 meses","1 año","3 años"],"explanation":"Una primera infracción mayor descalifica a un titular de CDL de Nebraska por 1 año. Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"43":{"q":"Si un conductor de Nebraska comete una primera infracción mayor mientras opera un CMV que requiere llevar carteles (placards) por materiales peligrosos, ¿por cuánto tiempo dura la descalificación?","options":["1 año","2 años","3 años","De por vida"],"explanation":"Una primera infracción mayor mientras se transportan materiales peligrosos con carteles (placards) eleva la descalificación de 1 año a 3 años. Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"44":{"q":"¿Cuál es el período de descalificación para un titular de CDL de Nebraska que es condenado por una SEGUNDA infracción mayor?","options":["3 años","5 años","10 años","De por vida"],"explanation":"Una segunda infracción mayor resulta en una descalificación de CDL de por vida en Nebraska. Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"45":{"q":"¿Cuál de las siguientes se clasifica como una infracción mayor que conlleva descalificación para un titular de CDL de Nebraska, en lugar de una infracción de tránsito grave?","options":["Seguir a otro vehículo demasiado de cerca","Darse a la fuga del lugar de un accidente","Cambios de carril indebidos o erráticos","Exceder el límite de velocidad por 15 mph o más"],"explanation":"Darse a la fuga del lugar de un accidente es una infracción MAYOR (descalificación de 1 año/de por vida). Seguir demasiado de cerca, los cambios de carril erráticos y el exceso de velocidad son infracciones de tránsito GRAVES (60/120 días). Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"46":{"q":"¿Cuánto debe exceder un titular de CDL de Nebraska el límite de velocidad publicado para que cuente como la infracción de tránsito grave de 'exceso de velocidad'?","options":["10 mph o más por encima","15 mph o más por encima","20 mph o más por encima","25 mph o más por encima"],"explanation":"Exceder el límite publicado por 15 mph o más es la infracción de tránsito grave de 'exceso de velocidad' en Nebraska. Fuente: Manual de CDL de Nebraska; página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"47":{"q":"En Nebraska, ¿por cuánto tiempo se descalifica a un titular de CDL por ser condenado por DOS infracciones de tránsito graves en incidentes separados dentro de un período de 3 años?","options":["30 días","60 días","120 días","1 año"],"explanation":"Dos infracciones de tránsito graves dentro de 3 años resultan en una descalificación de CDL de 60 días. Fuente: página de Descalificación de CDL / MCSIA del Nebraska DMV; 49 CFR 383.51."},"48":{"q":"¿Por cuánto tiempo se descalifica a un titular de CDL de Nebraska por cometer TRES infracciones de tránsito graves en incidentes separados dentro de un período de 3 años?","options":["60 días","90 días","120 días","180 días"],"explanation":"Tres infracciones de tránsito graves dentro de 3 años resultan en una descalificación de CDL de 120 días (que debe seguir a cualquier descalificación de 60 días ya impuesta). Fuente: página MCSIA del Nebraska DMV; 49 CFR 383.51."},"49":{"q":"¿Cuál de las siguientes está en la lista de infracciones de tránsito GRAVES de Nebraska para titulares de CDL?","options":["Conducir con un BAC de 0.04 o más","Enviar mensajes de texto mientras se conduce un CMV","Rechazar una prueba química","Usar un CMV para cometer un delito grave"],"explanation":"Enviar mensajes de texto mientras se conduce un CMV es una infracción de tránsito grave en Nebraska. Las otras tres mencionadas son infracciones mayores. Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"50":{"q":"Operar un CMV sin la clase adecuada de CDL o el endoso requerido para el vehículo que se conduce se clasifica en Nebraska como ¿qué tipo de infracción?","options":["Una infracción menor de equipo","Una infracción de tránsito grave","Una infracción mayor que conlleva descalificación","Una infracción de orden de fuera de servicio"],"explanation":"Conducir un CMV sin la clase adecuada de CDL o el endoso requerido es una de las infracciones de tránsito graves de Nebraska, sujeta a descalificación de 60 días/120 días cuando se comete de manera reiterada. Fuente: página MCSIA del Nebraska DMV; 49 CFR 383.51."},"51":{"q":"Por una PRIMERA condena por una infracción en un cruce ferroviario a nivel, ¿por cuánto tiempo se descalifica a un titular de CDL de Nebraska?","options":["Al menos 30 días","Al menos 60 días","Al menos 120 días","Al menos 1 año"],"explanation":"Una primera infracción en un cruce ferroviario a nivel resulta en una descalificación de al menos 60 días. Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"52":{"q":"¿Cuál es el período de descalificación para la SEGUNDA infracción en un cruce ferroviario a nivel de un titular de CDL de Nebraska dentro de un período de 3 años?","options":["Al menos 60 días","Al menos 90 días","Al menos 120 días","Al menos 1 año"],"explanation":"Una segunda infracción en un cruce ferroviario a nivel dentro de 3 años resulta en una descalificación de al menos 120 días. Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"53":{"q":"¿Cuál es la descalificación para una TERCERA infracción en un cruce ferroviario a nivel dentro de un período de 3 años en Nebraska?","options":["Al menos 120 días","Al menos 180 días","Al menos 1 año","Al menos 3 años"],"explanation":"Una tercera infracción en un cruce ferroviario a nivel dentro de 3 años resulta en una descalificación de al menos 1 año. Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"54":{"q":"Por una PRIMERA condena por violar una orden de fuera de servicio (OOS) mientras se conduce un CMV estándar en Nebraska, ¿cuál es el período de descalificación?","options":["30 a 60 días","90 días","180 días a 1 año","2 a 5 años"],"explanation":"Una primera violación de orden de fuera de servicio en un CMV estándar resulta en una descalificación de 180 días a 1 año. Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"55":{"q":"¿Cuál es el período de descalificación para una SEGUNDA violación de orden de fuera de servicio dentro de un período de 10 años mientras se conduce un CMV estándar en Nebraska?","options":["180 días a 1 año","1 a 2 años","2 a 5 años","De por vida"],"explanation":"Una segunda violación de orden de fuera de servicio dentro de 10 años resulta en una descalificación de 2 a 5 años. Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"56":{"q":"Cuando la violación de la orden de FUERA DE SERVICIO involucra un CMV que transporta materiales peligrosos que requieren carteles (placards) o diseñado para transportar 16 o más pasajeros, ¿cuál es la descalificación por PRIMERA condena en Nebraska?","options":["90 días a 1 año","180 días a 2 años","2 a 5 años","3 a 5 años"],"explanation":"Una primera violación de orden de fuera de servicio que involucra materiales peligrosos con carteles (placards) o un vehículo diseñado para 16 o más pasajeros conlleva una descalificación agravada de 180 días a 2 años. Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"57":{"q":"Conducir un CMV mientras su CDL está suspendida, revocada, o mientras usted está descalificado es tratado por Nebraska como ¿qué tipo de infracción?","options":["Una infracción de tránsito grave (60/120 días)","Una infracción mayor que conlleva descalificación (1 año/de por vida)","Una violación de fuera de servicio (180 días)","Una infracción de papeleo que no conlleva descalificación"],"explanation":"Conducir un CMV mientras la CDL propia está revocada, suspendida, cancelada, o mientras se está descalificado es una infracción mayor, que conlleva una descalificación de 1 año por la primera infracción y de por vida por la segunda. Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"58":{"q":"Según la ley de Nebraska (Neb. Rev. Stat. 60-6,179.01), ¿cuál es la multa por una PRIMERA infracción de enviar mensajes de texto mientras se conduce?","options":["$100","$200","$300","$500"],"explanation":"El estatuto antimensajes de texto de Nebraska (Neb. Rev. Stat. 60-6,179.01) establece una multa de $200 por la primera infracción, $300 por la segunda y $500 por la tercera o posteriores, más tres puntos. Para los conductores con CDL, enviar mensajes de texto de manera reiterada en un CMV también es una infracción de tránsito grave. Fuente: Neb. Rev. Stat. 60-6,179.01."},"59":{"q":"Usar un CMV en la comisión de un delito grave que involucre la fabricación, distribución o dispensación de una sustancia controlada resulta en ¿qué penalidad para un titular de CDL de Nebraska?","options":["Una descalificación de 1 año","Una descalificación de 3 años","Una descalificación de 5 años","Una descalificación de por vida sin reinstalación"],"explanation":"Usar cualquier vehículo motorizado para cometer un delito grave que involucre la fabricación, distribución o dispensación de una sustancia controlada resulta en una descalificación de por vida que no es elegible para la reinstalación a los 10 años disponible para algunos otros casos de por vida. Fuente: página de Descalificación de CDL del Nebraska DMV; 49 CFR 383.51."},"60":{"q":"En una autopista interestatal de Nebraska, una grúa de remolque está detenida en el acotamiento con luces ámbar destellando. Usted conduce un CMV en el carril derecho y hay un carril libre a su izquierda. Según la ley de Nebraska de cambiarse de carril (Move Over), ¿qué debe hacer?","options":["Cambiarse a un carril que esté al menos a un carril de circulación de distancia del vehículo detenido cuando sea seguro hacerlo","Mantener su velocidad pero tocar la bocina al pasar","Detenerse por completo hasta que la grúa de remolque se retire","Continuar en el carril derecho siempre que vaya a la velocidad límite o por debajo de ella"],"explanation":"La ley de cambiarse de carril (Move Over) de Nebraska (Neb. Rev. Stat. 60-6,378.01) exige que los conductores que se aproximan a un vehículo detenido con luces destellantes reduzcan la velocidad y, cuando sea seguro, se cambien a un carril que esté al menos a un carril de circulación de distancia del vehículo detenido. Fuente: Neb. Rev. Stat. 60-6,378.01 / NDOT 'Move Over, Slow Down'."},"61":{"q":"La ley de cambiarse de carril (Move Over) de Nebraska se amplió considerablemente con la LB 530, vigente a partir del 3 de septiembre de 2025. A partir de ese cambio, ¿para cuál de las siguientes opciones deben los conductores reducir la velocidad y cambiarse de carril?","options":["Solo vehículos de emergencia autorizados que muestren luces rojas o azules destellantes","Solo grúas de remolque y vehículos de mantenimiento de carreteras","Todos los vehículos detenidos y usuarios vulnerables de la vía al costado de la carretera, incluyendo peatones, ciclistas y equipo agrícola","Solo vehículos detenidos dentro de una zona de obras de construcción activa"],"explanation":"Bajo la LB 530 (vigente desde el 3 de septiembre de 2025), Nebraska amplió el requisito de cambiarse de carril más allá de los vehículos de emergencia y de asistencia en carretera para incluir a TODOS los vehículos detenidos y usuarios vulnerables de la vía al costado de la carretera, incluyendo peatones, ciclistas, personas en cruces peatonales y vehículos o equipos agrícolas. Fuente: Neb. LB 530 / comunicado de prensa de NDOT 'Nebraska's Updated Move-Over Law Takes Effect Sept. 3'."},"62":{"q":"Según la ley de cambiarse de carril (Move Over) de Nebraska, cuando usted no puede cambiar de carril de forma segura ante un vehículo detenido que muestra luces de advertencia, ¿qué debe hacer en su lugar?","options":["Detenerse por completo sobre la calzada hasta que el tránsito se despeje","Reducir su velocidad, mantener una velocidad segura para las condiciones y proceder con el debido cuidado y precaución","Mantener la velocidad límite señalizada y pasar normalmente","Acelerar para despejar la zona lo más rápido posible"],"explanation":"Neb. Rev. Stat. 60-6,378.01 establece que si no es posible o seguro cambiar de carril, el conductor debe reducir la velocidad, mantener una velocidad segura considerando el vehículo detenido, el clima, la vía y las condiciones del tránsito, y proceder con el debido cuidado y precaución. Fuente: Neb. Rev. Stat. 60-6,378.01."},"63":{"q":"¿Cuál es la velocidad máxima para un camión comercial en un tramo rural del Sistema Nacional de carreteras interestatales en Nebraska, salvo que se indique lo contrario?","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"Neb. Rev. Stat. 60-6,186 establece la velocidad máxima en 75 mph en las carreteras interestatales rurales. Nebraska no establece un límite de velocidad legal separado y más bajo para camiones; los CMV siguen los mismos máximos señalizados que los demás vehículos. Fuente: Neb. Rev. Stat. 60-6,186 / información de límites de velocidad de NDOT."},"64":{"q":"En una autopista expressway o super-two de Nebraska que forma parte del sistema de carreteras estatales, ¿cuál es la velocidad máxima salvo que se indique lo contrario?","options":["55 mph","65 mph","70 mph","75 mph"],"explanation":"Neb. Rev. Stat. 60-6,186 establece 70 mph en una autopista expressway, super-two o freeway que forma parte del sistema de carreteras estatales. (La interestatal rural es de 75 mph; las demás carreteras estatales son de 65 mph). Fuente: Neb. Rev. Stat. 60-6,186 / folleto de límites de velocidad de NDOT."},"65":{"q":"¿Establece la ley de Nebraska un límite de velocidad legal máximo separado y más bajo para los camiones comerciales en comparación con los automóviles de pasajeros?","options":["Sí, los camiones están limitados a 65 mph en todo el estado","Sí, los camiones deben circular 10 mph por debajo del límite señalizado","No, los límites de velocidad máximos legales en Neb. Rev. Stat. 60-6,186 se aplican de manera uniforme a todos los vehículos","Sí, pero solo en el sistema interestatal"],"explanation":"Neb. Rev. Stat. 60-6,186 establece velocidades máximas legales uniformes por categoría de vía sin un límite de velocidad separado para camiones; los vehículos comerciales deben obedecer los mismos máximos señalizados que el resto del tránsito. Fuente: Neb. Rev. Stat. 60-6,186."},"66":{"q":"En una carretera estatal de Nebraska que NO sea una expressway, super-two ni freeway, ¿cuál es la velocidad máxima salvo que se indique lo contrario?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Neb. Rev. Stat. 60-6,186 establece 65 mph en cualquier parte del sistema de carreteras estatales que no sea una expressway, super-two o freeway. Fuente: Neb. Rev. Stat. 60-6,186 / folleto de límites de velocidad de NDOT."},"67":{"q":"Un autobús que transporta pasajeros o un vehículo de materiales peligrosos con placas (placarded) se aproxima a un cruce de ferrocarril a nivel en Nebraska. ¿Dentro de qué distancia del riel más cercano debe detenerse el conductor?","options":["Entre 5 y 25 feet","Entre 15 y 50 feet","Entre 25 y 75 feet","Entre 50 y 100 feet"],"explanation":"Los autobuses que transportan pasajeros y los CMV de HazMat con placas (placarded) deben detenerse entre 15 y 50 feet del riel más cercano, y luego mirar y escuchar antes de cruzar (49 CFR 392.10, según se enseña en el Manual CDL de Nebraska). Fuente: Manual CDL de Nebraska / 49 CFR 392.10."},"68":{"q":"Después de detenerse en un cruce de ferrocarril, un conductor con CDL en Nebraska comienza a cruzar las vías. ¿Qué exige la regla respecto a los cambios de marcha?","options":["Reducir una marcha mientras está sobre las vías para mantener el control","Cruzar en una marcha que le permita terminar sin cambiar de marcha; no cambie de marcha mientras esté sobre las vías","Poner el cambio en neutro mientras cruza para reducir el esfuerzo del motor","Subir a la marcha más alta antes de llegar a los rieles"],"explanation":"El Manual CDL de Nebraska y 49 CFR 392.10-392.11 exigen cruzar en una marcha que le permita completar el cruce sin cambiar de marcha; no debe cambiar de marcha mientras cualquier parte del vehículo esté sobre las vías. Fuente: Manual CDL de Nebraska / 49 CFR 392.10-392.11."},"69":{"q":"¿Cuándo NO se exige que los vehículos de HazMat con placas (placarded) y los autobuses de pasajeros en Nebraska se detengan en un cruce de ferrocarril a nivel?","options":["Cada vez que el tránsito detrás de ellos sea intenso","En un cruce controlado por un semáforo de tránsito en funcionamiento que muestra verde, o señalizado con un letrero 'Exempt'","En cualquier cruce en un distrito residencial","Solo en caminos de grava"],"explanation":"Bajo 49 CFR 392.10 (enseñado en el Manual CDL de Nebraska), el requisito de detenerse no aplica, entre otros, en un cruce controlado por un semáforo de tránsito en funcionamiento que muestra verde, en un cruce de tranvía/ramal, o en un cruce a nivel industrial/de ramal señalizado con un letrero 'Exempt'. Fuente: Manual CDL de Nebraska / 49 CFR 392.10."},"70":{"q":"Al encontrarse con un autobús escolar de Nebraska detenido o al rebasarlo, con sus luces rojas destellando y el brazo de pare extendido, ¿qué deben hacer los demás conductores (cuando no aplique ninguna excepción)?","options":["Reducir a 25 mph y pasar con precaución","Detenerse por completo y permanecer detenidos hasta que las luces rojas se apaguen, el brazo de pare se retraiga y el autobús se ponga en marcha nuevamente","Detenerse solo si se ve a niños cruzando la vía","Cambiarse a la izquierda y continuar pasando el autobús"],"explanation":"Neb. Rev. Stat. 60-6,175 exige detenerse por completo cuando un autobús escolar está detenido con el brazo de señal de pare extendido y las luces rojas destellando, y el conductor debe permanecer detenido hasta que las luces rojas se apaguen, el brazo se retraiga y el autobús reanude su marcha. Fuente: Neb. Rev. Stat. 60-6,175."},"71":{"q":"La ley de Nebraska exige que los conductores hagan qué cosa cuando un autobús escolar activa por primera vez sus luces de advertencia AMARILLAS (ámbar), antes de que se enciendan las luces rojas?","options":["Detenerse de inmediato, incluso antes de que se activen las luces rojas","Reducir la velocidad a no más de 25 mph y prepararse para detenerse","Mantener la velocidad hasta que destellen las luces rojas","Reducir la velocidad a no más de 40 mph"],"explanation":"Neb. Rev. Stat. 60-6,175 exige que el conductor que se encuentra con un autobús escolar o lo rebasa cuando este destella sus luces de advertencia amarillas reduzca la velocidad a no más de 25 mph y esté preparado para detener el vehículo por completo. Fuente: Neb. Rev. Stat. 60-6,175."},"72":{"q":"Según la ley de Nebraska sobre detenerse ante autobuses escolares, ¿cuál situación en una carretera dividida NO exige que un conductor que se aproxima se detenga ante un autobús escolar con las luces rojas destellando?","options":["Tránsito que sigue directamente detrás del autobús en el mismo carril","Tránsito que se aproxima en sentido contrario en una carretera dividida","Tránsito en un carril adyacente en el mismo sentido en un camino de dos carriles sin división","Tránsito que se aproxima desde una calle lateral hacia la misma calzada"],"explanation":"Neb. Rev. Stat. 60-6,175 establece que el requisito de detenerse no aplica al tránsito que se aproxima en sentido contrario en una carretera dividida (p. ej., separada por un camellón); los conductores en una calzada distinta de una carretera dividida no necesitan detenerse. Los vehículos que siguen al autobús o se encuentran con él en un camino sin división aún deben detenerse. Fuente: Neb. Rev. Stat. 60-6,175."},"73":{"q":"Un conductor con CDL está detenido en el acotamiento de una carretera de dos carriles y doble sentido en Nebraska por una avería. ¿Dentro de cuántos minutos deben colocarse los dispositivos de advertencia de emergencia (triángulos reflectantes)?","options":["Dentro de 5 minutos","Dentro de 10 minutos","Dentro de 15 minutos","Dentro de 30 minutos"],"explanation":"El Manual CDL de Nebraska (conforme a 49 CFR 392.22) exige que los dispositivos de advertencia se coloquen dentro de los 10 minutos posteriores a detenerse. Fuente: Manual CDL de Nebraska / 49 CFR 392.22."},"74":{"q":"En un camino de dos carriles y doble sentido en Nebraska, ¿dónde debe colocar un conductor con CDL los tres triángulos de advertencia requeridos después de detenerse?","options":["Aproximadamente a 10 ft detrás, 100 ft detrás y 100 ft delante del vehículo","Los tres dentro de 10 ft del vehículo","A 50 ft, 150 ft y 250 ft detrás del vehículo","Aproximadamente a 25 ft, 75 ft y 200 ft solo hacia la parte trasera"],"explanation":"Según el Manual CDL de Nebraska (49 CFR 392.22), en un camino de dos carriles y doble sentido coloque un triángulo aproximadamente a 10 ft hacia la parte trasera (lado del tránsito), uno aproximadamente a 100 ft hacia la parte trasera y uno aproximadamente a 100 ft hacia la parte delantera del vehículo. Fuente: Manual CDL de Nebraska / 49 CFR 392.22."},"75":{"q":"En Nebraska, ¿cuál es el ancho máximo legal para un vehículo comercial antes de que se requiera un permiso de sobredimensión del NDOT?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"El ancho máximo legal general de un vehículo en Nebraska es de 8 feet 6 inches; cualquier ancho mayor requiere un permiso de sobredimensión del NDOT (aplica una excepción de luz diurna para equipo agrícola). Fuente: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska' / Neb. Rev. Stat. ch. 60."},"76":{"q":"¿Cuál es la altura máxima legal general de un vehículo en Nebraska antes de que se requiera un permiso?","options":["13 feet 6 inches","14 feet 0 inches","14 feet 6 inches","15 feet 0 inches"],"explanation":"La altura máxima legal general en Nebraska es de 14 feet 6 inches. Tenga en cuenta que los operadores de vehículos que excedan los 12 feet 6 inches asumen el riesgo por daños a obstáculos elevados. Fuente: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'."},"77":{"q":"Nebraska es particular por permitir un peso bruto legal mayor en las rutas de carreteras US y estatales que en las rutas interestatales. ¿Cuál es el límite de peso bruto legal en las rutas US y estatales de Nebraska (fuera de la interestatal)?","options":["80,000 lbs","85,500 lbs","94,000 lbs","105,500 lbs"],"explanation":"El peso bruto legal de Nebraska es de 80,000 lbs en las rutas designadas como interestatales, pero de 94,000 lbs en las rutas US y estatales (sujeto a límites de eje y de la fórmula de puente). Fuente: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'."},"78":{"q":"¿Cuál es el peso bruto máximo legal para un CMV en las rutas designadas como interestatales en Nebraska sin un permiso?","options":["73,280 lbs","80,000 lbs","88,000 lbs","94,000 lbs"],"explanation":"En las rutas designadas como interestatales, el peso bruto legal de Nebraska es de 80,000 lbs, en concordancia con el límite federal, sujeto a restricciones de eje simple (20,000 lbs), eje tándem (34,000 lbs) y de la fórmula de puente. Fuente: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'."},"79":{"q":"La regla de Nebraska sobre el carril izquierdo / mantenerse a la derecha (Neb. Rev. Stat. 60-6,131) exige que un CMV que circula más lento que el tránsito normal en una carretera de varios carriles haga qué cosa?","options":["Usar el carril izquierdo para que el tránsito más rápido pueda pasar por la derecha","Circular en el carril derecho disponible para el tránsito, usando el carril izquierdo solo para rebasar, girar a la izquierda o evitar un obstáculo","Circular en el carril central en todo momento","Igualar la velocidad del vehículo más rápido presente"],"explanation":"Neb. Rev. Stat. 60-6,131 exige que los vehículos, incluidos los CMV, que circulan más lento que el tránsito normal se mantengan en el carril derecho (o lo más cerca posible del borde derecho que sea practicable), reservando el carril izquierdo para rebasar, prepararse para un giro a la izquierda o evitar un obstáculo. Fuente: Neb. Rev. Stat. 60-6,131."},"80":{"q":"¿Qué agencia estatal emite las Licencias de Conducir Comerciales en Nebraska?","options":["El Departamento de Vehículos Motorizados de Nebraska (DMV), a través de Driver Licensing Services","La Patrulla Estatal de Nebraska","El Departamento de Transporte de Nebraska","La Administración Federal de Seguridad de Autotransportes (Federal Motor Carrier Safety Administration)"],"explanation":"En Nebraska, el Departamento de Vehículos Motorizados (DMV) emite las CDL a través de su Driver Licensing Services, y los solicitantes presentan la solicitud y realizan los exámenes en las Driver Licensing Offices. Fuente: Nebraska DMV, páginas de CDL (dmv.nebraska.gov/cdl)."},"81":{"q":"Antes de realizar el examen de habilidades de CDL en Nebraska, un solicitante primero debe obtener un Permiso de Aprendiz Comercial (CLP) y conservarlo durante al menos cuánto tiempo?","options":["14 days","7 days","30 days","60 days"],"explanation":"Nebraska exige que un conductor tenga un CLP válido y lo conserve durante un mínimo de 14 days antes de realizar el examen de habilidades de CDL. Esto refleja la regla federal del CLP. Fuente: Nebraska DMV, página de CDL Testing."},"82":{"q":"El examen de habilidades de CDL de Nebraska se divide en cuáles tres partes?","options":["Inspección previa al viaje, habilidades básicas de control y conducción en carretera","Examen de conocimientos escrito, evaluación de la visión e identificación de señales viales","Acoplamiento, retroceso y vaciado de frenos de aire (air-brake bleed-down)","Inspección previa al viaje, manejo de materiales peligrosos y conducción nocturna"],"explanation":"El examen de habilidades de CDL de Nebraska evalúa tres áreas: la inspección previa al viaje, las habilidades básicas de control y la conducción en carretera. Fuente: Nebraska DMV, página de CDL Testing."},"83":{"q":"¿Cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) en Nebraska?","options":["1 year","180 days","90 days","5 years"],"explanation":"Un CLP de Nebraska es válido por 1 year. Fuente: Nebraska DMV, página de Commercial Learner's Permit."},"84":{"q":"Según el sistema de autocertificación de Nebraska, ¿cuáles DOS categorías exigen que el conductor mantenga un Certificado de Examinador Médico (Medical Examiner's Certificate) válido?","options":["Categoría A (Interstate Non-Excepted) y Categoría C (Intrastate Non-Excepted)","Categoría B (Interstate Excepted) y Categoría D (Intrastate Excepted)","Categoría A (Interstate Non-Excepted) y Categoría B (Interstate Excepted)","Categoría C (Intrastate Non-Excepted) y Categoría D (Intrastate Excepted)"],"explanation":"Los conductores que se autocertifican como Categoría A (Interstate Non-Excepted) o Categoría C (Intrastate Non-Excepted) deben tener un certificado de examinador médico válido. Las categorías exceptuadas (B y D) no. Fuente: Nebraska DMV, CDL Documentation Requirements / tabla de autocertificación."},"85":{"q":"A partir del 19 de mayo de 2025, ¿cómo recibe el DMV de Nebraska la información del Certificado de Examinador Médico (MEC) de los titulares de CDL/CLP?","options":["Electrónicamente desde el FMCSA National Registry; los conductores ya no entregan copias en papel al DMV","Solo por correo certificado, con una copia en papel notariada de la tarjeta médica","En persona en una Driver Licensing Office, donde el personal escanea la tarjeta en papel","Por fax del empleador del conductor dentro de los 10 días posteriores al examen"],"explanation":"A partir del 19 de mayo de 2025, los titulares de CDL/CLP de Nebraska ya no entregan al DMV una copia en papel de su MEC; el DMV recibe la información electrónicamente del FMCSA National Registry. Fuente: comunicado de prensa del Nebraska DMV sobre la regla federal de certificación del examinador médico."},"86":{"q":"¿Cuál es el período de validez estándar de una Licencia de Conducir Comercial de Nebraska para un titular de 21 años o más?","options":["5 years (vence en el cumpleaños del titular en el quinto año después de la emisión)","4 years","8 years","2 years"],"explanation":"Las licencias de Nebraska emitidas a personas de 21 años o más, incluidas las CDL, vencen en el cumpleaños del titular en el quinto año después de la emisión (un ciclo de aproximadamente 5 years). Fuente: Nebraska DMV, página de Renewals."},"87":{"q":"¿Cuál es la edad mínima para tener una CDL de Nebraska para conducción comercial INTERESTATAL?","options":["21 years old","18 years old","19 years old","25 years old"],"explanation":"Nebraska exige que los conductores tengan al menos 21 años para operar en el comercio interestatal; los conductores con CDL solo intraestatal pueden calificar a los 18. Fuente: Nebraska DMV, página de CDL (requisitos de edad para Clase A/B/C)."},"88":{"q":"¿Cuál es la edad mínima para tener una CDL de Nebraska para conducción comercial únicamente INTRAESTATAL?","options":["18 years old","21 years old","16 years old","19 years old"],"explanation":"Nebraska permite una CDL Clase A, B o C a los 18 años para operación intraestatal; la operación interestatal requiere tener 21 años. Fuente: Nebraska DMV, página de CDL."},"89":{"q":"La Capacitación para Conductores de Nivel Inicial (ELDT) pasó a ser obligatoria en Nebraska para los nuevos solicitantes de CDL en qué fecha?","options":["7 de febrero de 2022","19 de mayo de 2025","1 de enero de 2020","1 de julio de 2021"],"explanation":"A partir del 7 de febrero de 2022, los nuevos solicitantes de CDL, quienes ascienden de clase y los solicitantes de hazmat por primera vez deben completar la ELDT antes de hacer el examen. Fuente: Nebraska DMV, página de CDL Testing."},"90":{"q":"¿Cómo confirma el DMV de Nebraska que un solicitante de CDL ha completado la Capacitación para Conductores de Nivel Inicial (ELDT) requerida?","options":["El DMV verifica el comprobante de ELDT electrónicamente","El solicitante envía por correo un certificado de capacitación en papel a la oficina central del DMV","El empleador del solicitante firma una declaración jurada en el sitio del examen","La escuela de capacitación envía por fax una lista a la Driver Licensing Office local"],"explanation":"Nebraska indica que el DMV verificará el comprobante de finalización de la ELDT electrónicamente (a través del FMCSA Training Provider Registry). Fuente: Nebraska DMV, página de CDL Testing."},"91":{"q":"¿Cuál evaluación debe aprobar TODO solicitante de CDL en Nebraska, ya sea que solicite una licencia nueva, como nuevo residente o al renovar?","options":["Un examen de la visión","Un examen de conocimientos de materiales peligrosos","Un examen de desempeño de frenos de aire","Una prueba de drogas y alcohol en el DMV"],"explanation":"Se requiere un examen de la visión para todos los solicitantes de CDL en Nebraska, incluyendo licencias nuevas, nuevos residentes y renovaciones. Fuente: Nebraska DMV, página de CDL Testing."},"92":{"q":"Si un solicitante de Nebraska no aprueba un examen de conocimientos escrito de CDL o un examen de habilidades, ¿con qué prontitud puede volver a presentar el examen por lo general?","options":["Después de un período de espera de al menos un día","De inmediato, el mismo día","Después de un período de espera de 14 días","Después de un período de espera de 30 días"],"explanation":"Nebraska exige una espera de al menos un día antes de volver a presentar el examen cuando se reprueba un examen escrito o de habilidades. Fuente: Nebraska DMV, página de CDL Testing."},"93":{"q":"¿Cuál examen de conocimientos de CDL NUNCA puede eximirse en Nebraska, ni siquiera para un nuevo residente que transfiere una CDL válida de otro estado?","options":["El examen de conocimientos de materiales peligrosos (hazmat)","El examen de conocimientos generales","El examen de conocimientos de frenos de aire","El examen de conocimientos de vehículos combinados"],"explanation":"Nebraska puede eximir ciertos exámenes escritos a nuevos residentes que califiquen o a renovaciones oportunas, pero el examen de conocimientos de hazmat no puede eximirse. Fuente: Nebraska DMV, página de CDL Testing."},"94":{"q":"¿Qué sucede con los segmentos del examen de habilidades ya aprobados por un titular de CLP en Nebraska si el CLP vence antes de que se completen los tres?","options":["Los segmentos previamente aprobados quedan inválidos y deben volver a presentarse","Siguen siendo válidos durante 90 días más como período de gracia","Se transfieren automáticamente al CLP renovado","Solo debe volver a presentarse el segmento de conducción en carretera"],"explanation":"En Nebraska, si un CLP vence antes de completar los tres segmentos del examen de habilidades, cualquier examen previamente aprobado queda inválido y debe volver a presentarse. Fuente: Nebraska DMV, página de Commercial Learner's Permit."},"95":{"q":"¿Dónde se administran los exámenes de habilidades de CDL de Nebraska, además de por los examinadores del DMV?","options":["Por evaluadores externos (third-party testers) autorizados por el DMV","Solo por inspectores federales de FMCSA","Solo por el instructor de la escuela de capacitación de CDL del solicitante","Por cualquier titular de licencia CDL designado por el empleador"],"explanation":"Nebraska permite que evaluadores externos (third-party testers) autorizados por el DMV administren los exámenes de habilidades de CDL; deben avisar al DMV con dos días hábiles de anticipación. Fuente: Nebraska DMV, página de CDL Testing y lista de Third-Party Testers."},"96":{"q":"Al solicitar una CDL o CLP de Nebraska, ¿cuál es la regla sobre divulgar un número de Seguro Social?","options":["Los solicitantes deben divulgar un número de Seguro Social válido; no hay exención para conductores de CDL","La divulgación es opcional y puede sustituirse por un número de pasaporte","Solo los conductores interestatales deben divulgarlo","Solo se requiere al agregar un endoso de hazmat"],"explanation":"Nebraska exige que los solicitantes de CDL/CLP divulguen un número de Seguro Social válido, sin exenciones para conductores comerciales. Fuente: Nebraska DMV, CDL Documentation Requirements."},"97":{"q":"Para comprobar un domicilio principal en Nebraska para una solicitud de CDL, ¿qué debe proporcionar el solicitante?","options":["Dos documentos de fuentes diferentes que muestren el domicilio en Nebraska; un apartado postal (P.O. Box) no es aceptable","Una factura de servicios públicos, con un apartado postal (P.O. Box) permitido","Una sola declaración jurada de residencia","Únicamente una tarjeta de registro de votante de Nebraska"],"explanation":"Nebraska exige dos documentos comprobantes de domicilio de fuentes diferentes (generalmente emitidos dentro de los 90 días); un apartado postal (P.O. Box) no es aceptable. Fuente: Nebraska DMV, CDL Documentation Requirements."},"98":{"q":"Un titular de CDL de Nebraska que se autocertifica como Categoría A o C corre qué riesgo si no mantiene un Certificado de Examinador Médico vigente en el National Registry?","options":["La degradación (downgrade) de sus privilegios comerciales de CDL/CLP","Una suspensión automática de la licencia por un año","Volver a presentar obligatoriamente el examen de habilidades en carretera","La conversión de la CDL en una licencia solo de hazmat"],"explanation":"Los conductores no exceptuados (Categoría A/C) deben mantener un MEC vigente, que ahora se transmite electrónicamente desde el National Registry; no hacerlo resulta en una degradación (downgrade) de la CDL/CLP. Fuente: comunicado de prensa del Nebraska DMV sobre la regla de certificación del examinador médico."},"99":{"q":"¿Cómo se programa por lo general una cita para el examen de habilidades de CDL en Nebraska, y quién debe llamar?","options":["Solo con cita, y la persona que realmente realizará el examen debe hacer la llamada","Solo sin cita, no se acepta agendar","El director de seguridad del empleador en nombre del conductor","Solo en línea, sin opción telefónica disponible"],"explanation":"Nebraska administra los exámenes de habilidades de CDL solo con cita, y el solicitante que realizará el examen debe ser quien llame para agendar. Fuente: Nebraska DMV, página de CDL Testing."}},"hi":{"0":{"q":"नेब्रास्का के राजमार्गों पर, विशेष परमिट के बिना किसी वाणिज्यिक वाहन के लिए अधिकतम कुल चौड़ाई कितनी अनुमत है?","options":["8 फीट 6 इंच","8 फीट","9 फीट","10 फीट"],"explanation":"नेब्रास्का अधिकतम कुल वाहन चौड़ाई को 8 फीट 6 इंच (102 inches) तक सीमित करता है। स्रोत: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' आइटम 1; Neb. Rev. Stat. 60-6,288 के अनुरूप।"},"1":{"q":"परमिट के बिना नेब्रास्का के राजमार्गों पर अनुमत अधिकतम कुल वाहन ऊँचाई कितनी है?","options":["14 फीट 6 इंच","13 फीट 6 इंच","14 फीट","15 फीट"],"explanation":"नेब्रास्का की अधिकतम कुल वाहन ऊँचाई 14 फीट 6 इंच है। स्रोत: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' आइटम 2।"},"2":{"q":"नेब्रास्का में, एकल वाहन (संयोजन नहीं) के लिए अधिकतम कुल लंबाई कितनी है?","options":["40 फीट","45 फीट","53 फीट","35 फीट"],"explanation":"नेब्रास्का में एकल वाहन कुल मिलाकर 40 फीट से अधिक लंबा नहीं हो सकता। स्रोत: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' आइटम 3।"},"3":{"q":"नेब्रास्का में सेमीट्रेलर (ट्रक-ट्रैक्टर को छोड़कर) की अधिकतम कानूनी लंबाई कितनी है?","options":["53 फीट","48 फीट","40 फीट","57 फीट"],"explanation":"नेब्रास्का एक सेमीट्रेलर (ट्रक-ट्रैक्टर को छोड़कर) को 53 फीट तक की अनुमति देता है। स्रोत: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' आइटम 5।"},"4":{"q":"नेब्रास्का में वाहनों के संयोजन के लिए अधिकतम कुल लंबाई कितनी है?","options":["65 फीट","60 फीट","75 फीट","53 फीट"],"explanation":"नेब्रास्का वाहनों के संयोजन के लिए अधिकतम कुल लंबाई 65 फीट निर्धारित करता है। स्रोत: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska,' आइटम 4।"},"5":{"q":"नेब्रास्का राजमार्ग पर अनुमत अधिकतम एकल पहिया भार कितना है?","options":["10,000 pounds","12,000 pounds","8,000 pounds","20,000 pounds"],"explanation":"किसी भी नेब्रास्का राजमार्ग पर कोई भी पहिया 10,000 pounds से अधिक का सकल भार नहीं उठा सकता। स्रोत: NDOT 'Legal Sizes and Weights,' आइटम 7; Neb. Rev. Stat. 60-6,294।"},"6":{"q":"नेब्रास्का के राजमार्गों पर अनुमत अधिकतम एकल एक्सल भार कितना है?","options":["20,000 pounds","18,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"नेब्रास्का एकल एक्सल को 20,000 pounds तक सीमित करता है। स्रोत: NDOT 'Legal Sizes and Weights,' आइटम 8; Neb. Rev. Stat. 60-6,294।"},"7":{"q":"नेब्रास्का के राजमार्गों पर अनुमत अधिकतम टैंडम एक्सल भार कितना है?","options":["34,000 pounds","36,000 pounds","40,000 pounds","32,000 pounds"],"explanation":"नेब्रास्का में टैंडम एक्सल समूह के माध्यम से संप्रेषित सकल भार 34,000 pounds से अधिक नहीं हो सकता। स्रोत: NDOT 'Legal Sizes and Weights,' आइटम 9; Neb. Rev. Stat. 60-6,294।"},"8":{"q":"नेब्रास्का में परमिट के बिना Interstate-निर्दिष्ट मार्गों पर संचालित होने वाले वाहन के लिए अधिकतम सकल भार कितना है?","options":["80,000 pounds","94,000 pounds","84,000 pounds","76,000 pounds"],"explanation":"नेब्रास्का में Interstate-निर्दिष्ट मार्गों पर कानूनी सकल भार 80,000 pounds है। स्रोत: NDOT 'Legal Sizes and Weights,' Weight exceptions नोट; Neb. Rev. Stat. 60-6,294।"},"9":{"q":"नेब्रास्का में U.S. और State मार्गों (गैर-Interstate) पर, कानूनी सकल भार सीमा क्या है?","options":["94,000 pounds","80,000 pounds","90,000 pounds","100,000 pounds"],"explanation":"नेब्रास्का U.S. और State मार्गों पर 94,000 pounds का कानूनी सकल भार अनुमत करता है (एक्सल और bridge-formula सीमाओं के अधीन), जबकि Interstate पर 80,000 pounds है। स्रोत: NDOT 'Legal Sizes and Weights,' Weight exceptions नोट।"},"10":{"q":"नेब्रास्का भार-सीमा उद्देश्यों के लिए 'टैंडम एक्सल' को कैसे परिभाषित करता है?","options":["दो लगातार एक्सल जो 40 से अधिक और 96 inches से अधिक दूरी पर न हों","दो एक्सल जो 40 inches से कम दूरी पर हों","एक-दूसरे के 120 inches के भीतर कोई भी दो एक्सल","ठीक 60 inches की दूरी पर दो एक्सल"],"explanation":"नेब्रास्का टैंडम एक्सल को किन्हीं दो लगातार एक्सल के रूप में परिभाषित करता है जिनके केंद्र 40 inches से अधिक और 96 inches से अधिक दूरी पर न हों। स्रोत: Neb. Rev. Stat. 60-6,294।"},"11":{"q":"नेब्रास्का की एक्सल-समूह भार तालिका (federal bridge formula) के तहत, 8 फीट की दूरी पर दो एक्सल के लिए अधिकतम भार कितना है?","options":["34,000 pounds","38,000 pounds","40,000 pounds","36,000 pounds"],"explanation":"नेब्रास्का की 'Maximum Load on Any Group of Two or More Axles' तालिका 8 फीट की दूरी पर दो एक्सल के लिए 34,000 pounds दर्शाती है। स्रोत: NDOT 'Legal Sizes and Weights' एक्सल-समूह तालिका; Neb. Rev. Stat. 60-6,294।"},"12":{"q":"नेब्रास्का की एक्सल-समूह भार तालिका के अनुसार, 51 फीट की दूरी पर (छोरों के बीच) पाँच एक्सल पर अधिकतम भार कितना है?","options":["80,000 pounds","76,000 pounds","84,000 pounds","78,000 pounds"],"explanation":"नेब्रास्का की bridge-formula तालिका छोरों के बीच 51 फीट की दूरी पर पाँच एक्सल के लिए 80,000 pounds सूचीबद्ध करती है। स्रोत: NDOT 'Legal Sizes and Weights' एक्सल-समूह तालिका; Neb. Rev. Stat. 60-6,294।"},"13":{"q":"नेब्रास्का के राजमार्गों पर दो या अधिक एक्सल का समूह अधिकतम कितना भार उठा सकता है, इसे क्या नियंत्रित करता है?","options":["समूह के छोर के एक्सल के बीच की दूरी, bridge-formula तालिका के अनुसार","केवल वाहन पर टायरों की संख्या","इंजन की हॉर्सपावर","केवल ट्रेलर की चौड़ाई"],"explanation":"नेब्रास्का किसी भी एक्सल समूह पर भार को समूह के छोर के एक्सल के बीच की दूरी के आधार पर सीमित करता है, जिसमें federal bridge-formula तालिका लागू होती है। स्रोत: NDOT 'Legal Sizes and Weights'; Neb. Rev. Stat. 60-6,294।"},"14":{"q":"नेब्रास्का राज्य राजमार्गों पर यात्रा के लिए ओवरसाइज/ओवरवेट परमिट कौन-सी एजेंसी जारी करती है?","options":["Nebraska Department of Transportation (NDOT)","Nebraska Department of Motor Vehicles","Nebraska State Patrol","काउंटी शेरिफ का कार्यालय"],"explanation":"Nebraska Department of Transportation (NDOT) राज्य राजमार्गों के लिए ओवरसाइज/ओवरवेट परमिट जारी करता है; DMV आवेदकों को NDOT की ओर निर्देशित करता है। स्रोत: Nebraska DMV FAQ; NDOT Permits / Automated Truck Permit System।"},"15":{"q":"कोई वाहक नेब्रास्का के DOT से ओवरसाइज/ओवरवेट परमिट सबसे आम तौर पर कैसे प्राप्त कर सकता है?","options":["NDOT के ऑनलाइन Automated Truck Permit System के माध्यम से","DMV को कागज़ी फॉर्म डाक से भेजकर","स्थानीय पुलिस विभाग को कॉल करके","परमिट पहले से प्राप्त नहीं किए जा सकते"],"explanation":"नेब्रास्का ओवरसाइज/ओवरवेट परमिट NDOT के ऑनलाइन Automated Truck Permit System (dottruckpermits.nebraska.gov) के माध्यम से प्राप्त किए जाते हैं। स्रोत: NDOT Permits; Nebraska DMV FAQ।"},"16":{"q":"नेब्रास्का के राजमार्गों पर संचालन के लिए ओवरसाइज या ओवरवेट परमिट की आवश्यकता कब होती है?","options":["जब वाहन या भार कानूनी अधिकतम आकार या भार सीमा से अधिक हो","केवल जब किसी अन्य राज्य में प्रवेश किया जाए","केवल बजरी वाली सड़कों पर","केवल खतरनाक सामग्री ले जाने वाले वाहनों के लिए"],"explanation":"किसी ऐसे वाहन या भार को ले जाने के लिए एक विशेष NDOT परमिट की आवश्यकता होती है जो कानूनी अधिकतम आकार या भार से अधिक हो; ऐसे भार के लिए कोई परमिट जारी नहीं किया जाता जिसे बहुत अधिक कठिनाई के बिना कम या अलग किया जा सके। स्रोत: NDOT 'Legal Sizes and Weights' (Excess Size or Weight); Neb. Rev. Stat. 60-6,294।"},"17":{"q":"नेब्रास्का में, किस ऊँचाई से ऊपर ऑपरेटर ऊपरी अवरोधों से टकराने के लिए हानि का जोखिम और दायित्व ग्रहण करता है?","options":["12 फीट 6 इंच से अधिक","13 फीट 6 इंच से अधिक","14 फीट 6 इंच से अधिक","11 फीट से अधिक"],"explanation":"नेब्रास्का कानून प्रावधान करता है कि 12 फीट 6 इंच से अधिक ऊँचाई वाले वाहन के मालिक/ऑपरेटर जोखिम ग्रहण करते हैं और ऊपरी अवरोधों को हुए नुकसान के लिए उत्तरदायी होते हैं। स्रोत: NDOT 'Legal Sizes and Weights,' Height exception।"},"18":{"q":"नेब्रास्का 8-फीट-6-इंच चौड़ाई सीमा से कौन-सी विशेष छूट प्रदान करता है?","options":["खेती के सामान्य कार्य के दौरान दिन के उजाले में ले जाए जाने वाले कृषि उपकरण","स्टील ढोने वाला कोई भी फ्लैटबेड ट्रेलर","सभी रेफ्रिजरेटेड ट्रेलर","राज्य से बाहर पंजीकृत वाहन"],"explanation":"नेब्रास्का की 8'6\" चौड़ाई सीमा खेती के सामान्य कार्य के दौरान दिन के उजाले में अस्थायी रूप से ले जाए जाने वाले कृषि उपकरणों पर लागू नहीं होती। स्रोत: NDOT 'Legal Sizes and Weights,' Width exception।"},"19":{"q":"नेब्रास्का के वैधानिक भार नियमों के तहत, यदि कोई ट्रक किसी पुल की पोस्ट की गई क्षमता से अधिक सकल भार के साथ पुल पार करता है और नुकसान पहुँचाता है, तो क्या होता है?","options":["वाहन का मालिक सभी नुकसान के लिए जिम्मेदार है","दायित्व NDOT के साथ समान रूप से साझा किया जाता है","यदि परमिट खरीदा गया था तो कोई दायित्व नहीं है","केवल चालक उत्तरदायी है, मालिक नहीं"],"explanation":"नेब्रास्का कानून ट्रक के मालिक को किसी पुल को उसकी पोस्ट की गई क्षमता से अधिक भार के साथ पार करने से होने वाले सभी नुकसान के लिए जिम्मेदार ठहराता है। स्रोत: NDOT 'Legal Sizes and Weights' (bridge provision); Neb. Rev. Stat. 60-6,294।"},"20":{"q":"नेब्रास्का में, 26,001 pounds या अधिक के Gross Combination Weight Rating (GCWR) वाले वाहनों के संयोजन को संचालित करने के लिए कौन-सा CDL वर्ग आवश्यक है, बशर्ते खींची जा रही इकाई(यों) का GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"नेब्रास्का Class A CDL को वाहनों के संयोजन के रूप में परिभाषित करता है जिसका GCWR 26,001 या अधिक pounds हो, जहाँ खींची गई इकाई(यों) का GVWR 10,000 pounds से अधिक हो। स्रोत: Nebraska DMV, CDL Classes, Endorsements and Restrictions।"},"21":{"q":"नेब्रास्का नियमों के तहत, कौन-सा CDL वर्ग 26,001 pounds या अधिक GVWR वाले एकल वाहन (या ऐसे वाहन को कवर करता है जो 10,000 pounds से अधिक न होने वाली इकाई खींच रहा हो)?","options":["Class A","Class B","Class C","Class M"],"explanation":"नेब्रास्का Class B CDL को 26,001 या अधिक pounds GVWR वाले एकल वाहन के रूप में, या ऐसे किसी वाहन के रूप में परिभाषित करता है जो 10,000 pounds से अधिक न होने वाली इकाई खींच रहा हो। स्रोत: Nebraska DMV, CDL Classes, Endorsements and Restrictions।"},"22":{"q":"एक नेब्रास्का चालक 26,001 pounds GVWR से कम के एकल वाहन को संचालित करता है जिसे खतरनाक सामग्री के लिए प्लेकार्ड लगाना आवश्यक है। कौन-सा CDL वर्ग लागू होता है?","options":["Class A","Class B","Class C","Class O"],"explanation":"नेब्रास्का का Class C CDL 26,001 pounds GVWR से कम के एकल वाहन (या 10,000 pounds तक की इकाई खींचने वाले) को कवर करता है जिसे खतरनाक सामग्री के लिए प्लेकार्ड लगाना आवश्यक हो या जो चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन की गई बस हो। स्रोत: Nebraska DMV, CDL Classes, Endorsements and Restrictions।"},"23":{"q":"नेब्रास्का की Class C परिभाषा के अनुसार, बस को CDL की आवश्यकता तब होती है जब उसे कितने यात्रियों को ले जाने के लिए डिज़ाइन किया गया हो?","options":["चालक सहित 8 या अधिक","चालक सहित 11 या अधिक","चालक सहित 16 या अधिक","चालक सहित 24 या अधिक"],"explanation":"नेब्रास्का की Class C परिभाषा में कोई भी ऐसी बस शामिल है जिसे चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया हो। स्रोत: Nebraska DMV, CDL Classes, Endorsements and Restrictions।"},"24":{"q":"इंट्रास्टेट (केवल नेब्रास्का के भीतर) संचालन के लिए नेब्रास्का वाणिज्यिक चालक लाइसेंस जारी किए जाने हेतु न्यूनतम आयु क्या है?","options":["16 वर्ष","17 वर्ष","18 वर्ष","21 वर्ष"],"explanation":"नेब्रास्का किसी ऐसे व्यक्ति को CDL या CLP जारी नहीं करता जिसने 18 वर्ष की आयु प्राप्त नहीं की है; इंट्रास्टेट CDL संचालन के लिए न्यूनतम आयु 18 है। स्रोत: Neb. Rev. Stat. 60-4,143; Nebraska DMV CDL पृष्ठ।"},"25":{"q":"एक नेब्रास्का CDL धारक राज्य की सीमाओं के पार (इंटरस्टेट) वाणिज्यिक वाहन चलाना चाहता है। ऐसा करने के लिए न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","20 वर्ष","21 वर्ष"],"explanation":"हालाँकि नेब्रास्का 18 वर्ष की आयु पर इंट्रास्टेट CDL जारी करता है, चालक को इंटरस्टेट वाणिज्य में वाणिज्यिक मोटर वाहन संचालित करने के लिए कम से कम 21 वर्ष का होना चाहिए। स्रोत: Nebraska DMV CDL पृष्ठ; 49 CFR 391.11 नेब्रास्का नियम के रूप में लागू।"},"26":{"q":"प्लेकार्ड की आवश्यकता वाली मात्रा में खतरनाक सामग्री ले जाने के लिए एक नेब्रास्का चालक को कौन-सा एंडोर्समेंट चाहिए?","options":["N एंडोर्समेंट","H एंडोर्समेंट","T एंडोर्समेंट","X एंडोर्समेंट"],"explanation":"प्लेकार्ड वाली खतरनाक सामग्री ढोने के लिए H (Hazardous Materials) एंडोर्समेंट आवश्यक है; इसके लिए एक नॉलेज टेस्ट और एक TSA सुरक्षा खतरा आकलन की आवश्यकता होती है। स्रोत: Nebraska DMV, CDL Classes, Endorsements and Restrictions।"},"27":{"q":"नेब्रास्का द्वारा HazMat (H) एंडोर्समेंट के साथ CDL जारी करने से पहले, आवेदक को कौन-सा अतिरिक्त संघीय पृष्ठभूमि चरण पूरा करना होगा?","options":["फिंगरप्रिंटिंग के साथ एक TSA सुरक्षा खतरा आकलन","एक FBI नागरिक अधिकार साक्षात्कार","एक DEA नियंत्रित-पदार्थ पंजीकरण","एक USCIS नागरिकता समीक्षा"],"explanation":"HazMat नॉलेज टेस्ट पास करने के अलावा, नेब्रास्का H एंडोर्समेंट जारी होने से पहले आवेदकों से Transportation Security Administration (TSA) सुरक्षा खतरा आकलन पूरा करने की आवश्यकता रखता है, जिसमें प्री-एनरोलमेंट और फिंगरप्रिंटिंग शामिल है। स्रोत: Nebraska DMV, CDL Classes, Endorsements and Restrictions; TSA HME कार्यक्रम।"},"28":{"q":"एक नेब्रास्का चालक को HazMat (H) एंडोर्समेंट को कितनी बार नवीनीकृत करना होगा, जिसमें TSA खतरा आकलन के लिए नए फिंगरप्रिंट जमा करना शामिल है?","options":["कम से कम हर 2 साल","कम से कम हर 3 साल","कम से कम हर 5 साल","कम से कम हर 8 साल"],"explanation":"HazMat एंडोर्समेंट और इसके TSA सुरक्षा खतरा आकलन को कम से कम हर पाँच साल में नवीनीकृत करना होगा, जिसमें नवीनीकरण पर नए फिंगरप्रिंट जमा किए जाते हैं। स्रोत: Nebraska DMV CDL पृष्ठ; TSA HME कार्यक्रम (49 CFR 1572)।"},"29":{"q":"नेब्रास्का में थोक में तरल पदार्थ या गैसों को ढोने के लिए उपयोग किए जाने वाले टैंक वाहन को चलाने के लिए कौन-सा एंडोर्समेंट आवश्यक है?","options":["T एंडोर्समेंट","N एंडोर्समेंट","H एंडोर्समेंट","P एंडोर्समेंट"],"explanation":"टैंक वाहन को संचालित करने के लिए N (Tank Vehicle) एंडोर्समेंट आवश्यक है और इसके लिए एक नॉलेज टेस्ट पास करना आवश्यक है। स्रोत: Nebraska DMV, CDL Classes, Endorsements and Restrictions।"},"30":{"q":"एक नेब्रास्का चालक डबल या ट्रिपल ट्रेलर खींचना चाहता है। कौन-सा एंडोर्समेंट आवश्यक है?","options":["N एंडोर्समेंट","P एंडोर्समेंट","T एंडोर्समेंट","S एंडोर्समेंट"],"explanation":"डबल और ट्रिपल ट्रेलर खींचने के लिए T (Doubles/Triples) एंडोर्समेंट आवश्यक है और इसके लिए एक नॉलेज टेस्ट पास करना आवश्यक है। स्रोत: Nebraska DMV, CDL Classes, Endorsements and Restrictions।"},"31":{"q":"एक नेब्रास्का CDL धारक को 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाहन, जैसे यात्री बस, चलाने के लिए कौन-सा एंडोर्समेंट होना चाहिए?","options":["S एंडोर्समेंट","P एंडोर्समेंट","N एंडोर्समेंट","H एंडोर्समेंट"],"explanation":"16 या अधिक लोगों (चालक सहित) को ले जाने के लिए डिज़ाइन किए गए वाहनों के लिए P (Passenger) एंडोर्समेंट आवश्यक है और इसके लिए एक नॉलेज टेस्ट के साथ-साथ एक प्रतिनिधि वाहन में एक स्किल्स टेस्ट की आवश्यकता होती है। स्रोत: Nebraska DMV, CDL Classes, Endorsements and Restrictions।"},"32":{"q":"नेब्रास्का में, S (School Bus) एंडोर्समेंट केवल किस अन्य एंडोर्समेंट के साथ जारी किया जा सकता है?","options":["H (HazMat) एंडोर्समेंट","N (Tank) एंडोर्समेंट","P (Passenger) एंडोर्समेंट","T (Doubles/Triples) एंडोर्समेंट"],"explanation":"नेब्रास्का को S (School Bus) एंडोर्समेंट के साथ P (Passenger) एंडोर्समेंट का होना आवश्यक है; कोई चालक P के बिना S नहीं रख सकता। स्रोत: Nebraska DMV, CDL Classes, Endorsements and Restrictions।"},"33":{"q":"CDL स्किल्स टेस्ट देने से पहले एक नेब्रास्का चालक को Commercial Learner's Permit (CLP) रखने की न्यूनतम अवधि क्या है?","options":["7 दिन","10 दिन","14 दिन","30 दिन"],"explanation":"नेब्रास्का, संघीय नियम का पालन करते हुए, CDL स्किल्स टेस्ट देने से पहले चालक को कम से कम 14 दिनों के लिए वैध CLP रखने की आवश्यकता रखता है। स्रोत: Nebraska DMV, Commercial Learner's Permit; 49 CFR 383.25।"},"34":{"q":"एक नेब्रास्का Commercial Learner's Permit (CLP) कितने समय तक वैध रहता है?","options":["180 दिन","1 साल","2 साल","5 साल"],"explanation":"एक नेब्रास्का CLP 1 साल के लिए वैध होता है। यदि यह सभी तीन स्किल्स-टेस्ट खंडों के पास होने से पहले समाप्त हो जाता है, तो पहले पास किए गए खंड अमान्य हो जाते हैं और सभी स्किल्स परीक्षण फिर से देने होते हैं। स्रोत: Nebraska DMV, Commercial Learner's Permit।"},"35":{"q":"नेब्रास्का किन CDL वर्गों में Commercial Learner's Permit (CLP) जारी करता है?","options":["केवल Class A और Class B","केवल Class C","Class A, B, और C","केवल Class B और Class C"],"explanation":"नेब्रास्का केवल Class A और Class B में CLP जारी करता है। स्रोत: Nebraska DMV, Commercial Learner's Permit।"},"36":{"q":"एक नेब्रास्का Commercial Learner's Permit (CLP) कौन-से एंडोर्समेंट के सेट को रख सकता है?","options":["H, T, और X","P, S, और N","केवल H और N","केवल T और X"],"explanation":"एक नेब्रास्का CLP केवल P (Passenger), S (School Bus), और N (Tank, खाली/बिना कार्गो तक सीमित) एंडोर्समेंट रख सकता है; H, T, और X की CLP पर अनुमति नहीं है। स्रोत: Nebraska DMV, Commercial Learner's Permit; 49 CFR 383.25।"},"37":{"q":"निवास स्थापित करने के लिए एक CDL/CLP आवेदक को नेब्रास्का के मुख्य पते को साबित करने वाले कितने दस्तावेज़ प्रदान करने होंगे?","options":["एक दस्तावेज़","विभिन्न स्रोतों से दो दस्तावेज़","तीन दस्तावेज़","किसी निवास प्रमाण की आवश्यकता नहीं है"],"explanation":"नेब्रास्का आवेदक के नेब्रास्का मुख्य पते को दर्शाने वाले विभिन्न स्रोतों से दो दस्तावेज़ों की आवश्यकता रखता है; एक P.O. Box स्वीकार नहीं किया जाता। आवेदक को पहचान का प्रमाण, एक Social Security number, और U.S. नागरिकता या वैध स्थिति का प्रमाण भी प्रदान करना होगा। स्रोत: Nebraska DMV, CDL Documentation Requirements।"},"38":{"q":"नेब्रास्का की संघीय Entry-Level Driver Training (ELDT) आवश्यकता के तहत, चालक का प्रशिक्षण कहाँ पूरा और दर्ज किया जाना चाहिए?","options":["FMCSA Training Provider Registry पर सूचीबद्ध प्रदाता के साथ","चालक की पसंद के किसी भी निजी ड्राइविंग स्कूल में","केवल नौकरी पर अप्रेंटिसशिप के माध्यम से","एक Nebraska DMV परीक्षण केंद्र पर"],"explanation":"ELDT, जो 7 फरवरी 2022 से प्रभावी है, पहली बार के Class A/B आवेदकों, B-से-A अपग्रेड, और पहली बार के P, S, या H एंडोर्समेंट आवेदकों से FMCSA Training Provider Registry पर सूचीबद्ध प्रदाता के साथ प्रशिक्षण पूरा करने की आवश्यकता रखता है, जो पूर्णता को दर्ज करता है। स्रोत: Nebraska DMV, Entry Level Driver Training (ELDT); 49 CFR Part 380।"},"39":{"q":"कौन-सी नेब्रास्का CDL चिकित्सा स्व-प्रमाणन श्रेणी ऐसे चालक पर लागू होती है जो इंटरस्टेट वाणिज्य में संचालन करता है और संघीय चिकित्सा (DOT physical) आवश्यकताओं के अधीन है?","options":["Interstate Non-Excepted (Category A)","Interstate Excepted (Category B)","Intrastate Non-Excepted (Category C)","Intrastate Excepted (Category D)"],"explanation":"Category A, Interstate Non-Excepted, संघीय चिकित्सा और दृष्टि आवश्यकताओं के अधीन चालकों पर लागू होती है; उन्हें National Registry पर मौजूद प्रदाता से एक वर्तमान चिकित्सा परीक्षक प्रमाणपत्र प्रदान करना होगा और DMV के पास फाइल पर रखना होगा। स्रोत: Nebraska DMV, CDL Self-Certification Categories; Neb. Rev. Stat. 60-4,144.01।"},"40":{"q":"नेब्रास्का में वाणिज्यिक मोटर वाहन (CMV) चलाते समय, किस रक्त अल्कोहल सांद्रता (BAC) पर एक चालक को नशे में गाड़ी चलाने वाला और एक प्रमुख अयोग्यता अपराध करने वाला माना जाता है?","options":["0.02 या अधिक","0.04 या अधिक","0.08 या अधिक","0.10 या अधिक"],"explanation":"नेब्रास्का, 49 CFR 383.51 और Nebraska CDL Manual का पालन करते हुए, 0.04 या अधिक BAC के साथ CMV चलाने को एक प्रमुख अयोग्यता अपराध बनाता है। 0.08 की सीमा गैर-वाणिज्यिक वाहनों पर लागू होती है। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; Nebraska CDL Manual।"},"41":{"q":"नेब्रास्का के निहित सहमति कानून के तहत, मोटर वाहन चलाने के बाद किसी रासायनिक (श्वास, रक्त, या मूत्र) परीक्षण से इनकार करने वाले CDL धारक का क्या परिणाम होता है?","options":["केवल एक चेतावनी पत्र, बिना किसी अयोग्यता के","इसे एक प्रमुख अपराध माना जाता है, जो DUI दोषसिद्धि की तरह ही CDL को अयोग्य कर देता है","एक 30-दिन का निलंबन जो CDL को प्रभावित नहीं करता","बिना किसी लाइसेंस कार्रवाई के $100 का प्रशासनिक जुर्माना"],"explanation":"नेब्रास्का का निहित सहमति कानून अल्कोहल/ड्रग परीक्षण से इनकार को एक प्रमुख अयोग्यता अपराध मानता है, जो DUI के समान ही CDL अयोग्यता वहन करता है (पहले अपराध पर 1 साल, दूसरे पर आजीवन)। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"42":{"q":"नेब्रास्का में, प्लेकार्ड वाली खतरनाक सामग्री न ले जाते समय किसी पहले प्रमुख अपराध (जैसे DUI या परीक्षण से इनकार) के लिए एक CDL धारक कितने समय तक अयोग्य रहता है?","options":["60 दिन","6 महीने","1 साल","3 साल"],"explanation":"एक पहला प्रमुख अपराध एक नेब्रास्का CDL धारक को 1 साल के लिए अयोग्य ठहराता है। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"43":{"q":"यदि कोई नेब्रास्का चालक ऐसे CMV को चलाते समय पहला प्रमुख अपराध करता है जिसे खतरनाक सामग्री के लिए प्लेकार्ड लगाना आवश्यक है, तो अयोग्यता कितने समय की होती है?","options":["1 साल","2 साल","3 साल","आजीवन"],"explanation":"प्लेकार्ड वाली खतरनाक सामग्री ले जाते समय पहला प्रमुख अपराध अयोग्यता को 1 साल से बढ़ाकर 3 साल कर देता है। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"44":{"q":"किसी दूसरे प्रमुख अपराध के लिए दोषी ठहराए जाने वाले नेब्रास्का CDL धारक के लिए अयोग्यता अवधि क्या है?","options":["3 साल","5 साल","10 साल","आजीवन"],"explanation":"नेब्रास्का में दूसरे प्रमुख अपराध के परिणामस्वरूप आजीवन CDL अयोग्यता होती है। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"45":{"q":"निम्नलिखित में से किसे एक नेब्रास्का CDL धारक के लिए एक गंभीर यातायात उल्लंघन के बजाय एक प्रमुख अयोग्यता अपराध के रूप में वर्गीकृत किया गया है?","options":["किसी अन्य वाहन का बहुत पास से अनुसरण करना","दुर्घटना के स्थल को छोड़ना","अनुचित या अनियमित लेन परिवर्तन","सीमा से 15 mph या अधिक की गति से चलना"],"explanation":"दुर्घटना के स्थल को छोड़ना एक प्रमुख अपराध है (1-साल/आजीवन अयोग्यता)। बहुत पास से अनुसरण करना, अनियमित लेन परिवर्तन, और अत्यधिक गति गंभीर यातायात उल्लंघन हैं (60/120 दिन)। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"46":{"q":"किसी नेब्रास्का CDL धारक को 'अत्यधिक गति' गंभीर यातायात उल्लंघन के रूप में गिने जाने के लिए पोस्ट की गई गति सीमा से कितनी अधिक तेज़ चलाना चाहिए?","options":["10 mph या अधिक","15 mph या अधिक","20 mph या अधिक","25 mph या अधिक"],"explanation":"पोस्ट की गई सीमा से 15 mph या अधिक की गति से चलना नेब्रास्का में 'अत्यधिक गति' गंभीर यातायात उल्लंघन है। स्रोत: Nebraska CDL Manual; Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"47":{"q":"नेब्रास्का में, 3-वर्ष की अवधि के भीतर अलग-अलग घटनाओं में दो गंभीर यातायात उल्लंघनों के लिए दोषी ठहराए जाने पर एक CDL धारक कितने समय तक अयोग्य रहता है?","options":["30 दिन","60 दिन","120 दिन","1 साल"],"explanation":"3 साल के भीतर दो गंभीर यातायात उल्लंघनों के परिणामस्वरूप 60-दिन की CDL अयोग्यता होती है। स्रोत: Nebraska DMV CDL Disqualification / MCSIA पृष्ठ; 49 CFR 383.51।"},"48":{"q":"3-वर्ष की अवधि के भीतर अलग-अलग घटनाओं में तीन गंभीर यातायात उल्लंघन करने के लिए एक नेब्रास्का CDL धारक कितने समय तक अयोग्य रहता है?","options":["60 दिन","90 दिन","120 दिन","180 दिन"],"explanation":"3 साल के भीतर तीन गंभीर यातायात उल्लंघनों के परिणामस्वरूप 120-दिन की CDL अयोग्यता होती है (जो पहले से लगाई गई किसी भी 60-दिन की अयोग्यता के बाद आनी चाहिए)। स्रोत: Nebraska DMV MCSIA पृष्ठ; 49 CFR 383.51।"},"49":{"q":"निम्नलिखित में से कौन-सा CDL धारकों के लिए नेब्रास्का की गंभीर यातायात उल्लंघनों की सूची में है?","options":["0.04 या अधिक BAC के साथ गाड़ी चलाना","CMV चलाते समय टेक्स्टिंग करना","रासायनिक परीक्षण से इनकार करना","एक अपराध करने के लिए CMV का उपयोग करना"],"explanation":"CMV चलाते समय टेक्स्टिंग करना नेब्रास्का में एक गंभीर यातायात उल्लंघन है। सूचीबद्ध अन्य तीन प्रमुख अपराध हैं। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"50":{"q":"चलाए जा रहे वाहन के लिए उचित वर्ग के CDL या आवश्यक एंडोर्समेंट के बिना CMV संचालित करने को नेब्रास्का में किस प्रकार के उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["एक मामूली उपकरण उल्लंघन","एक गंभीर यातायात उल्लंघन","एक प्रमुख अयोग्यता अपराध","एक आउट-ऑफ-सर्विस आदेश उल्लंघन"],"explanation":"उचित CDL वर्ग या एंडोर्समेंट के बिना CMV चलाना नेब्रास्का के गंभीर यातायात उल्लंघनों में से एक है, जो बार-बार करने पर 60-दिन/120-दिन की अयोग्यता के अधीन है। स्रोत: Nebraska DMV MCSIA पृष्ठ; 49 CFR 383.51।"},"51":{"q":"रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन की पहली दोषसिद्धि के लिए, एक नेब्रास्का CDL धारक कितने समय तक अयोग्य रहता है?","options":["कम से कम 30 दिन","कम से कम 60 दिन","कम से कम 120 दिन","कम से कम 1 साल"],"explanation":"पहले रेलमार्ग ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप कम से कम 60 दिनों की अयोग्यता होती है। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"52":{"q":"3-वर्ष की अवधि के भीतर एक नेब्रास्का CDL धारक के दूसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["कम से कम 60 दिन","कम से कम 90 दिन","कम से कम 120 दिन","कम से कम 1 साल"],"explanation":"3 साल के भीतर दूसरे रेलमार्ग ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप कम से कम 120 दिनों की अयोग्यता होती है। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"53":{"q":"नेब्रास्का में 3-वर्ष की अवधि के भीतर तीसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए अयोग्यता क्या है?","options":["कम से कम 120 दिन","कम से कम 180 दिन","कम से कम 1 साल","कम से कम 3 साल"],"explanation":"3 साल के भीतर तीसरे रेलमार्ग ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप कम से कम 1 साल की अयोग्यता होती है। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"54":{"q":"नेब्रास्का में एक मानक CMV चलाते समय आउट-ऑफ-सर्विस (OOS) आदेश का उल्लंघन करने की पहली दोषसिद्धि के लिए, अयोग्यता अवधि क्या है?","options":["30 से 60 दिन","90 दिन","180 दिन से 1 साल","2 से 5 साल"],"explanation":"एक मानक CMV में पहले आउट-ऑफ-सर्विस आदेश उल्लंघन के परिणामस्वरूप 180 दिन से 1 साल की अयोग्यता होती है। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"55":{"q":"नेब्रास्का में एक मानक CMV चलाते समय 10-वर्ष की अवधि के भीतर दूसरे आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["180 दिन से 1 साल","1 से 2 साल","2 से 5 साल","आजीवन"],"explanation":"10 साल के भीतर दूसरे आउट-ऑफ-सर्विस आदेश उल्लंघन के परिणामस्वरूप 2-से-5-साल की अयोग्यता होती है। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"56":{"q":"जब आउट-ऑफ-सर्विस आदेश उल्लंघन में ऐसा CMV शामिल हो जो प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ले जा रहा हो या 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया हो, तो नेब्रास्का में पहली-दोषसिद्धि की अयोग्यता क्या है?","options":["90 दिन से 1 साल","180 दिन से 2 साल","2 से 5 साल","3 से 5 साल"],"explanation":"प्लेकार्ड वाली खतरनाक सामग्री या 16+ यात्रियों के लिए डिज़ाइन किए गए वाहन से जुड़े पहले आउट-ऑफ-सर्विस आदेश उल्लंघन में 180 दिन से 2 साल की बढ़ी हुई अयोग्यता वहन होती है। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"57":{"q":"अपने CDL के निलंबित, निरस्त, या अयोग्य होने के दौरान CMV चलाने को नेब्रास्का द्वारा किस प्रकार के अपराध के रूप में माना जाता है?","options":["एक गंभीर यातायात उल्लंघन (60/120 दिन)","एक प्रमुख अयोग्यता अपराध (1 साल/आजीवन)","एक आउट-ऑफ-सर्विस उल्लंघन (180 दिन)","एक गैर-अयोग्यता कागज़ी उल्लंघन"],"explanation":"अपने CDL के निरस्त, निलंबित, रद्द होने, या अयोग्य होने के दौरान CMV चलाना एक प्रमुख अपराध है, जो पहले अपराध पर 1-साल की अयोग्यता और दूसरे पर आजीवन वहन करता है। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"58":{"q":"नेब्रास्का कानून (Neb. Rev. Stat. 60-6,179.01) के तहत, पहले टेक्स्टिंग-व्हाइल-ड्राइविंग उल्लंघन के लिए जुर्माना क्या है?","options":["$100","$200","$300","$500"],"explanation":"नेब्रास्का का एंटी-टेक्स्टिंग कानून (Neb. Rev. Stat. 60-6,179.01) पहले अपराध के लिए $200 का जुर्माना, दूसरे के लिए $300, और तीसरे या बाद के अपराध के लिए $500, साथ ही तीन अंक निर्धारित करता है। CDL चालकों के लिए, CMV में बार-बार टेक्स्टिंग करना भी एक गंभीर यातायात उल्लंघन है। स्रोत: Neb. Rev. Stat. 60-6,179.01।"},"59":{"q":"किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरित करने से जुड़े अपराध को करने में CMV का उपयोग करने के परिणामस्वरूप एक नेब्रास्का CDL धारक के लिए क्या दंड होता है?","options":["1-साल की अयोग्यता","3-साल की अयोग्यता","5-साल की अयोग्यता","बिना किसी पुनर्बहाली के आजीवन अयोग्यता"],"explanation":"किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरित करने से जुड़े अपराध को करने के लिए किसी भी मोटर वाहन का उपयोग करने के परिणामस्वरूप एक आजीवन अयोग्यता होती है जो कुछ अन्य आजीवन मामलों के लिए उपलब्ध 10-साल की पुनर्बहाली के लिए पात्र नहीं है। स्रोत: Nebraska DMV CDL Disqualification पृष्ठ; 49 CFR 383.51।"},"60":{"q":"नेब्रास्का के एक इंटरस्टेट पर, एक टो ट्रक शोल्डर पर खड़ा है जिसकी एम्बर (पीली) लाइटें चमक रही हैं। आप दाहिनी लेन में एक CMV चला रहे हैं और आपकी बायीं ओर एक खुली लेन है। नेब्रास्का के Move Over कानून के तहत, आपको क्या करना चाहिए?","options":["जब ऐसा करना सुरक्षित हो, तो खड़े वाहन से कम से कम एक चलती हुई लेन की दूरी वाली लेन में चले जाएं","अपनी गति बनाए रखें लेकिन पास से गुजरते समय अपना हॉर्न बजाएं","टो ट्रक के चले जाने तक पूरी तरह रुक जाएं","जब तक आप गति सीमा पर या उससे नीचे हैं, दाहिनी लेन में चलते रहें"],"explanation":"नेब्रास्का का Move Over कानून (Neb. Rev. Stat. 60-6,378.01) चमकती लाइटों वाले खड़े वाहन के पास आने वाले चालकों से गति कम करने और, जब सुरक्षित हो, खड़े वाहन से कम से कम एक चलती हुई लेन की दूरी वाली लेन में जाने की मांग करता है। स्रोत: Neb. Rev. Stat. 60-6,378.01 / NDOT 'Move Over, Slow Down'।"},"61":{"q":"नेब्रास्का के Move Over कानून का LB 530 के द्वारा 3 सितंबर, 2025 से काफी विस्तार किया गया। उस बदलाव के बाद से, चालकों को निम्नलिखित में से किसके लिए गति कम करनी और हटना चाहिए?","options":["केवल अधिकृत आपातकालीन वाहन जो चमकती लाल या नीली लाइटें दिखा रहे हों","केवल टो ट्रक और हाईवे रखरखाव वाहन","हाईवे के किनारे खड़े सभी वाहन और कमज़ोर सड़क उपयोगकर्ता, जिनमें पैदल यात्री, साइकिल चालक और कृषि उपकरण शामिल हैं","केवल किसी सक्रिय निर्माण कार्य क्षेत्र के भीतर खड़े वाहन"],"explanation":"LB 530 (3 सितंबर, 2025 से प्रभावी) के तहत, नेब्रास्का ने move-over आवश्यकता को आपातकालीन और रोडसाइड-असिस्टेंस वाहनों से आगे बढ़ाकर हाईवे के किनारे खड़े सभी वाहनों और कमज़ोर सड़क उपयोगकर्ताओं तक विस्तारित किया, जिनमें पैदल यात्री, साइकिल चालक, क्रॉसवॉक में मौजूद लोग, और कृषि वाहन या उपकरण शामिल हैं। स्रोत: Neb. LB 530 / NDOT प्रेस विज्ञप्ति 'Nebraska's Updated Move-Over Law Takes Effect Sept. 3'।"},"62":{"q":"नेब्रास्का के Move Over कानून के तहत, जब आप चेतावनी लाइटें दिखा रहे किसी खड़े वाहन के लिए सुरक्षित रूप से लेन नहीं बदल सकते, तो इसके बजाय आपको क्या करना चाहिए?","options":["ट्रैफ़िक साफ़ होने तक सड़क पर पूरी तरह रुक जाएं","अपनी गति कम करें, परिस्थितियों के लिए एक सुरक्षित गति बनाए रखें, और उचित सावधानी और सतर्कता के साथ आगे बढ़ें","निर्धारित गति सीमा बनाए रखें और सामान्य रूप से पास से गुजरें","क्षेत्र को जितनी जल्दी हो सके पार करने के लिए गति बढ़ाएं"],"explanation":"Neb. Rev. Stat. 60-6,378.01 यह प्रावधान करता है कि यदि लेन बदलना संभव या सुरक्षित नहीं है, तो चालक को गति कम करनी चाहिए, खड़े वाहन, मौसम, सड़क और ट्रैफ़िक परिस्थितियों को ध्यान में रखते हुए एक सुरक्षित गति बनाए रखनी चाहिए, और उचित सावधानी और सतर्कता के साथ आगे बढ़ना चाहिए। स्रोत: Neb. Rev. Stat. 60-6,378.01।"},"63":{"q":"नेब्रास्का में नेशनल सिस्टम ऑफ़ इंटरस्टेट हाईवे के ग्रामीण भाग पर एक वाणिज्यिक ट्रक के लिए अधिकतम गति सीमा क्या है, जब तक कि अन्यथा सूचित न हो?","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"Neb. Rev. Stat. 60-6,186 ग्रामीण इंटरस्टेट हाईवे पर अधिकतम गति 75 mph निर्धारित करता है। नेब्रास्का ट्रकों के लिए कोई अलग, कम वैधानिक गति सीमा निर्धारित नहीं करता; CMV अन्य वाहनों के समान ही निर्धारित अधिकतम गति का पालन करते हैं। स्रोत: Neb. Rev. Stat. 60-6,186 / NDOT गति-सीमा जानकारी।"},"64":{"q":"नेब्रास्का में किसी एक्सप्रेसवे या सुपर-टू हाईवे पर जो राज्य हाईवे प्रणाली का हिस्सा है, अधिकतम गति सीमा क्या है, जब तक कि अन्यथा सूचित न हो?","options":["55 mph","65 mph","70 mph","75 mph"],"explanation":"Neb. Rev. Stat. 60-6,186 राज्य हाईवे प्रणाली के हिस्से वाले एक्सप्रेसवे, सुपर-टू हाईवे, या फ़्रीवे पर 70 mph निर्धारित करता है। (ग्रामीण इंटरस्टेट 75 mph है; अन्य राज्य हाईवे 65 mph हैं।) स्रोत: Neb. Rev. Stat. 60-6,186 / NDOT गति-सीमा ब्रोशर।"},"65":{"q":"क्या नेब्रास्का का कानून यात्री कारों की तुलना में वाणिज्यिक ट्रकों के लिए एक अलग, कम अधिकतम वैधानिक गति सीमा निर्धारित करता है?","options":["हां, ट्रक पूरे राज्य में 65 mph तक सीमित हैं","हां, ट्रकों को निर्धारित सीमा से 10 mph नीचे चलना चाहिए","नहीं, Neb. Rev. Stat. 60-6,186 की वैधानिक अधिकतम गति सीमाएं सभी वाहनों पर समान रूप से लागू होती हैं","हां, लेकिन केवल इंटरस्टेट प्रणाली पर"],"explanation":"Neb. Rev. Stat. 60-6,186 सड़क श्रेणी के अनुसार समान वैधानिक अधिकतम गतियां स्थापित करता है, जिसमें ट्रकों के लिए कोई अलग गति सीमा नहीं है; वाणिज्यिक वाहनों को अन्य ट्रैफ़िक के समान ही निर्धारित अधिकतम गति का पालन करना चाहिए। स्रोत: Neb. Rev. Stat. 60-6,186।"},"66":{"q":"नेब्रास्का के एक राज्य हाईवे पर जो एक्सप्रेसवे, सुपर-टू, या फ़्रीवे नहीं है, अधिकतम गति सीमा क्या है, जब तक कि अन्यथा सूचित न हो?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Neb. Rev. Stat. 60-6,186 राज्य हाईवे प्रणाली के किसी भी हिस्से पर 65 mph निर्धारित करता है, जो एक्सप्रेसवे, सुपर-टू हाईवे, या फ़्रीवे के अलावा हो। स्रोत: Neb. Rev. Stat. 60-6,186 / NDOT गति-सीमा ब्रोशर।"},"67":{"q":"यात्रियों को ले जा रही एक बस या प्लेकार्ड लगा एक खतरनाक-सामग्री वाहन नेब्रास्का में एक रेलरोड ग्रेड क्रॉसिंग के पास पहुंचता है। निकटतम रेल से किस दूरी के भीतर चालक को रुकना चाहिए?","options":["5 और 25 फीट के बीच","15 और 50 फीट के बीच","25 और 75 फीट के बीच","50 और 100 फीट के बीच"],"explanation":"यात्रियों को ले जा रही बसों और प्लेकार्ड लगे HazMat CMV को निकटतम रेल से 15 और 50 फीट के बीच रुकना चाहिए, फिर पार करने से पहले देखना और सुनना चाहिए (49 CFR 392.10, जैसा कि नेब्रास्का CDL मैनुअल में सिखाया गया है)। स्रोत: Nebraska CDL Manual / 49 CFR 392.10।"},"68":{"q":"रेलरोड क्रॉसिंग पर रुकने के बाद, नेब्रास्का में एक CDL चालक पटरियों को पार करना शुरू करता है। गियर बदलने के संबंध में नियम क्या मांग करता है?","options":["नियंत्रण बनाए रखने के लिए पटरियों पर रहते हुए एक बार डाउनशिफ़्ट करें","ऐसे गियर में पार करें जो आपको बिना शिफ़्ट किए पूरा करने दे; पटरियों पर रहते हुए गियर न बदलें","इंजन पर तनाव कम करने के लिए पार करते समय न्यूट्रल में शिफ़्ट करें","रेल तक पहुंचने से पहले सबसे ऊंचे गियर में शिफ़्ट करें"],"explanation":"नेब्रास्का CDL मैनुअल और 49 CFR 392.10-392.11 ऐसे गियर में पार करने की मांग करते हैं जो आपको गियर बदले बिना क्रॉसिंग पूरी करने दे; जब वाहन का कोई भी हिस्सा पटरियों पर हो तो आपको गियर नहीं बदलना चाहिए। स्रोत: Nebraska CDL Manual / 49 CFR 392.10-392.11।"},"69":{"q":"नेब्रास्का में प्लेकार्ड लगे HazMat वाहनों और यात्री बसों को किस स्थिति में रेलरोड ग्रेड क्रॉसिंग पर रुकने की आवश्यकता नहीं होती?","options":["जब भी उनके पीछे का ट्रैफ़िक भारी हो","ऐसे क्रॉसिंग पर जो कार्यशील हाईवे ट्रैफ़िक सिग्नल द्वारा नियंत्रित हो जो हरा दिखा रहा हो, या जिस पर 'Exempt' चिह्न लगा हो","किसी आवासीय जिले में किसी भी क्रॉसिंग पर","केवल बजरी वाली सड़कों पर"],"explanation":"49 CFR 392.10 के तहत (नेब्रास्का CDL मैनुअल में सिखाया गया), रुकने की आवश्यकता अन्य बातों के साथ-साथ ऐसे क्रॉसिंग पर लागू नहीं होती जो हरा दिखा रहे कार्यशील हाईवे ट्रैफ़िक सिग्नल द्वारा नियंत्रित हो, स्ट्रीटकार/स्पर क्रॉसिंग, या 'Exempt' चिह्न से चिह्नित औद्योगिक/स्पर ग्रेड क्रॉसिंग पर। स्रोत: Nebraska CDL Manual / 49 CFR 392.10।"},"70":{"q":"जब अपनी चमकती लाल लाइटों के साथ और स्टॉप आर्म फैली हुई एक खड़ी नेब्रास्का स्कूल बस से मिलते या उससे आगे निकलते हैं, तो अन्य चालकों को क्या करना चाहिए (जहां कोई अपवाद लागू न हो)?","options":["25 mph तक धीमा करें और सावधानी से पास से गुजरें","पूरी तरह रुक जाएं और तब तक रुके रहें जब तक लाल लाइटें बंद न हो जाएं, स्टॉप आर्म वापस न आ जाए, और बस फिर से चल न पड़े","केवल तभी रुकें जब बच्चे सड़क पार करते दिखाई दें","बायीं ओर मर्ज करें और बस से आगे चलते रहें"],"explanation":"Neb. Rev. Stat. 60-6,175 के तहत जब कोई स्कूल बस स्टॉप सिग्नल आर्म फैली हुई और चमकती लाल लाइटों के साथ खड़ी हो तो पूरी तरह रुकना आवश्यक है, और चालक को तब तक रुके रहना चाहिए जब तक लाल लाइटें बंद न हो जाएं, आर्म वापस न आ जाए, और बस चलना फिर से शुरू न कर दे। स्रोत: Neb. Rev. Stat. 60-6,175।"},"71":{"q":"नेब्रास्का का कानून चालकों से क्या करने की मांग करता है जब कोई स्कूल बस पहली बार अपनी पीली (एम्बर) चेतावनी सिग्नल लाइटें सक्रिय करती है, इससे पहले कि लाल लाइटें चालू हों?","options":["तुरंत रुक जाएं, लाल लाइटें सक्रिय होने से भी पहले","गति को 25 mph से अधिक न करते हुए कम करें और रुकने के लिए तैयार रहें","लाल लाइटें चमकने तक गति बनाए रखें","गति को 40 mph से अधिक न करते हुए कम करें"],"explanation":"Neb. Rev. Stat. 60-6,175 किसी स्कूल बस से मिलने या उससे आगे निकलने वाले चालक से, जब वह अपनी पीली चेतावनी लाइटें चमका रही हो, गति को 25 mph से अधिक न करते हुए कम करने और वाहन को पूरी तरह रोकने के लिए तैयार रहने की मांग करता है। स्रोत: Neb. Rev. Stat. 60-6,175।"},"72":{"q":"नेब्रास्का के स्कूल-बस रुकने वाले कानून के तहत, विभाजित हाईवे की कौन सी स्थिति में पास आने वाले चालक को चमकती लाल लाइटों वाली स्कूल बस के लिए रुकने की आवश्यकता नहीं होती?","options":["उसी लेन में बस के ठीक पीछे चल रहा ट्रैफ़िक","विभाजित हाईवे पर विपरीत दिशा में पास आ रहा ट्रैफ़िक","अविभाजित दो-लेन वाली सड़क पर एक ही दिशा की निकटवर्ती लेन में ट्रैफ़िक","किसी साइड सड़क से उसी सड़क पर पास आ रहा ट्रैफ़िक"],"explanation":"Neb. Rev. Stat. 60-6,175 यह प्रावधान करता है कि रुकने की आवश्यकता विभाजित हाईवे पर विपरीत दिशा में पास आ रहे ट्रैफ़िक पर लागू नहीं होती (जैसे, मीडियन द्वारा अलग किया गया); विभाजित हाईवे की अलग सड़क पर चलने वाले चालकों को रुकने की ज़रूरत नहीं। अविभाजित सड़क पर बस का पीछा कर रहे या उससे मिल रहे वाहनों को फिर भी रुकना चाहिए। स्रोत: Neb. Rev. Stat. 60-6,175।"},"73":{"q":"एक CDL चालक किसी खराबी के कारण नेब्रास्का के दो-लेन, दो-तरफ़ा हाईवे के शोल्डर पर रुका हुआ है। आपातकालीन चेतावनी उपकरण (परावर्तक त्रिकोण) कितने मिनट के भीतर रखे जाने चाहिए?","options":["5 मिनट के भीतर","10 मिनट के भीतर","15 मिनट के भीतर","30 मिनट के भीतर"],"explanation":"नेब्रास्का CDL मैनुअल (49 CFR 392.22 का पालन करते हुए) रुकने के 10 मिनट के भीतर चेतावनी उपकरण रखे जाने की मांग करता है। स्रोत: Nebraska CDL Manual / 49 CFR 392.22।"},"74":{"q":"नेब्रास्का की एक दो-लेन, दो-तरफ़ा सड़क पर, एक CDL चालक को रुकने के बाद तीन आवश्यक चेतावनी त्रिकोण कहां रखने चाहिए?","options":["वाहन के लगभग 10 फीट पीछे, 100 फीट पीछे, और 100 फीट आगे","तीनों को वाहन के 10 फीट के भीतर","वाहन के 50 फीट, 150 फीट, और 250 फीट पीछे","केवल पिछली ओर लगभग 25 फीट, 75 फीट, और 200 फीट पर"],"explanation":"नेब्रास्का CDL मैनुअल (49 CFR 392.22) के अनुसार, दो-लेन दो-तरफ़ा सड़क पर एक त्रिकोण लगभग 10 फीट पीछे (ट्रैफ़िक की ओर), एक लगभग 100 फीट पीछे, और एक वाहन के लगभग 100 फीट आगे रखें। स्रोत: Nebraska CDL Manual / 49 CFR 392.22।"},"75":{"q":"नेब्रास्का में, NDOT से ओवरसाइज़ परमिट की आवश्यकता होने से पहले एक वाणिज्यिक वाहन की अधिकतम वैध चौड़ाई क्या है?","options":["8 फीट 0 इंच","8 फीट 6 इंच","9 फीट 0 इंच","10 फीट 0 इंच"],"explanation":"नेब्रास्का की वैध अधिकतम कुल वाहन चौड़ाई 8 फीट 6 इंच है; इससे चौड़ी किसी भी चीज़ के लिए NDOT ओवरसाइज़ परमिट की आवश्यकता होती है (एक कृषि-उपकरण दिन के उजाले का अपवाद लागू होता है)। स्रोत: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska' / Neb. Rev. Stat. ch. 60।"},"76":{"q":"परमिट की आवश्यकता होने से पहले नेब्रास्का की वैध अधिकतम कुल वाहन ऊंचाई क्या है?","options":["13 फीट 6 इंच","14 फीट 0 इंच","14 फीट 6 इंच","15 फीट 0 इंच"],"explanation":"नेब्रास्का की वैध अधिकतम कुल ऊंचाई 14 फीट 6 इंच है। ध्यान दें कि 12 फीट 6 इंच से अधिक वाहनों के संचालक ऊपरी अवरोधों को होने वाले नुकसान का जोखिम स्वयं उठाते हैं। स्रोत: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'।"},"77":{"q":"नेब्रास्का इस मायने में विशिष्ट है कि वह इंटरस्टेट मार्गों की तुलना में US और राज्य हाईवे मार्गों पर अधिक वैध सकल वज़न की अनुमति देता है। नेब्रास्का के US और राज्य मार्गों (इंटरस्टेट से अलग) पर वैध सकल वज़न सीमा क्या है?","options":["80,000 lbs","85,500 lbs","94,000 lbs","105,500 lbs"],"explanation":"नेब्रास्का का वैध सकल वज़न इंटरस्टेट-निर्दिष्ट मार्गों पर 80,000 lbs है लेकिन US और राज्य मार्गों पर 94,000 lbs (एक्सल और ब्रिज-फ़ॉर्मूला सीमाओं के अधीन)। स्रोत: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'।"},"78":{"q":"नेब्रास्का में इंटरस्टेट-निर्दिष्ट मार्गों पर परमिट के बिना एक CMV के लिए वैध अधिकतम सकल वज़न क्या है?","options":["73,280 lbs","80,000 lbs","88,000 lbs","94,000 lbs"],"explanation":"इंटरस्टेट-निर्दिष्ट मार्गों पर नेब्रास्का का वैध सकल वज़न 80,000 lbs है, जो संघीय सीमा के अनुरूप है, और सिंगल-एक्सल (20,000 lbs), टैंडम-एक्सल (34,000 lbs), और ब्रिज-फ़ॉर्मूला प्रतिबंधों के अधीन है। स्रोत: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'।"},"79":{"q":"नेब्रास्का का लेफ़्ट लेन / कीप-राइट नियम (Neb. Rev. Stat. 60-6,131) एक मल्टीलेन हाईवे पर सामान्य ट्रैफ़िक से धीमी गति से चल रहे एक CMV से क्या करने की मांग करता है?","options":["बायीं लेन का उपयोग करें ताकि तेज़ ट्रैफ़िक दायीं ओर से पास हो सके","ट्रैफ़िक के लिए उपलब्ध दाहिनी-ओर की लेन में चलें, बायीं लेन का उपयोग केवल पास करने, बायें मुड़ने, या किसी अवरोध से बचने के लिए करें","हर समय बीच की लेन में चलें","मौजूद सबसे तेज़ वाहन की गति से मिलाएं"],"explanation":"Neb. Rev. Stat. 60-6,131 वाहनों से, जिनमें CMV शामिल हैं, जो सामान्य ट्रैफ़िक से धीमी गति से चल रहे हों, दाहिनी-ओर की लेन में (या जितना व्यावहारिक हो दाहिने किनारे के पास) रहने की मांग करता है, और बायीं लेन को पास करने, बायें मोड़ की तैयारी, या किसी अवरोध से बचने के लिए आरक्षित रखता है। स्रोत: Neb. Rev. Stat. 60-6,131।"},"80":{"q":"नेब्रास्का में कौन सी राज्य एजेंसी वाणिज्यिक चालक लाइसेंस जारी करती है?","options":["Nebraska Department of Motor Vehicles (DMV), Driver Licensing Services के माध्यम से","Nebraska State Patrol","Nebraska Department of Transportation","Federal Motor Carrier Safety Administration"],"explanation":"नेब्रास्का में, Department of Motor Vehicles (DMV) अपनी Driver Licensing Services के माध्यम से CDL जारी करती है, और आवेदक Driver Licensing Offices में आवेदन और परीक्षण करते हैं। स्रोत: Nebraska DMV, CDL पेज (dmv.nebraska.gov/cdl)।"},"81":{"q":"नेब्रास्का में CDL कौशल परीक्षण देने से पहले, एक आवेदक को पहले एक Commercial Learner's Permit (CLP) प्राप्त करना होगा और इसे कम से कम कितने समय तक रखना होगा?","options":["14 दिन","7 दिन","30 दिन","60 दिन"],"explanation":"नेब्रास्का के लिए आवश्यक है कि चालक के पास एक वैध CLP हो और CDL कौशल परीक्षण देने से पहले इसे न्यूनतम 14 दिनों तक रखे। यह संघीय CLP नियम के अनुरूप है। स्रोत: Nebraska DMV, CDL Testing पेज।"},"82":{"q":"नेब्रास्का का CDL कौशल परीक्षण किन तीन भागों में विभाजित है?","options":["प्री-ट्रिप निरीक्षण, बुनियादी नियंत्रण कौशल, और ऑन-रोड ड्राइविंग","लिखित ज्ञान, दृष्टि जांच, और सड़क संकेत पहचान","कपलिंग, बैकिंग, और एयर-ब्रेक ब्लीड-डाउन","प्री-ट्रिप निरीक्षण, हज़मैट हैंडलिंग, और रात्रि ड्राइविंग"],"explanation":"नेब्रास्का की CDL कौशल परीक्षा तीन क्षेत्रों का मूल्यांकन करती है: प्री-ट्रिप निरीक्षण, बुनियादी नियंत्रण कौशल, और ऑन-रोड ड्राइविंग। स्रोत: Nebraska DMV, CDL Testing पेज।"},"83":{"q":"नेब्रास्का में एक Commercial Learner's Permit (CLP) कितने समय तक वैध रहता है?","options":["1 वर्ष","180 दिन","90 दिन","5 वर्ष"],"explanation":"एक नेब्रास्का CLP 1 वर्ष के लिए वैध होता है। स्रोत: Nebraska DMV, Commercial Learner's Permit पेज।"},"84":{"q":"नेब्रास्का की स्व-प्रमाणन प्रणाली के तहत, किन दो श्रेणियों के लिए चालक को एक वैध Medical Examiner's Certificate बनाए रखने की आवश्यकता होती है?","options":["श्रेणी A (Interstate Non-Excepted) और श्रेणी C (Intrastate Non-Excepted)","श्रेणी B (Interstate Excepted) और श्रेणी D (Intrastate Excepted)","श्रेणी A (Interstate Non-Excepted) और श्रेणी B (Interstate Excepted)","श्रेणी C (Intrastate Non-Excepted) और श्रेणी D (Intrastate Excepted)"],"explanation":"श्रेणी A (Interstate Non-Excepted) या श्रेणी C (Intrastate Non-Excepted) के रूप में स्व-प्रमाणन करने वाले चालकों के पास एक वैध medical examiner's certificate होना चाहिए। अपवादित श्रेणियों (B और D) के लिए ऐसा नहीं है। स्रोत: Nebraska DMV, CDL Documentation Requirements / Self-Certification चार्ट।"},"85":{"q":"19 मई, 2025 से प्रभावी, नेब्रास्का की DMV CDL/CLP धारकों के लिए Medical Examiner's Certificate (MEC) की जानकारी कैसे प्राप्त करती है?","options":["FMCSA National Registry से इलेक्ट्रॉनिक रूप से; चालक अब DMV को कागज़ी प्रतियां जमा नहीं करते","केवल प्रमाणित मेल द्वारा, मेडिकल कार्ड की नोटरीकृत कागज़ी प्रति के साथ","किसी Driver Licensing Office में व्यक्तिगत रूप से, जहां कर्मचारी कागज़ी कार्ड स्कैन करते हैं","परीक्षा के 10 दिनों के भीतर चालक के नियोक्ता से फ़ैक्स द्वारा"],"explanation":"19 मई, 2025 से शुरू होकर, नेब्रास्का CDL/CLP धारक अब DMV को अपने MEC की कागज़ी प्रति नहीं देते; DMV यह जानकारी FMCSA की National Registry से इलेक्ट्रॉनिक रूप से प्राप्त करती है। स्रोत: Nebraska DMV संघीय Medical Examiner's Certification नियम पर समाचार विज्ञप्ति।"},"86":{"q":"21 वर्ष या उससे अधिक आयु के धारक के लिए नेब्रास्का वाणिज्यिक चालक लाइसेंस की मानक वैधता अवधि क्या है?","options":["5 वर्ष (जारी होने के बाद पांचवें वर्ष में धारक के जन्मदिन पर समाप्त होता है)","4 वर्ष","8 वर्ष","2 वर्ष"],"explanation":"21 वर्ष या उससे अधिक आयु के व्यक्तियों को जारी किए गए नेब्रास्का लाइसेंस, जिनमें CDL शामिल हैं, जारी होने के बाद पांचवें वर्ष में धारक के जन्मदिन पर समाप्त होते हैं (लगभग 5-वर्ष का चक्र)। स्रोत: Nebraska DMV, Renewals पेज।"},"87":{"q":"INTERSTATE (अंतरराज्यीय) वाणिज्यिक ड्राइविंग के लिए नेब्रास्का CDL रखने की न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","25 वर्ष"],"explanation":"नेब्रास्का के लिए आवश्यक है कि चालक अंतरराज्यीय वाणिज्य में संचालन के लिए कम से कम 21 वर्ष के हों; केवल राज्य-के-भीतर वाले CDL चालक 18 वर्ष में योग्य हो सकते हैं। स्रोत: Nebraska DMV, CDL पेज (Class A/B/C आयु आवश्यकताएं)।"},"88":{"q":"केवल INTRASTATE (राज्य-के-भीतर) वाणिज्यिक ड्राइविंग के लिए नेब्रास्का CDL रखने की न्यूनतम आयु क्या है?","options":["18 वर्ष","21 वर्ष","16 वर्ष","19 वर्ष"],"explanation":"नेब्रास्का राज्य-के-भीतर संचालन के लिए 18 वर्ष में Class A, B, या C CDL की अनुमति देता है; अंतरराज्यीय संचालन के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: Nebraska DMV, CDL पेज।"},"89":{"q":"नेब्रास्का में नए CDL आवेदकों के लिए Entry-Level Driver Training (ELDT) किस तारीख को आवश्यक हुआ?","options":["7 फरवरी, 2022","19 मई, 2025","1 जनवरी, 2020","1 जुलाई, 2021"],"explanation":"7 फरवरी, 2022 से शुरू होकर, नए CDL आवेदकों, श्रेणी अपग्रेड करने वालों, और पहली बार हज़मैट आवेदन करने वालों को परीक्षण से पहले ELDT पूरा करना होगा। स्रोत: Nebraska DMV, CDL Testing पेज।"},"90":{"q":"नेब्रास्का DMV कैसे पुष्टि करती है कि एक CDL आवेदक ने आवश्यक Entry-Level Driver Training (ELDT) पूरा कर लिया है?","options":["DMV ELDT के प्रमाण को इलेक्ट्रॉनिक रूप से सत्यापित करती है","आवेदक केंद्रीय DMV कार्यालय को एक कागज़ी प्रशिक्षण प्रमाणपत्र डाक से भेजता है","आवेदक का नियोक्ता परीक्षण स्थल पर एक शपथपत्र पर हस्ताक्षर करता है","प्रशिक्षण स्कूल स्थानीय Driver Licensing Office को एक रोस्टर फ़ैक्स करता है"],"explanation":"नेब्रास्का बताता है कि DMV ELDT पूर्णता के प्रमाण को इलेक्ट्रॉनिक रूप से सत्यापित करेगी (FMCSA Training Provider Registry के माध्यम से)। स्रोत: Nebraska DMV, CDL Testing पेज।"},"91":{"q":"प्रत्येक नेब्रास्का CDL आवेदक को कौन सी जांच पास करनी चाहिए, चाहे वह नए सिरे से आवेदन कर रहा हो, नए निवासी के रूप में, या नवीनीकरण कर रहा हो?","options":["एक दृष्टि परीक्षण","एक खतरनाक सामग्री ज्ञान परीक्षण","एक एयर-ब्रेक प्रदर्शन परीक्षण","DMV में एक ड्रग और अल्कोहल जांच"],"explanation":"नेब्रास्का में सभी CDL आवेदकों के लिए एक दृष्टि परीक्षण आवश्यक है, जिनमें नए लाइसेंस, नए निवासी, और नवीनीकरण शामिल हैं। स्रोत: Nebraska DMV, CDL Testing पेज।"},"92":{"q":"यदि कोई नेब्रास्का आवेदक एक CDL लिखित ज्ञान परीक्षण या एक कौशल परीक्षण में असफल हो जाता है, तो वे आम तौर पर कितनी जल्दी पुनः परीक्षण दे सकते हैं?","options":["कम से कम एक-दिन की प्रतीक्षा अवधि के बाद","तुरंत, उसी दिन","14-दिन की प्रतीक्षा अवधि के बाद","30-दिन की प्रतीक्षा अवधि के बाद"],"explanation":"जब कोई लिखित या कौशल परीक्षण असफल हो जाता है तो नेब्रास्का पुनः परीक्षण से पहले कम से कम एक-दिन की प्रतीक्षा की मांग करता है। स्रोत: Nebraska DMV, CDL Testing पेज।"},"93":{"q":"नेब्रास्का में कौन सा CDL ज्ञान परीक्षण कभी माफ़ नहीं किया जा सकता, यहां तक कि एक वैध बाहरी-राज्य CDL को स्थानांतरित करने वाले नए निवासी के लिए भी?","options":["खतरनाक सामग्री (हज़मैट) ज्ञान परीक्षण","सामान्य ज्ञान परीक्षण","एयर-ब्रेक ज्ञान परीक्षण","कॉम्बिनेशन-वाहन ज्ञान परीक्षण"],"explanation":"नेब्रास्का योग्य नए निवासियों या समय पर नवीनीकरण के लिए कुछ लिखित परीक्षण माफ़ कर सकता है, लेकिन हज़मैट ज्ञान परीक्षण माफ़ नहीं किया जा सकता। स्रोत: Nebraska DMV, CDL Testing पेज।"},"94":{"q":"यदि सभी तीन कौशल-परीक्षण खंड पूरे होने से पहले CLP समाप्त हो जाता है, तो एक नेब्रास्का CLP धारक के पहले पास किए गए कौशल-परीक्षण खंडों का क्या होता है?","options":["पहले पास किए गए खंड अमान्य हो जाते हैं और उन्हें फिर से देना होता है","वे एक छूट अवधि के रूप में 90 और दिनों तक वैध रहते हैं","वे स्वचालित रूप से नवीनीकृत CLP में स्थानांतरित हो जाते हैं","केवल ऑन-रोड खंड फिर से देना होता है"],"explanation":"नेब्रास्का में, यदि सभी तीन कौशल-परीक्षण खंड पूरे होने से पहले CLP समाप्त हो जाता है, तो पहले पास किए गए कोई भी परीक्षण अमान्य हो जाते हैं और उन्हें फिर से देना होता है। स्रोत: Nebraska DMV, Commercial Learner's Permit पेज।"},"95":{"q":"DMV परीक्षकों के अलावा, नेब्रास्का CDL कौशल परीक्षण कहां आयोजित किए जाते हैं?","options":["DMV-अधिकृत तृतीय-पक्ष परीक्षकों द्वारा","केवल FMCSA संघीय निरीक्षकों द्वारा","केवल आवेदक के CDL प्रशिक्षण स्कूल प्रशिक्षक द्वारा","नियोक्ता द्वारा नामित किसी भी लाइसेंस प्राप्त CDL धारक द्वारा"],"explanation":"नेब्रास्का DMV-अधिकृत तृतीय-पक्ष परीक्षकों को CDL कौशल परीक्षण आयोजित करने की अनुमति देता है; उन्हें DMV को दो व्यावसायिक दिनों की अग्रिम सूचना देनी चाहिए। स्रोत: Nebraska DMV, CDL Testing पेज और Third-Party Testers सूची।"},"96":{"q":"नेब्रास्का CDL या CLP के लिए आवेदन करते समय, सोशल सिक्योरिटी नंबर का खुलासा करने का नियम क्या है?","options":["आवेदकों को एक वैध सोशल सिक्योरिटी नंबर का खुलासा करना होगा; CDL चालकों के लिए कोई छूट नहीं है","खुलासा वैकल्पिक है और इसे पासपोर्ट नंबर से बदला जा सकता है","केवल अंतरराज्यीय चालकों को इसका खुलासा करना होगा","यह केवल हज़मैट एंडोर्समेंट जोड़ते समय आवश्यक है"],"explanation":"नेब्रास्का CDL/CLP आवेदकों से एक वैध सोशल सिक्योरिटी नंबर का खुलासा करने की मांग करता है, जिसमें वाणिज्यिक चालकों के लिए कोई छूट नहीं है। स्रोत: Nebraska DMV, CDL Documentation Requirements।"},"97":{"q":"CDL आवेदन के लिए एक नेब्रास्का मुख्य पते को साबित करने के लिए, आवेदक को क्या प्रदान करना होगा?","options":["अलग-अलग स्रोतों से दो दस्तावेज़ जो नेब्रास्का पता दर्शाते हों; P.O. Box स्वीकार्य नहीं है","एक उपयोगिता बिल, जिसमें P.O. Box की अनुमति है","निवास का एक एकल शपथ-पत्र","केवल एक नेब्रास्का मतदाता पंजीकरण कार्ड"],"explanation":"नेब्रास्का अलग-अलग स्रोतों से दो पते-प्रमाण दस्तावेज़ों की मांग करता है (आम तौर पर 90 दिनों के भीतर जारी किए गए); P.O. Box स्वीकार्य नहीं है। स्रोत: Nebraska DMV, CDL Documentation Requirements।"},"98":{"q":"एक नेब्रास्का CDL धारक जो श्रेणी A या C के रूप में स्व-प्रमाणन करता है, यदि वह National Registry पर एक मौजूदा Medical Examiner's Certificate बनाए रखने में विफल रहता है, तो उसे किस परिणाम का जोखिम है?","options":["उनके CDL/CLP वाणिज्यिक विशेषाधिकारों का डाउनग्रेड","एक स्वचालित एक-वर्ष का लाइसेंस निलंबन","ऑन-रोड कौशल परीक्षण का अनिवार्य पुनः परीक्षण","CDL का हज़मैट-केवल लाइसेंस में रूपांतरण"],"explanation":"गैर-अपवादित (श्रेणी A/C) चालकों को एक मौजूदा MEC बनाए रखना चाहिए, जो अब National Registry से इलेक्ट्रॉनिक रूप से प्रेषित होता है; ऐसा करने में विफलता CDL/CLP के डाउनग्रेड का परिणाम देती है। स्रोत: Nebraska DMV Medical Examiner's Certification नियम पर समाचार विज्ञप्ति।"},"99":{"q":"एक नेब्रास्का CDL कौशल-परीक्षण अपॉइंटमेंट आम तौर पर कैसे निर्धारित होती है, और किसे कॉल करना चाहिए?","options":["केवल अपॉइंटमेंट द्वारा, और जो व्यक्ति वास्तव में परीक्षण दे रहा है उसे कॉल करना चाहिए","केवल वॉक-इन, कोई अपॉइंटमेंट स्वीकार नहीं","चालक की ओर से नियोक्ता के सुरक्षा निदेशक द्वारा","केवल ऑनलाइन, कोई फ़ोन विकल्प उपलब्ध नहीं"],"explanation":"नेब्रास्का CDL कौशल परीक्षण केवल अपॉइंटमेंट द्वारा आयोजित करता है, और जो आवेदक परीक्षण देगा उसे ही शेड्यूल करने के लिए कॉल करना होगा। स्रोत: Nebraska DMV, CDL Testing पेज।"}},"ar":{"0":{"q":"على الطرق السريعة في نبراسكا، ما هو الحد الأقصى للعرض الإجمالي المسموح به لمركبة تجارية دون تصريح خاص؟","options":["8 أقدام و6 بوصات","8 أقدام","9 أقدام","10 أقدام"],"explanation":"تحدد نبراسكا الحد الأقصى للعرض الإجمالي للمركبة بـ 8 أقدام و6 بوصات (102 بوصة). المصدر: NDOT 'الأحجام والأوزان القانونية للمركبات في نبراسكا'، البند 1؛ بما يتوافق مع Neb. Rev. Stat. 60-6,288."},"1":{"q":"ما هو الحد الأقصى للارتفاع الإجمالي للمركبة المسموح به على الطرق السريعة في نبراسكا دون تصريح؟","options":["14 قدمًا و6 بوصات","13 قدمًا و6 بوصات","14 قدمًا","15 قدمًا"],"explanation":"الحد الأقصى للارتفاع الإجمالي للمركبة في نبراسكا هو 14 قدمًا و6 بوصات. المصدر: NDOT 'الأحجام والأوزان القانونية للمركبات في نبراسكا'، البند 2."},"2":{"q":"في نبراسكا، ما هو الحد الأقصى للطول الإجمالي لمركبة واحدة (وليست مجموعة مركبات)؟","options":["40 قدمًا","45 قدمًا","53 قدمًا","35 قدمًا"],"explanation":"لا يجوز أن يتجاوز طول المركبة الواحدة في نبراسكا 40 قدمًا إجمالًا. المصدر: NDOT 'الأحجام والأوزان القانونية للمركبات في نبراسكا'، البند 3."},"3":{"q":"ما هو الحد الأقصى القانوني لطول نصف المقطورة (باستثناء الجرار-الشاحنة) في نبراسكا؟","options":["53 قدمًا","48 قدمًا","40 قدمًا","57 قدمًا"],"explanation":"تسمح نبراسكا بنصف مقطورة (باستثناء الجرار-الشاحنة) يصل طولها إلى 53 قدمًا. المصدر: NDOT 'الأحجام والأوزان القانونية للمركبات في نبراسكا'، البند 5."},"4":{"q":"ما هو الحد الأقصى للطول الإجمالي لمجموعة من المركبات في نبراسكا؟","options":["65 قدمًا","60 قدمًا","75 قدمًا","53 قدمًا"],"explanation":"تحدد نبراسكا الحد الأقصى للطول الإجمالي لمجموعة من المركبات بـ 65 قدمًا. المصدر: NDOT 'الأحجام والأوزان القانونية للمركبات في نبراسكا'، البند 4."},"5":{"q":"ما هو الحد الأقصى لحمل العجلة الواحدة المسموح به على طريق سريع في نبراسكا؟","options":["10,000 رطل","12,000 رطل","8,000 رطل","20,000 رطل"],"explanation":"لا يجوز لأي عجلة أن تحمل حمولة إجمالية تزيد عن 10,000 رطل على أي طريق سريع في نبراسكا. المصدر: NDOT 'الأحجام والأوزان القانونية'، البند 7؛ Neb. Rev. Stat. 60-6,294."},"6":{"q":"ما هو الحد الأقصى لحمل المحور الواحد المسموح به على الطرق السريعة في نبراسكا؟","options":["20,000 رطل","18,000 رطل","22,400 رطل","34,000 رطل"],"explanation":"تحدد نبراسكا حمل المحور الواحد بـ 20,000 رطل. المصدر: NDOT 'الأحجام والأوزان القانونية'، البند 8؛ Neb. Rev. Stat. 60-6,294."},"7":{"q":"ما هو الحد الأقصى لحمل المحور المزدوج المسموح به على الطرق السريعة في نبراسكا؟","options":["34,000 رطل","36,000 رطل","40,000 رطل","32,000 رطل"],"explanation":"لا يجوز أن يتجاوز الوزن الإجمالي المنقول عبر مجموعة المحور المزدوج 34,000 رطل في نبراسكا. المصدر: NDOT 'الأحجام والأوزان القانونية'، البند 9؛ Neb. Rev. Stat. 60-6,294."},"8":{"q":"ما هو الحد الأقصى للوزن الإجمالي لمركبة تعمل على الطرق المخصصة كطرق بين الولايات (Interstate) في نبراسكا دون تصريح؟","options":["80,000 رطل","94,000 رطل","84,000 رطل","76,000 رطل"],"explanation":"الوزن الإجمالي القانوني على الطرق المخصصة كطرق بين الولايات في نبراسكا هو 80,000 رطل. المصدر: NDOT 'الأحجام والأوزان القانونية'، ملاحظة استثناءات الوزن؛ Neb. Rev. Stat. 60-6,294."},"9":{"q":"على الطرق الأمريكية (U.S.) وطرق الولاية (غير الطرق بين الولايات) في نبراسكا، ما هو الحد القانوني للوزن الإجمالي؟","options":["94,000 رطل","80,000 رطل","90,000 رطل","100,000 رطل"],"explanation":"تسمح نبراسكا بوزن إجمالي قانوني قدره 94,000 رطل على الطرق الأمريكية وطرق الولاية (مع مراعاة حدود المحور وصيغة الجسر)، مقابل 80,000 رطل على الطرق بين الولايات. المصدر: NDOT 'الأحجام والأوزان القانونية'، ملاحظة استثناءات الوزن."},"10":{"q":"كيف تعرّف نبراسكا 'المحور المزدوج' لأغراض حدود الوزن؟","options":["محوران متتاليان تزيد المسافة بينهما عن 40 بوصة ولا تتجاوز 96 بوصة","محوران تقل المسافة بينهما عن 40 بوصة","أي محورين على بعد 120 بوصة من بعضهما البعض","محوران يبعدان بالضبط 60 بوصة"],"explanation":"تعرّف نبراسكا المحور المزدوج بأنه أي محورين متتاليين تزيد المسافة بين مركزيهما عن 40 بوصة ولا تتجاوز 96 بوصة. المصدر: Neb. Rev. Stat. 60-6,294."},"11":{"q":"بموجب جدول وزن مجموعة المحاور في نبراسكا (صيغة الجسر الفيدرالية)، ما هو الحد الأقصى للحمل لمحورين تفصل بينهما مسافة 8 أقدام؟","options":["34,000 رطل","38,000 رطل","40,000 رطل","36,000 رطل"],"explanation":"يبيّن جدول نبراسكا 'الحد الأقصى للحمل على أي مجموعة من محورين أو أكثر' مقدار 34,000 رطل لمحورين تفصل بينهما مسافة 8 أقدام. المصدر: جدول مجموعة المحاور في NDOT 'الأحجام والأوزان القانونية'؛ Neb. Rev. Stat. 60-6,294."},"12":{"q":"وفقًا لجدول وزن مجموعة المحاور في نبراسكا، ما هو الحد الأقصى للحمل على خمسة محاور تفصل بينها مسافة 51 قدمًا (بين الطرفين)؟","options":["80,000 رطل","76,000 رطل","84,000 رطل","78,000 رطل"],"explanation":"يُدرج جدول صيغة الجسر في نبراسكا مقدار 80,000 رطل لخمسة محاور تفصل بينها مسافة 51 قدمًا بين الطرفين. المصدر: جدول مجموعة المحاور في NDOT 'الأحجام والأوزان القانونية'؛ Neb. Rev. Stat. 60-6,294."},"13":{"q":"ما الذي يحكم الحد الأقصى للحمل الذي قد تحمله مجموعة من محورين أو أكثر على الطرق السريعة في نبراسكا؟","options":["مسافة التباعد بين المحورين الطرفيين للمجموعة، وفقًا لجدول صيغة الجسر","عدد الإطارات على المركبة فقط","قدرة المحرك بالحصان فقط","عرض المقطورة فقط"],"explanation":"تحدد نبراسكا حمل أي مجموعة محاور بناءً على المسافة بين المحورين الطرفيين للمجموعة، بتطبيق جدول صيغة الجسر الفيدرالية. المصدر: NDOT 'الأحجام والأوزان القانونية'؛ Neb. Rev. Stat. 60-6,294."},"14":{"q":"أي جهة تصدر تصاريح المركبات ذات الحجم الزائد/الوزن الزائد للسفر على الطرق السريعة لولاية نبراسكا؟","options":["وزارة النقل في نبراسكا (NDOT)","إدارة المركبات الآلية في نبراسكا","دورية ولاية نبراسكا","مكتب مأمور المقاطعة"],"explanation":"تصدر وزارة النقل في نبراسكا (NDOT) تصاريح الحجم الزائد/الوزن الزائد للطرق السريعة للولاية؛ وتوجّه DMV مقدمي الطلبات إلى NDOT. المصدر: الأسئلة الشائعة لـ Nebraska DMV؛ تصاريح NDOT / نظام تصاريح الشاحنات الآلي."},"15":{"q":"كيف يمكن لشركة نقل أن تحصل في معظم الأحيان على تصريح حجم زائد/وزن زائد من وزارة النقل (DOT) في نبراسكا؟","options":["من خلال نظام تصاريح الشاحنات الآلي عبر الإنترنت التابع لـ NDOT","بإرسال نموذج ورقي بالبريد إلى DMV","بالاتصال بقسم الشرطة المحلي","لا يمكن الحصول على التصاريح مسبقًا"],"explanation":"يتم الحصول على تصاريح الحجم الزائد/الوزن الزائد في نبراسكا من خلال نظام تصاريح الشاحنات الآلي عبر الإنترنت التابع لـ NDOT (dottruckpermits.nebraska.gov). المصدر: تصاريح NDOT؛ الأسئلة الشائعة لـ Nebraska DMV."},"16":{"q":"متى يكون تصريح الحجم الزائد أو الوزن الزائد مطلوبًا للتشغيل على الطرق السريعة في نبراسكا؟","options":["عندما تتجاوز المركبة أو الحمولة الحدود القصوى القانونية للحجم أو الوزن","فقط عند العبور إلى ولاية أخرى","فقط على الطرق المرصوفة بالحصى","فقط للمركبات التي تنقل مواد خطرة"],"explanation":"يلزم تصريح خاص من NDOT لنقل مركبة أو حمولة تتجاوز الحد الأقصى القانوني للحجم أو الوزن؛ ولا يُصدر تصريح لحمولة يمكن تقليلها أو تفكيكها دون صعوبة كبيرة. المصدر: NDOT 'الأحجام والأوزان القانونية' (الحجم أو الوزن الزائد)؛ Neb. Rev. Stat. 60-6,294."},"17":{"q":"في نبراسكا، عند أي ارتفاع يتحمل المشغّل مخاطر الخسارة والمسؤولية عن الاصطدام بالعوائق العلوية؟","options":["أكثر من 12 قدمًا و6 بوصات","أكثر من 13 قدمًا و6 بوصات","أكثر من 14 قدمًا و6 بوصات","أكثر من 11 قدمًا"],"explanation":"ينص قانون نبراسكا على أن مالكي/مشغّلي مركبة يتجاوز ارتفاعها 12 قدمًا و6 بوصات يتحملون المخاطرة ويكونون مسؤولين عن الأضرار التي تلحق بالعوائق العلوية. المصدر: NDOT 'الأحجام والأوزان القانونية'، استثناء الارتفاع."},"18":{"q":"أي استثناء خاص تمنحه نبراسكا من حد العرض البالغ 8 أقدام و6 بوصات؟","options":["المعدات الزراعية المنقولة خلال ساعات النهار في السياق المعتاد للعمليات الزراعية","أي مقطورة مسطحة تنقل الفولاذ","جميع المقطورات المبردة","المركبات المسجلة خارج الولاية"],"explanation":"لا ينطبق حد العرض البالغ 8'6\" في نبراسكا على المعدات الزراعية أثناء الحركة المؤقتة خلال ساعات النهار في السياق المعتاد للعمليات الزراعية. المصدر: NDOT 'الأحجام والأوزان القانونية'، استثناء العرض."},"19":{"q":"بموجب قواعد الوزن القانونية في نبراسكا، ماذا يحدث إذا عبرت شاحنة جسرًا بحمولة إجمالية تتجاوز السعة المعلنة للجسر وتسببت في ضرر؟","options":["يكون مالك المركبة مسؤولًا عن جميع الأضرار","تُقسم المسؤولية بالتساوي مع NDOT","لا توجد مسؤولية إذا تم شراء تصريح","السائق فقط، وليس المالك، هو المسؤول"],"explanation":"يجعل قانون نبراسكا مالك الشاحنة مسؤولًا عن جميع الأضرار الناتجة عن عبور جسر بحمولة تتجاوز سعته المعلنة. المصدر: NDOT 'الأحجام والأوزان القانونية' (نص الجسر)؛ Neb. Rev. Stat. 60-6,294."},"20":{"q":"في نبراسكا، أي فئة من CDL مطلوبة لتشغيل مجموعة من المركبات بتصنيف وزن مجموعة إجمالي (GCWR) قدره 26,001 رطل أو أكثر، بشرط أن يتجاوز تصنيف الوزن الإجمالي للمركبة (GVWR) للوحدة (الوحدات) المقطورة 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تعرّف نبراسكا CDL من الفئة A بأنها مجموعة من المركبات بتصنيف GCWR قدره 26,001 رطل أو أكثر حيث يكون لدى الوحدة (الوحدات) المقطورة تصنيف GVWR يزيد عن 10,000 رطل. المصدر: Nebraska DMV، فئات CDL والمصادقات والقيود."},"21":{"q":"بموجب قواعد نبراسكا، أي فئة من CDL تغطي مركبة واحدة بتصنيف GVWR قدره 26,001 رطل أو أكثر (أو مثل هذه المركبة وهي تقطر وحدة لا تتجاوز 10,000 رطل)؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تعرّف نبراسكا CDL من الفئة B بأنها مركبة واحدة بتصنيف GVWR قدره 26,001 رطل أو أكثر، أو أي مركبة من هذا القبيل تقطر وحدة لا تتجاوز 10,000 رطل. المصدر: Nebraska DMV، فئات CDL والمصادقات والقيود."},"22":{"q":"يشغّل سائق في نبراسكا مركبة واحدة بتصنيف GVWR أقل من 26,001 رطل ويُطلب وضع لافتات عليها للمواد الخطرة. أي فئة من CDL تنطبق؟","options":["الفئة A","الفئة B","الفئة C","الفئة O"],"explanation":"تغطي CDL من الفئة C في نبراسكا مركبة واحدة بتصنيف GVWR أقل من 26,001 رطل (أو تقطر وحدة تصل إلى 10,000 رطل) ويُطلب وضع لافتات عليها للمواد الخطرة أو تكون حافلة مصممة لنقل 16 راكبًا أو أكثر بما في ذلك السائق. المصدر: Nebraska DMV، فئات CDL والمصادقات والقيود."},"23":{"q":"وفقًا لتعريف الفئة C في نبراسكا، تتطلب الحافلة CDL عندما تكون مصممة لنقل كم عدد من الركاب؟","options":["8 أو أكثر بما في ذلك السائق","11 أو أكثر بما في ذلك السائق","16 أو أكثر بما في ذلك السائق","24 أو أكثر بما في ذلك السائق"],"explanation":"يشمل تعريف الفئة C في نبراسكا أي حافلة مصممة لنقل 16 راكبًا أو أكثر بما في ذلك السائق. المصدر: Nebraska DMV، فئات CDL والمصادقات والقيود."},"24":{"q":"ما هو الحد الأدنى للعمر اللازم لإصدار رخصة قيادة تجارية من نبراسكا للتشغيل داخل الولاية (داخل نبراسكا فقط)؟","options":["16 عامًا","17 عامًا","18 عامًا","21 عامًا"],"explanation":"لا تصدر نبراسكا CDL أو CLP لأي شخص لم يبلغ سن 18؛ فسن 18 هو الحد الأدنى للعمر لتشغيل CDL داخل الولاية. المصدر: Neb. Rev. Stat. 60-4,143؛ صفحات CDL لـ Nebraska DMV."},"25":{"q":"يرغب حامل CDL في نبراسكا في قيادة مركبة تجارية عبر حدود الولايات (بين الولايات). ما هو الحد الأدنى للعمر لفعل ذلك؟","options":["18 عامًا","19 عامًا","20 عامًا","21 عامًا"],"explanation":"في حين تصدر نبراسكا CDL داخل الولاية في سن 18، يجب أن يكون عمر السائق 21 عامًا على الأقل لتشغيل مركبة آلية تجارية في التجارة بين الولايات. المصدر: صفحات CDL لـ Nebraska DMV؛ 49 CFR 391.11 المطبق كقاعدة في نبراسكا."},"26":{"q":"أي مصادقة يحتاجها سائق في نبراسكا لنقل مواد خطرة بكميات تتطلب لافتات؟","options":["المصادقة N","المصادقة H","المصادقة T","المصادقة X"],"explanation":"المصادقة H (المواد الخطرة) مطلوبة لنقل المواد الخطرة ذات اللافتات؛ وهي تتطلب اختبار معرفة وتقييم تهديد أمني من TSA. المصدر: Nebraska DMV، فئات CDL والمصادقات والقيود."},"27":{"q":"قبل أن تصدر نبراسكا CDL مع مصادقة HazMat (H)، يجب على مقدم الطلب إكمال أي خطوة فحص خلفية فيدرالية إضافية؟","options":["تقييم تهديد أمني من TSA مع أخذ البصمات","مقابلة حقوق مدنية من FBI","تسجيل مواد خاضعة للرقابة من DEA","مراجعة تجنيس من USCIS"],"explanation":"إلى جانب اجتياز اختبار معرفة HazMat، تطلب نبراسكا من مقدمي الطلبات إكمال تقييم تهديد أمني من إدارة أمن النقل (TSA)، والذي يتضمن التسجيل المسبق وأخذ البصمات، قبل إصدار مصادقة H. المصدر: Nebraska DMV، فئات CDL والمصادقات والقيود؛ برنامج TSA HME."},"28":{"q":"كم مرة يجب على سائق في نبراسكا تجديد مصادقة HazMat (H)، بما في ذلك تقديم بصمات جديدة لتقييم تهديد TSA؟","options":["كل سنتين على الأقل","كل 3 سنوات على الأقل","كل 5 سنوات على الأقل","كل 8 سنوات على الأقل"],"explanation":"يجب تجديد مصادقة HazMat وتقييم تهديدها الأمني من TSA كل خمس سنوات على الأقل، مع تقديم بصمات جديدة عند التجديد. المصدر: صفحات CDL لـ Nebraska DMV؛ برنامج TSA HME (49 CFR 1572)."},"29":{"q":"أي مصادقة مطلوبة في نبراسكا لقيادة مركبة صهريج تُستخدم لنقل السوائل أو الغازات بالجملة؟","options":["المصادقة T","المصادقة N","المصادقة H","المصادقة P"],"explanation":"المصادقة N (مركبة الصهريج) مطلوبة لتشغيل مركبة صهريج وتتطلب اجتياز اختبار معرفة. المصدر: Nebraska DMV، فئات CDL والمصادقات والقيود."},"30":{"q":"يرغب سائق في نبراسكا في قطر مقطورات مزدوجة أو ثلاثية. أي مصادقة مطلوبة؟","options":["المصادقة N","المصادقة P","المصادقة T","المصادقة S"],"explanation":"المصادقة T (المزدوجة/الثلاثية) مطلوبة لقطر المقطورات المزدوجة والثلاثية وتتطلب اجتياز اختبار معرفة. المصدر: Nebraska DMV، فئات CDL والمصادقات والقيود."},"31":{"q":"أي مصادقة يجب أن يحملها حامل CDL في نبراسكا لقيادة مركبة مصممة لنقل 16 شخصًا أو أكثر، مثل حافلة الركاب؟","options":["المصادقة S","المصادقة P","المصادقة N","المصادقة H"],"explanation":"المصادقة P (الركاب) مطلوبة للمركبات المصممة لنقل 16 شخصًا أو أكثر (بما في ذلك السائق) وتتطلب اختبار معرفة بالإضافة إلى اختبار مهارات في مركبة تمثيلية. المصدر: Nebraska DMV، فئات CDL والمصادقات والقيود."},"32":{"q":"في نبراسكا، لا يجوز إصدار مصادقة S (الحافلة المدرسية) إلا مع أي مصادقة أخرى؟","options":["المصادقة H (HazMat)","المصادقة N (الصهريج)","المصادقة P (الركاب)","المصادقة T (المزدوجة/الثلاثية)"],"explanation":"تشترط نبراسكا أن تكون مصادقة S (الحافلة المدرسية) مصحوبة بمصادقة P (الركاب)؛ فلا يمكن للسائق حمل S دون P. المصدر: Nebraska DMV، فئات CDL والمصادقات والقيود."},"33":{"q":"ما هي أقل مدة يجب أن يحمل فيها سائق في نبراسكا تصريح متعلم تجاري (CLP) قبل إجراء اختبار مهارات CDL؟","options":["7 أيام","10 أيام","14 يومًا","30 يومًا"],"explanation":"تشترط نبراسكا، تبعًا للقاعدة الفيدرالية، أن يحمل السائق CLP صالحًا لمدة 14 يومًا كحد أدنى قبل إجراء اختبار مهارات CDL. المصدر: Nebraska DMV، تصريح المتعلم التجاري؛ 49 CFR 383.25."},"34":{"q":"ما هي مدة صلاحية تصريح المتعلم التجاري (CLP) في نبراسكا؟","options":["180 يومًا","سنة واحدة","سنتان","5 سنوات"],"explanation":"تصريح CLP في نبراسكا صالح لمدة سنة واحدة. وإذا انتهت صلاحيته قبل اجتياز جميع أجزاء اختبار المهارات الثلاثة، تصبح الأجزاء المجتازة سابقًا غير صالحة ويجب إعادة جميع اختبارات المهارات. المصدر: Nebraska DMV، تصريح المتعلم التجاري."},"35":{"q":"في أي فئات من CDL تصدر نبراسكا تصريح متعلم تجاري (CLP)؟","options":["الفئة A والفئة B فقط","الفئة C فقط","الفئة A وB وC","الفئة B والفئة C فقط"],"explanation":"تصدر نبراسكا تصاريح CLP في الفئة A والفئة B فقط. المصدر: Nebraska DMV، تصريح المتعلم التجاري."},"36":{"q":"أي مجموعة من المصادقات يمكن أن يحملها تصريح المتعلم التجاري (CLP) في نبراسكا؟","options":["H وT وX","P وS وN","H وN فقط","T وX فقط"],"explanation":"يمكن أن يحمل تصريح CLP في نبراسكا فقط المصادقات P (الركاب) وS (الحافلة المدرسية) وN (الصهريج، مقيدة بالفارغ/بلا حمولة)؛ ولا يُسمح بـ H وT وX على CLP. المصدر: Nebraska DMV، تصريح المتعلم التجاري؛ 49 CFR 383.25."},"37":{"q":"كم عدد المستندات التي تثبت عنوان الإقامة الرئيسي في نبراسكا التي يجب على مقدم طلب CDL/CLP تقديمها لإثبات الإقامة؟","options":["مستند واحد","مستندان من مصدرين مختلفين","ثلاثة مستندات","لا يلزم إثبات الإقامة"],"explanation":"تطلب نبراسكا مستندين من مصدرين مختلفين يبيّنان عنوان الإقامة الرئيسي لمقدم الطلب في نبراسكا؛ ولا يُقبل صندوق بريد. كما يجب على مقدم الطلب تقديم إثبات الهوية ورقم الضمان الاجتماعي وإثبات الجنسية الأمريكية أو الوضع القانوني. المصدر: Nebraska DMV، متطلبات وثائق CDL."},"38":{"q":"بموجب متطلب التدريب الفيدرالي لسائقي المستوى المبتدئ (ELDT) في نبراسكا، أين يجب إكمال تدريب السائق وتسجيله؟","options":["مع مزوّد مدرج في سجل مزودي التدريب التابع لـ FMCSA","في أي مدرسة قيادة خاصة يختارها السائق","من خلال تدريب مهني أثناء العمل فقط","في محطة فحص تابعة لـ Nebraska DMV"],"explanation":"يتطلب ELDT، الساري اعتبارًا من 7 فبراير 2022، من مقدمي الطلبات لأول مرة في الفئة A/B، والترقيات من B إلى A، ومقدمي الطلبات لأول مرة لمصادقات P أو S أو H إكمال التدريب مع مزوّد مدرج في سجل مزودي التدريب التابع لـ FMCSA، والذي يسجّل الإكمال. المصدر: Nebraska DMV، تدريب سائقي المستوى المبتدئ (ELDT)؛ 49 CFR Part 380."},"39":{"q":"أي فئة من فئات الإقرار الذاتي الطبي لـ CDL في نبراسكا تنطبق على سائق يعمل في التجارة بين الولايات ويخضع للمتطلبات الطبية الفيدرالية (الفحص الطبي DOT)؟","options":["بين الولايات غير معفى (الفئة A)","بين الولايات معفى (الفئة B)","داخل الولاية غير معفى (الفئة C)","داخل الولاية معفى (الفئة D)"],"explanation":"تنطبق الفئة A، بين الولايات غير معفى، على السائقين الخاضعين للمتطلبات الطبية والبصرية الفيدرالية؛ ويجب عليهم تقديم شهادة فاحص طبي حالية والاحتفاظ بها من مزوّد مدرج في السجل الوطني لدى DMV. المصدر: Nebraska DMV، فئات الإقرار الذاتي لـ CDL؛ Neb. Rev. Stat. 60-4,144.01."},"40":{"q":"أثناء تشغيل مركبة آلية تجارية (CMV) في نبراسكا، عند أي تركيز للكحول في الدم (BAC) يُعتبر السائق قائدًا تحت التأثير ومرتكبًا لمخالفة كبرى موجبة لإلغاء الأهلية؟","options":["0.02 أو أعلى","0.04 أو أعلى","0.08 أو أعلى","0.10 أو أعلى"],"explanation":"تجعل نبراسكا، تبعًا لـ 49 CFR 383.51 ودليل CDL في نبراسكا، تشغيل CMV بتركيز BAC قدره 0.04 أو أعلى مخالفة كبرى موجبة لإلغاء الأهلية. وينطبق حد 0.08 على المركبات غير التجارية. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ دليل CDL في نبراسكا."},"41":{"q":"بموجب قانون الموافقة الضمنية في نبراسكا، ما هي عاقبة رفض حامل CDL لاختبار كيميائي (نفس أو دم أو بول) بعد تشغيل مركبة آلية؟","options":["خطاب تحذير فقط، دون إلغاء الأهلية","يُعامل كمخالفة كبرى، تُلغى أهلية CDL تمامًا مثل إدانة DUI","تعليق لمدة 30 يومًا لا يؤثر على CDL","غرامة إدارية قدرها 100 دولار دون إجراء على الرخصة"],"explanation":"يعامل قانون الموافقة الضمنية في نبراسكا رفض اختبار الكحول/المخدرات كمخالفة كبرى موجبة لإلغاء الأهلية، تحمل نفس إلغاء أهلية CDL مثل DUI (سنة واحدة للمخالفة الأولى، مدى الحياة للثانية). المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"42":{"q":"في نبراسكا، كم مدة إلغاء أهلية حامل CDL عن أول مخالفة كبرى (مثل DUI أو رفض الاختبار) عند عدم نقل مواد خطرة ذات لافتات؟","options":["60 يومًا","6 أشهر","سنة واحدة","3 سنوات"],"explanation":"تُلغي أول مخالفة كبرى أهلية حامل CDL في نبراسكا لمدة سنة واحدة. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"43":{"q":"إذا ارتكب سائق في نبراسكا أول مخالفة كبرى أثناء تشغيل CMV يُطلب وضع لافتات عليها للمواد الخطرة، كم مدة إلغاء الأهلية؟","options":["سنة واحدة","سنتان","3 سنوات","مدى الحياة"],"explanation":"ترفع أول مخالفة كبرى أثناء نقل مواد خطرة ذات لافتات مدة إلغاء الأهلية من سنة واحدة إلى 3 سنوات. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"44":{"q":"ما هي مدة إلغاء الأهلية لحامل CDL في نبراسكا الذي يُدان بمخالفة كبرى ثانية؟","options":["3 سنوات","5 سنوات","10 سنوات","مدى الحياة"],"explanation":"تؤدي المخالفة الكبرى الثانية إلى إلغاء أهلية CDL مدى الحياة في نبراسكا. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"45":{"q":"أي مما يلي يُصنّف كمخالفة كبرى موجبة لإلغاء الأهلية لحامل CDL في نبراسكا، بدلًا من مخالفة مرورية خطيرة؟","options":["متابعة مركبة أخرى عن قرب شديد","مغادرة موقع حادث","تغييرات حارة غير سليمة أو غير منتظمة","السرعة 15 ميلًا في الساعة أو أكثر فوق الحد"],"explanation":"مغادرة موقع حادث مخالفة كبرى (إلغاء أهلية لسنة واحدة/مدى الحياة). أما المتابعة عن قرب شديد، والتغييرات غير المنتظمة للحارة، والسرعة المفرطة فهي مخالفات مرورية خطيرة (60/120 يومًا). المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"46":{"q":"ما مقدار تجاوز حد السرعة المعلن الذي يجب أن يقود به حامل CDL في نبراسكا حتى يُحتسب كمخالفة مرورية خطيرة من نوع 'السرعة المفرطة'؟","options":["10 ميل في الساعة أو أكثر فوق الحد","15 ميلًا في الساعة أو أكثر فوق الحد","20 ميلًا في الساعة أو أكثر فوق الحد","25 ميلًا في الساعة أو أكثر فوق الحد"],"explanation":"السرعة 15 ميلًا في الساعة أو أكثر فوق الحد المعلن هي مخالفة 'السرعة المفرطة' المرورية الخطيرة في نبراسكا. المصدر: دليل CDL في نبراسكا؛ صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"47":{"q":"في نبراسكا، كم مدة إلغاء أهلية حامل CDL عند إدانته بمخالفتين مروريتين خطيرتين في حادثتين منفصلتين خلال فترة 3 سنوات؟","options":["30 يومًا","60 يومًا","120 يومًا","سنة واحدة"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال 3 سنوات إلى إلغاء أهلية CDL لمدة 60 يومًا. المصدر: صفحة إلغاء أهلية CDL / MCSIA لـ Nebraska DMV؛ 49 CFR 383.51."},"48":{"q":"كم مدة إلغاء أهلية حامل CDL في نبراسكا عند ارتكاب ثلاث مخالفات مرورية خطيرة في حوادث منفصلة خلال فترة 3 سنوات؟","options":["60 يومًا","90 يومًا","120 يومًا","180 يومًا"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة خلال 3 سنوات إلى إلغاء أهلية CDL لمدة 120 يومًا (والتي يجب أن تتبع أي إلغاء أهلية لمدة 60 يومًا مفروض بالفعل). المصدر: صفحة MCSIA لـ Nebraska DMV؛ 49 CFR 383.51."},"49":{"q":"أي مما يلي مدرج في قائمة نبراسكا للمخالفات المرورية الخطيرة لحاملي CDL؟","options":["القيادة بتركيز BAC قدره 0.04 أو أعلى","إرسال الرسائل النصية أثناء قيادة CMV","رفض اختبار كيميائي","استخدام CMV لارتكاب جناية"],"explanation":"إرسال الرسائل النصية أثناء قيادة CMV مخالفة مرورية خطيرة في نبراسكا. أما الثلاثة الأخرى المدرجة فهي مخالفات كبرى. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"50":{"q":"تشغيل CMV دون الفئة المناسبة من CDL أو المصادقة المطلوبة للمركبة التي تُقاد يُصنّف في نبراسكا كأي نوع من المخالفات؟","options":["مخالفة معدات بسيطة","مخالفة مرورية خطيرة","مخالفة كبرى موجبة لإلغاء الأهلية","مخالفة أمر الإيقاف عن الخدمة"],"explanation":"قيادة CMV دون الفئة المناسبة من CDL أو المصادقة من بين المخالفات المرورية الخطيرة في نبراسكا، وتخضع لإلغاء أهلية لمدة 60 يومًا/120 يومًا عند ارتكابها بشكل متكرر. المصدر: صفحة MCSIA لـ Nebraska DMV؛ 49 CFR 383.51."},"51":{"q":"عن أول إدانة بمخالفة معبر سكة حديد-طريق سريع، كم مدة إلغاء أهلية حامل CDL في نبراسكا؟","options":["30 يومًا على الأقل","60 يومًا على الأقل","120 يومًا على الأقل","سنة واحدة على الأقل"],"explanation":"تؤدي أول مخالفة معبر سكة حديد إلى إلغاء أهلية لمدة 60 يومًا على الأقل. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"52":{"q":"ما هي مدة إلغاء الأهلية لمخالفة معبر سكة حديد-طريق سريع ثانية لحامل CDL في نبراسكا خلال فترة 3 سنوات؟","options":["60 يومًا على الأقل","90 يومًا على الأقل","120 يومًا على الأقل","سنة واحدة على الأقل"],"explanation":"تؤدي مخالفة معبر سكة حديد ثانية خلال 3 سنوات إلى إلغاء أهلية لمدة 120 يومًا على الأقل. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"53":{"q":"ما هي مدة إلغاء الأهلية لمخالفة معبر سكة حديد-طريق سريع ثالثة خلال فترة 3 سنوات في نبراسكا؟","options":["120 يومًا على الأقل","180 يومًا على الأقل","سنة واحدة على الأقل","3 سنوات على الأقل"],"explanation":"تؤدي مخالفة معبر سكة حديد ثالثة خلال 3 سنوات إلى إلغاء أهلية لمدة سنة واحدة على الأقل. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"54":{"q":"عن أول إدانة بمخالفة أمر الإيقاف عن الخدمة (OOS) أثناء قيادة CMV قياسية في نبراسكا، ما هي مدة إلغاء الأهلية؟","options":["30 إلى 60 يومًا","90 يومًا","180 يومًا إلى سنة واحدة","2 إلى 5 سنوات"],"explanation":"تؤدي أول مخالفة لأمر الإيقاف عن الخدمة في CMV قياسية إلى إلغاء أهلية لمدة 180 يومًا إلى سنة واحدة. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"55":{"q":"ما هي مدة إلغاء الأهلية لمخالفة أمر الإيقاف عن الخدمة ثانية خلال فترة 10 سنوات أثناء قيادة CMV قياسية في نبراسكا؟","options":["180 يومًا إلى سنة واحدة","1 إلى 2 سنة","2 إلى 5 سنوات","مدى الحياة"],"explanation":"تؤدي مخالفة أمر الإيقاف عن الخدمة ثانية خلال 10 سنوات إلى إلغاء أهلية لمدة 2 إلى 5 سنوات. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"56":{"q":"عندما تتعلق مخالفة أمر الإيقاف عن الخدمة بمركبة CMV تنقل مواد خطرة تتطلب لافتات أو مصممة لنقل 16 راكبًا أو أكثر، ما هي مدة إلغاء الأهلية عن أول إدانة في نبراسكا؟","options":["90 يومًا إلى سنة واحدة","180 يومًا إلى سنتين","2 إلى 5 سنوات","3 إلى 5 سنوات"],"explanation":"تحمل أول مخالفة لأمر الإيقاف عن الخدمة تتعلق بمواد خطرة ذات لافتات أو مركبة مصممة لـ 16 راكبًا فأكثر إلغاء أهلية مشددًا لمدة 180 يومًا إلى سنتين. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"57":{"q":"قيادة CMV بينما تكون رخصة CDL الخاصة بك معلقة أو ملغاة أو بينما أنت ملغى الأهلية تعاملها نبراسكا كأي نوع من المخالفات؟","options":["مخالفة مرورية خطيرة (60/120 يومًا)","مخالفة كبرى موجبة لإلغاء الأهلية (سنة واحدة/مدى الحياة)","مخالفة الإيقاف عن الخدمة (180 يومًا)","مخالفة أوراق غير موجبة لإلغاء الأهلية"],"explanation":"قيادة CMV بينما تكون رخصة CDL ملغاة أو معلقة أو موقوفة، أو بينما يكون السائق ملغى الأهلية، مخالفة كبرى، تحمل إلغاء أهلية لمدة سنة واحدة للمخالفة الأولى ومدى الحياة للثانية. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"58":{"q":"بموجب قانون نبراسكا (Neb. Rev. Stat. 60-6,179.01)، ما هي غرامة أول مخالفة لإرسال الرسائل النصية أثناء القيادة؟","options":["100 دولار","200 دولار","300 دولار","500 دولار"],"explanation":"يحدد قانون نبراسكا لمكافحة الرسائل النصية (Neb. Rev. Stat. 60-6,179.01) غرامة قدرها 200 دولار للمخالفة الأولى، و300 دولار للثانية، و500 دولار للثالثة أو ما بعدها، بالإضافة إلى ثلاث نقاط. وبالنسبة لسائقي CDL، يُعد تكرار إرسال الرسائل النصية في CMV أيضًا مخالفة مرورية خطيرة. المصدر: Neb. Rev. Stat. 60-6,179.01."},"59":{"q":"استخدام CMV في ارتكاب جناية تتعلق بتصنيع أو توزيع أو صرف مادة خاضعة للرقابة يؤدي إلى أي عقوبة لحامل CDL في نبراسكا؟","options":["إلغاء أهلية لمدة سنة واحدة","إلغاء أهلية لمدة 3 سنوات","إلغاء أهلية لمدة 5 سنوات","إلغاء أهلية مدى الحياة دون إعادة تأهيل"],"explanation":"استخدام أي مركبة آلية لارتكاب جناية تتعلق بتصنيع أو توزيع أو صرف مادة خاضعة للرقابة يؤدي إلى إلغاء أهلية مدى الحياة لا يكون مؤهلًا لإعادة التأهيل بعد 10 سنوات المتاحة لبعض حالات إلغاء الأهلية مدى الحياة الأخرى. المصدر: صفحة إلغاء أهلية CDL لـ Nebraska DMV؛ 49 CFR 383.51."},"60":{"q":"على طريق سريع بين الولايات في نبراسكا، تتوقف شاحنة قطر على الكتف الجانبي مع وميض أضوائها الكهرمانية. أنت تقود مركبة تجارية في المسار الأيمن، ويوجد مسار خالٍ على يسارك. بموجب قانون \"أفسح الطريق\" (Move Over) في نبراسكا، ماذا يجب أن تفعل؟","options":["انتقل إلى مسار يبعد بمسار متحرك واحد على الأقل عن المركبة المتوقفة عندما يكون ذلك آمنًا","حافظ على سرعتك ولكن أطلق بوق سيارتك أثناء تجاوزك","توقف توقفًا تامًا حتى تغادر شاحنة القطر","استمر في المسار الأيمن طالما أنك عند حد السرعة أو دونه"],"explanation":"يتطلب قانون \"أفسح الطريق\" (Move Over) في نبراسكا (Neb. Rev. Stat. 60-6,378.01) من السائقين الذين يقتربون من مركبة متوقفة ذات أضواء وامضة أن يخفضوا السرعة، وعندما يكون ذلك آمنًا، أن ينتقلوا إلى مسار يبعد بمسار متحرك واحد على الأقل عن المركبة المتوقفة. المصدر: Neb. Rev. Stat. 60-6,378.01 / NDOT 'Move Over, Slow Down'."},"61":{"q":"جرى توسيع قانون \"أفسح الطريق\" (Move Over) في نبراسكا بشكل كبير بموجب LB 530 اعتبارًا من 3 سبتمبر 2025. اعتبارًا من هذا التغيير، يجب على السائقين إبطاء السرعة وإفساح الطريق لأي مما يلي؟","options":["فقط مركبات الطوارئ المرخصة التي تعرض أضواء حمراء أو زرقاء وامضة","فقط شاحنات القطر ومركبات صيانة الطرق السريعة","جميع المركبات المتوقفة ومستخدمي الطريق المعرّضين للخطر على جانب الطريق السريع، بما في ذلك المشاة وراكبي الدراجات والمعدات الزراعية","فقط المركبات المتوقفة داخل منطقة عمل إنشائية نشطة"],"explanation":"بموجب LB 530 (الساري اعتبارًا من 3 سبتمبر 2025)، وسّعت نبراسكا متطلب إفساح الطريق ليتجاوز مركبات الطوارئ ومركبات المساعدة على الطريق ليشمل جميع المركبات المتوقفة ومستخدمي الطريق المعرّضين للخطر على جانب الطريق السريع، بما في ذلك المشاة وراكبي الدراجات والأشخاص في ممرات عبور المشاة والمركبات أو المعدات الزراعية. المصدر: Neb. LB 530 / NDOT press release 'Nebraska's Updated Move-Over Law Takes Effect Sept. 3'."},"62":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في نبراسكا، عندما لا تستطيع تغيير المسار بأمان لأجل مركبة متوقفة تعرض أضواء تحذيرية، ماذا يجب أن تفعل بدلًا من ذلك؟","options":["توقف توقفًا تامًا على الطريق حتى تنحسر حركة المرور","أخفض سرعتك، وحافظ على سرعة آمنة وفقًا للظروف، وتابع السير بعناية وحذر واجبين","حافظ على حد السرعة المعلن وتجاوز بشكل طبيعي","زِد سرعتك لمغادرة المنطقة بأسرع ما يمكن"],"explanation":"ينص Neb. Rev. Stat. 60-6,378.01 على أنه إذا لم يكن تغيير المسار ممكنًا أو آمنًا، فيجب على السائق خفض السرعة، والحفاظ على سرعة آمنة مع مراعاة المركبة المتوقفة وظروف الطقس والطريق وحركة المرور، والمتابعة بعناية وحذر واجبين. المصدر: Neb. Rev. Stat. 60-6,378.01."},"63":{"q":"ما هو الحد الأقصى لسرعة شاحنة تجارية على مقطع ريفي من النظام الوطني للطرق السريعة بين الولايات في نبراسكا، ما لم يُعلن خلاف ذلك؟","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"يحدد Neb. Rev. Stat. 60-6,186 الحد الأقصى للسرعة بـ 75 mph على الطرق السريعة الريفية بين الولايات. لا تحدد نبراسكا حد سرعة قانونيًا منفصلًا وأدنى للشاحنات؛ فالمركبات التجارية تتبع الحدود القصوى المعلنة نفسها التي تتبعها المركبات الأخرى. المصدر: Neb. Rev. Stat. 60-6,186 / NDOT speed-limit information."},"64":{"q":"على طريق سريع (expressway) أو طريق super-two في نبراسكا يكون جزءًا من نظام الطرق السريعة في الولاية، ما هو الحد الأقصى للسرعة ما لم يُعلن خلاف ذلك؟","options":["55 mph","65 mph","70 mph","75 mph"],"explanation":"يحدد Neb. Rev. Stat. 60-6,186 السرعة بـ 70 mph على طريق سريع (expressway) أو طريق super-two أو طريق حر (freeway) يكون جزءًا من نظام الطرق السريعة في الولاية. (الطريق الريفي بين الولايات هو 75 mph؛ والطرق السريعة الأخرى في الولاية هي 65 mph.) المصدر: Neb. Rev. Stat. 60-6,186 / NDOT speed-limit brochure."},"65":{"q":"هل يحدد قانون نبراسكا حدًا أقصى قانونيًا منفصلًا وأدنى للسرعة للشاحنات التجارية مقارنة بسيارات الركاب؟","options":["نعم، الشاحنات مقيدة بـ 65 mph على مستوى الولاية","نعم، يجب أن تسير الشاحنات بسرعة 10 mph دون الحد المعلن","لا، فالحدود القصوى القانونية للسرعة في Neb. Rev. Stat. 60-6,186 تنطبق بشكل موحّد على جميع المركبات","نعم، ولكن فقط على نظام الطرق بين الولايات"],"explanation":"يضع Neb. Rev. Stat. 60-6,186 حدودًا قصوى قانونية موحّدة للسرعة بحسب فئة الطريق دون حد سرعة منفصل للشاحنات؛ ويجب على المركبات التجارية الالتزام بالحدود القصوى المعلنة نفسها التي تلتزم بها بقية حركة المرور. المصدر: Neb. Rev. Stat. 60-6,186."},"66":{"q":"على طريق سريع تابع للولاية في نبراسكا لا يكون طريقًا سريعًا (expressway) أو super-two أو طريقًا حرًا (freeway)، ما هو الحد الأقصى للسرعة ما لم يُعلن خلاف ذلك؟","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"يحدد Neb. Rev. Stat. 60-6,186 السرعة بـ 65 mph على أي جزء من نظام الطرق السريعة في الولاية بخلاف الطريق السريع (expressway) أو طريق super-two أو الطريق الحر (freeway). المصدر: Neb. Rev. Stat. 60-6,186 / NDOT speed-limit brochure."},"67":{"q":"تقترب حافلة تنقل ركابًا أو مركبة تحمل لافتة مواد خطرة من معبر سكة حديد عند مستوى الطريق في نبراسكا. ضمن أي مسافة من أقرب قضيب سكة يجب على السائق أن يتوقف؟","options":["بين 5 و25 قدمًا","بين 15 و50 قدمًا","بين 25 و75 قدمًا","بين 50 و100 قدم"],"explanation":"يجب على الحافلات التي تنقل ركابًا والمركبات التجارية التي تحمل لافتة مواد خطرة (HazMat) أن تتوقف بين 15 و50 قدمًا من أقرب قضيب سكة، ثم تنظر وتُصغي قبل العبور (49 CFR 392.10، كما هو مُعلّم في دليل CDL في نبراسكا). المصدر: Nebraska CDL Manual / 49 CFR 392.10."},"68":{"q":"بعد التوقف عند معبر سكة حديد، يبدأ سائق CDL في نبراسكا بعبور القضبان. ماذا تتطلب القاعدة فيما يتعلق بتغيير التروس؟","options":["خفّض الترس مرة واحدة أثناء وجودك على القضبان للحفاظ على السيطرة","اعبر بترس يتيح لك إنهاء العبور دون تغيير التروس؛ لا تغيّر التروس أثناء وجودك على القضبان","انقل إلى الترس المحايد أثناء العبور لتقليل إجهاد المحرك","ارفع إلى أعلى ترس قبل وصولك إلى القضبان"],"explanation":"يتطلب دليل CDL في نبراسكا و49 CFR 392.10-392.11 العبور بترس يتيح لك إكمال العبور دون تغيير التروس؛ ويجب ألّا تغيّر التروس أثناء وجود أي جزء من المركبة على القضبان. المصدر: Nebraska CDL Manual / 49 CFR 392.10-392.11."},"69":{"q":"متى لا يُطلب من المركبات التي تحمل لافتة مواد خطرة (HazMat) وحافلات الركاب في نبراسكا التوقف عند معبر سكة حديد عند مستوى الطريق؟","options":["كلما كانت حركة المرور خلفها كثيفة","عند معبر تتحكم فيه إشارة مرور للطريق السريع تعمل وتُظهر اللون الأخضر، أو معلّم بلافتة 'Exempt'","عند أي معبر في منطقة سكنية","فقط على الطرق المرصوفة بالحصى"],"explanation":"بموجب 49 CFR 392.10 (المُعلّم في دليل CDL في نبراسكا)، لا ينطبق متطلب التوقف عند جملة أمور منها معبر تتحكم فيه إشارة مرور للطريق السريع تعمل وتُظهر اللون الأخضر، أو معبر ترام/فرعي، أو معبر صناعي/فرعي عند مستوى الطريق معلّم بلافتة 'Exempt'. المصدر: Nebraska CDL Manual / 49 CFR 392.10."},"70":{"q":"عند مقابلة أو تجاوز حافلة مدرسية متوقفة في نبراسكا تومض أضواؤها الحمراء وذراع التوقف ممدودة، ماذا يجب على السائقين الآخرين فعله (حيث لا ينطبق أي استثناء)؟","options":["أبطئ إلى 25 mph وتجاوز بحذر","توقف توقفًا تامًا وابقَ متوقفًا حتى تنطفئ الأضواء الحمراء، وتُسحب ذراع التوقف، وتتحرك الحافلة مجددًا","توقف فقط إذا كان الأطفال مرئيين وهم يعبرون الطريق","اندمج يسارًا واستمر في المرور بجانب الحافلة"],"explanation":"يتطلب Neb. Rev. Stat. 60-6,175 التوقف التام عندما تكون حافلة مدرسية متوقفة مع ذراع إشارة التوقف ممدودة وأضوائها الحمراء وامضة، ويجب على السائق أن يبقى متوقفًا حتى تنطفئ الأضواء الحمراء، وتُسحب الذراع، وتستأنف الحافلة الحركة. المصدر: Neb. Rev. Stat. 60-6,175."},"71":{"q":"يتطلب قانون نبراسكا من السائقين فعل ماذا عندما تُفعّل حافلة مدرسية لأول مرة أضواء إشارتها التحذيرية الصفراء (الكهرمانية)، قبل أن تضيء الأضواء الحمراء؟","options":["التوقف فورًا، حتى قبل أن تُفعّل الأضواء الحمراء","خفض السرعة إلى ما لا يزيد عن 25 mph والاستعداد للتوقف","الحفاظ على السرعة حتى تومض الأضواء الحمراء","خفض السرعة إلى ما لا يزيد عن 40 mph"],"explanation":"يتطلب Neb. Rev. Stat. 60-6,175 من السائق الذي يقابل أو يتجاوز حافلة مدرسية تومض أضواؤها التحذيرية الصفراء أن يخفض السرعة إلى ما لا يزيد عن 25 mph وأن يكون مستعدًا لإيقاف المركبة توقفًا تامًا. المصدر: Neb. Rev. Stat. 60-6,175."},"72":{"q":"بموجب قانون التوقف للحافلات المدرسية في نبراسكا، أي حالة على طريق مقسوم لا تتطلب من السائق المقترب التوقف لحافلة مدرسية تومض أضواؤها الحمراء؟","options":["حركة المرور التي تسير خلف الحافلة مباشرة في المسار نفسه","حركة المرور المقتربة في الاتجاه المعاكس على طريق مقسوم","حركة المرور في مسار مجاور بالاتجاه نفسه على طريق غير مقسوم بمسارين","حركة المرور المقتربة من شارع جانبي إلى الطريق نفسه"],"explanation":"ينص Neb. Rev. Stat. 60-6,175 على أن متطلب التوقف لا ينطبق على حركة المرور المقتربة في الاتجاه المعاكس على طريق مقسوم (مثل المفصول بجزيرة وسطية)؛ فالسائقون على مسار مختلف من طريق مقسوم لا يحتاجون إلى التوقف. أما المركبات التي تتبع الحافلة أو تقابلها على طريق غير مقسوم فيجب أن تتوقف. المصدر: Neb. Rev. Stat. 60-6,175."},"73":{"q":"توقف سائق CDL على كتف طريق سريع بمسارين واتجاهين في نبراسكا بسبب عطل. خلال كم دقيقة يجب وضع أجهزة التحذير من الطوارئ (المثلثات العاكسة)؟","options":["خلال 5 دقائق","خلال 10 دقائق","خلال 15 دقيقة","خلال 30 دقيقة"],"explanation":"يتطلب دليل CDL في نبراسكا (وفقًا لـ 49 CFR 392.22) وضع أجهزة التحذير خلال 10 دقائق من التوقف. المصدر: Nebraska CDL Manual / 49 CFR 392.22."},"74":{"q":"على طريق بمسارين واتجاهين في نبراسكا، أين يجب على سائق CDL وضع مثلثات التحذير الثلاثة المطلوبة بعد التوقف؟","options":["نحو 10 أقدام خلف المركبة، و100 قدم خلفها، و100 قدم أمامها","الثلاثة جميعها ضمن 10 أقدام من المركبة","عند 50 قدمًا و150 قدمًا و250 قدمًا خلف المركبة","نحو 25 قدمًا و75 قدمًا و200 قدم إلى الخلف فقط"],"explanation":"وفقًا لدليل CDL في نبراسكا (49 CFR 392.22)، على طريق بمسارين واتجاهين ضع مثلثًا واحدًا على نحو 10 أقدام إلى الخلف (جهة حركة المرور)، وواحدًا على نحو 100 قدم إلى الخلف، وواحدًا على نحو 100 قدم إلى الأمام من المركبة. المصدر: Nebraska CDL Manual / 49 CFR 392.22."},"75":{"q":"في نبراسكا، ما هو الحد الأقصى القانوني لعرض مركبة تجارية قبل أن يصبح تصريح الحجم الزائد من NDOT مطلوبًا؟","options":["8 أقدام و0 بوصة","8 أقدام و6 بوصات","9 أقدام و0 بوصة","10 أقدام و0 بوصة"],"explanation":"الحد الأقصى القانوني لعرض المركبة الإجمالي في نبراسكا هو 8 أقدام و6 بوصات؛ وأي عرض أكبر يتطلب تصريح حجم زائد من NDOT (ينطبق استثناء للمعدات الزراعية خلال ساعات النهار). المصدر: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska' / Neb. Rev. Stat. ch. 60."},"76":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة الإجمالي في نبراسكا قبل أن يصبح التصريح مطلوبًا؟","options":["13 قدمًا و6 بوصات","14 قدمًا و0 بوصة","14 قدمًا و6 بوصات","15 قدمًا و0 بوصة"],"explanation":"الحد الأقصى القانوني للارتفاع الإجمالي في نبراسكا هو 14 قدمًا و6 بوصات. لاحظ أن مشغّلي المركبات التي يتجاوز ارتفاعها 12 قدمًا و6 بوصات يتحملون مخاطر الأضرار التي تلحق بالعوائق العلوية. المصدر: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'."},"77":{"q":"تتميز نبراسكا بالسماح بوزن إجمالي قانوني أعلى على طرق US وطرق الولاية مقارنة بطرق Interstate. ما هو الحد القانوني للوزن الإجمالي على طرق US وطرق الولاية في نبراسكا (خارج Interstate)؟","options":["80,000 lbs","85,500 lbs","94,000 lbs","105,500 lbs"],"explanation":"الوزن الإجمالي القانوني في نبراسكا هو 80,000 lbs على الطرق المخصصة كـ Interstate، لكنه 94,000 lbs على طرق US وطرق الولاية (مع مراعاة حدود المحاور وصيغة الجسور). المصدر: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'."},"78":{"q":"ما هو الحد الأقصى القانوني للوزن الإجمالي لمركبة تجارية على الطرق المخصصة كـ Interstate في نبراسكا دون تصريح؟","options":["73,280 lbs","80,000 lbs","88,000 lbs","94,000 lbs"],"explanation":"على الطرق المخصصة كـ Interstate، الوزن الإجمالي القانوني في نبراسكا هو 80,000 lbs، بما يتوافق مع الحد الفيدرالي، مع مراعاة قيود المحور المفرد (20,000 lbs) والمحور المزدوج (34,000 lbs) وصيغة الجسور. المصدر: NDOT 'Legal Sizes and Weights for Vehicles in Nebraska'."},"79":{"q":"تتطلب قاعدة المسار الأيسر / الالتزام باليمين في نبراسكا (Neb. Rev. Stat. 60-6,131) من مركبة تجارية تسير أبطأ من حركة المرور المعتادة على طريق سريع متعدد المسارات أن تفعل ماذا؟","options":["استخدام المسار الأيسر كي تتمكن حركة المرور الأسرع من التجاوز من اليمين","السير في المسار الأيمن المتاح لحركة المرور، واستخدام المسار الأيسر فقط للتجاوز أو الانعطاف يسارًا أو تجنب عائق","السير في المسار الأوسط في جميع الأوقات","مجاراة سرعة أسرع مركبة موجودة"],"explanation":"يتطلب Neb. Rev. Stat. 60-6,131 من المركبات، بما فيها المركبات التجارية، التي تسير أبطأ من حركة المرور المعتادة أن تبقى في المسار الأيمن (أو أقرب ما يمكن من الحافة اليمنى)، مع حجز المسار الأيسر للتجاوز أو التحضير للانعطاف يسارًا أو تجنب عائق. المصدر: Neb. Rev. Stat. 60-6,131."},"80":{"q":"أي جهة حكومية في الولاية تُصدر رخص القيادة التجارية في نبراسكا؟","options":["إدارة المركبات الآلية في نبراسكا (DMV)، من خلال خدمات ترخيص السائقين","دورية ولاية نبراسكا","إدارة النقل في نبراسكا","الإدارة الفيدرالية لسلامة الناقلات الآلية"],"explanation":"في نبراسكا، تُصدر إدارة المركبات الآلية (DMV) رخص CDL من خلال خدمات ترخيص السائقين التابعة لها، ويتقدم المتقدمون بطلباتهم ويخضعون للاختبار في مكاتب ترخيص السائقين. المصدر: Nebraska DMV, CDL pages (dmv.nebraska.gov/cdl)."},"81":{"q":"قبل إجراء اختبار مهارات CDL في نبراسكا، يجب على المتقدم أولًا الحصول على تصريح متعلّم تجاري (CLP) والاحتفاظ به لمدة لا تقل عن كم؟","options":["14 days","7 days","30 days","60 days"],"explanation":"تتطلب نبراسكا من السائق أن يكون لديه CLP صالح وأن يحتفظ به لمدة لا تقل عن 14 days قبل إجراء اختبار مهارات CDL. وهذا يعكس قاعدة CLP الفيدرالية. المصدر: Nebraska DMV, CDL Testing page."},"82":{"q":"ينقسم اختبار مهارات CDL في نبراسكا إلى أي ثلاثة أجزاء؟","options":["الفحص قبل الرحلة، ومهارات التحكم الأساسية، والقيادة على الطريق","الاختبار النظري للمعرفة، وفحص النظر، والتعرّف على إشارات الطريق","الوصل، والرجوع للخلف، وتفريغ ضغط الفرامل الهوائية","الفحص قبل الرحلة، والتعامل مع المواد الخطرة، والقيادة الليلية"],"explanation":"يقيّم اختبار مهارات CDL في نبراسكا ثلاثة مجالات: الفحص قبل الرحلة، ومهارات التحكم الأساسية، والقيادة على الطريق. المصدر: Nebraska DMV, CDL Testing page."},"83":{"q":"ما مدة صلاحية تصريح المتعلّم التجاري (CLP) في نبراسكا؟","options":["1 year","180 days","90 days","5 years"],"explanation":"تصريح CLP في نبراسكا صالح لمدة 1 year. المصدر: Nebraska DMV, Commercial Learner's Permit page."},"84":{"q":"بموجب نظام التصديق الذاتي في نبراسكا، أي فئتين تتطلبان من السائق الاحتفاظ بشهادة فاحص طبي (Medical Examiner's Certificate) صالحة؟","options":["الفئة A (Interstate Non-Excepted) والفئة C (Intrastate Non-Excepted)","الفئة B (Interstate Excepted) والفئة D (Intrastate Excepted)","الفئة A (Interstate Non-Excepted) والفئة B (Interstate Excepted)","الفئة C (Intrastate Non-Excepted) والفئة D (Intrastate Excepted)"],"explanation":"يجب على السائقين الذين يصدّقون ذاتيًا أنهم ضمن الفئة A (Interstate Non-Excepted) أو الفئة C (Intrastate Non-Excepted) أن يكون لديهم شهادة فاحص طبي صالحة. أما الفئتان المستثناتان (B وD) فلا تتطلبان ذلك. المصدر: Nebraska DMV, CDL Documentation Requirements / Self-Certification chart."},"85":{"q":"اعتبارًا من 19 مايو 2025، كيف تتلقى DMV في نبراسكا معلومات شهادة الفاحص الطبي (MEC) لحاملي CDL/CLP؟","options":["إلكترونيًا من السجل الوطني التابع لـ FMCSA؛ ولم يعد السائقون يقدّمون نسخًا ورقية إلى DMV","بالبريد المسجّل فقط، مع نسخة ورقية موثّقة من البطاقة الطبية","شخصيًا في مكتب ترخيص السائقين، حيث يقوم الموظفون بمسح البطاقة الورقية ضوئيًا","بالفاكس من صاحب عمل السائق خلال 10 أيام من الفحص"],"explanation":"اعتبارًا من 19 مايو 2025، لم يعد حاملو CDL/CLP في نبراسكا يزوّدون DMV بنسخة ورقية من شهادة MEC الخاصة بهم؛ إذ تتلقى DMV المعلومات إلكترونيًا من السجل الوطني التابع لـ FMCSA. المصدر: Nebraska DMV news release on the federal Medical Examiner's Certification rule."},"86":{"q":"ما مدة الصلاحية القياسية لرخصة القيادة التجارية في نبراسكا لحاملها البالغ 21 عامًا أو أكثر؟","options":["5 years (تنتهي في عيد ميلاد الحامل في السنة الخامسة بعد الإصدار)","4 years","8 years","2 years"],"explanation":"الرخص الصادرة في نبراسكا للأفراد البالغين 21 عامًا أو أكثر، بما في ذلك رخص CDL، تنتهي في عيد ميلاد الحامل في السنة الخامسة بعد الإصدار (دورة مدتها نحو 5 years). المصدر: Nebraska DMV, Renewals page."},"87":{"q":"ما الحد الأدنى للعمر للحصول على رخصة CDL في نبراسكا للقيادة التجارية بين الولايات (INTERSTATE)؟","options":["21 years old","18 years old","19 years old","25 years old"],"explanation":"تتطلب نبراسكا أن يكون السائقون 21 عامًا على الأقل للعمل في التجارة بين الولايات؛ أما سائقو CDL داخل الولاية فقط فقد يكونون مؤهلين عند 18 عامًا. المصدر: Nebraska DMV, CDL page (Class A/B/C age requirements)."},"88":{"q":"ما الحد الأدنى للعمر للحصول على رخصة CDL في نبراسكا للقيادة التجارية داخل الولاية فقط (INTRASTATE)؟","options":["18 years old","21 years old","16 years old","19 years old"],"explanation":"تسمح نبراسكا برخصة CDL من الفئة A أو B أو C عند 18 عامًا للعمل داخل الولاية؛ أما العمل بين الولايات فيتطلب سن 21 عامًا. المصدر: Nebraska DMV, CDL page."},"89":{"q":"أصبح تدريب السائقين المبتدئين (ELDT) مطلوبًا في نبراسكا للمتقدمين الجدد لرخصة CDL في أي تاريخ؟","options":["February 7, 2022","May 19, 2025","January 1, 2020","July 1, 2021"],"explanation":"اعتبارًا من February 7, 2022، يجب على المتقدمين الجدد لرخصة CDL، والذين يرفعون فئتهم، والمتقدمين لأول مرة لاعتماد المواد الخطرة، إكمال ELDT قبل الاختبار. المصدر: Nebraska DMV, CDL Testing page."},"90":{"q":"كيف تؤكد DMV في نبراسكا أن متقدم CDL قد أكمل تدريب السائقين المبتدئين (ELDT) المطلوب؟","options":["تتحقق DMV من إثبات إكمال ELDT إلكترونيًا","يرسل المتقدم شهادة تدريب ورقية بالبريد إلى مكتب DMV المركزي","يوقّع صاحب عمل المتقدم إفادة خطية في موقع الاختبار","ترسل مدرسة التدريب قائمة بالأسماء بالفاكس إلى مكتب ترخيص السائقين المحلي"],"explanation":"تذكر نبراسكا أن DMV ستتحقق من إثبات إكمال ELDT إلكترونيًا (عبر سجل مزوّدي التدريب التابع لـ FMCSA). المصدر: Nebraska DMV, CDL Testing page."},"91":{"q":"أي فحص يجب أن يجتازه كل متقدم لرخصة CDL في نبراسكا، سواء كان متقدمًا جديدًا أو مقيمًا جديدًا أو مجدِّدًا؟","options":["فحص النظر","اختبار معرفة المواد الخطرة","اختبار أداء الفرامل الهوائية","فحص المخدرات والكحول في DMV"],"explanation":"فحص النظر مطلوب لجميع المتقدمين لرخصة CDL في نبراسكا، بما في ذلك الرخص الجديدة والمقيمين الجدد والتجديدات. المصدر: Nebraska DMV, CDL Testing page."},"92":{"q":"إذا رسب متقدم في نبراسكا في اختبار CDL النظري للمعرفة أو في اختبار المهارات، فبعد كم من الوقت يمكنه إعادة الاختبار عمومًا؟","options":["بعد فترة انتظار لا تقل عن يوم واحد","فورًا، في اليوم نفسه","بعد فترة انتظار مدتها 14 days","بعد فترة انتظار مدتها 30 days"],"explanation":"تتطلب نبراسكا انتظارًا لا يقل عن يوم واحد قبل إعادة الاختبار عند الرسوب في اختبار نظري أو اختبار مهارات. المصدر: Nebraska DMV, CDL Testing page."},"93":{"q":"أي اختبار معرفة CDL لا يمكن إعفاؤه أبدًا في نبراسكا، حتى للمقيم الجديد الذي ينقل رخصة CDL صالحة من ولاية أخرى؟","options":["اختبار معرفة المواد الخطرة (hazmat)","اختبار المعرفة العامة","اختبار معرفة الفرامل الهوائية","اختبار معرفة المركبات المركّبة (combination-vehicles)"],"explanation":"قد تُعفي نبراسكا من بعض الاختبارات النظرية للمقيمين الجدد المؤهلين أو في التجديدات المقدمة في وقتها، لكن اختبار معرفة المواد الخطرة (hazmat) لا يمكن إعفاؤه. المصدر: Nebraska DMV, CDL Testing page."},"94":{"q":"ماذا يحدث لأجزاء اختبار المهارات التي اجتازها حامل CLP في نبراسكا سابقًا إذا انتهت صلاحية CLP قبل إكمال الأجزاء الثلاثة جميعها؟","options":["تصبح الأجزاء التي اجتازها سابقًا باطلة ويجب إعادة إجرائها","تظل صالحة لمدة 90 days إضافية كفترة سماح","تُنقل تلقائيًا إلى CLP المجدَّد","يجب إعادة جزء القيادة على الطريق فقط"],"explanation":"في نبراسكا، إذا انتهت صلاحية CLP قبل إكمال أجزاء اختبار المهارات الثلاثة جميعها، فإن أي اختبارات اجتازها سابقًا تصبح باطلة ويجب إعادة إجرائها. المصدر: Nebraska DMV, Commercial Learner's Permit page."},"95":{"q":"أين تُجرى اختبارات مهارات CDL في نبراسكا، إضافةً إلى فاحصي DMV؟","options":["من قبل فاحصين خارجيين مفوّضين من DMV","فقط من قبل مفتشين فيدراليين تابعين لـ FMCSA","فقط من قبل مدرّب مدرسة تدريب CDL الخاص بالمتقدم","من قبل أي حامل رخصة CDL يعيّنه صاحب العمل"],"explanation":"تسمح نبراسكا لفاحصين خارجيين مفوّضين من DMV بإجراء اختبارات مهارات CDL؛ ويجب عليهم إشعار DMV قبل يومي عمل. المصدر: Nebraska DMV, CDL Testing page and Third-Party Testers list."},"96":{"q":"عند التقدم بطلب للحصول على CDL أو CLP في نبراسكا، ما القاعدة المتعلقة بالإفصاح عن رقم الضمان الاجتماعي؟","options":["يجب على المتقدمين الإفصاح عن رقم ضمان اجتماعي صالح؛ ولا يوجد إعفاء لسائقي CDL","الإفصاح اختياري ويمكن استبداله برقم جواز سفر","يجب على سائقي ما بين الولايات فقط الإفصاح عنه","يُطلب فقط عند إضافة اعتماد المواد الخطرة"],"explanation":"تتطلب نبراسكا من المتقدمين لـ CDL/CLP الإفصاح عن رقم ضمان اجتماعي صالح، دون أي إعفاءات للسائقين التجاريين. المصدر: Nebraska DMV, CDL Documentation Requirements."},"97":{"q":"لإثبات عنوان رئيسي في نبراسكا لطلب CDL، ماذا يجب على المتقدم تقديمه؟","options":["مستندان من مصدرين مختلفين يُظهران العنوان في نبراسكا؛ صندوق البريد (P.O. Box) غير مقبول","فاتورة مرافق واحدة، مع السماح بصندوق بريد (P.O. Box)","إفادة واحدة مشفوعة بقسم عن الإقامة","بطاقة تسجيل ناخب في نبراسكا فقط"],"explanation":"تتطلب نبراسكا مستندين لإثبات العنوان من مصدرين مختلفين (يصدران عمومًا خلال 90 days)؛ وصندوق البريد (P.O. Box) غير مقبول. المصدر: Nebraska DMV, CDL Documentation Requirements."},"98":{"q":"ما العاقبة التي يخاطر بها حامل رخصة CDL في نبراسكا الذي يصدّق ذاتيًا أنه ضمن الفئة A أو C إذا أخفق في الاحتفاظ بشهادة فاحص طبي سارية في السجل الوطني؟","options":["تخفيض امتيازات CDL/CLP التجارية الخاصة به","تعليق تلقائي للرخصة لمدة سنة واحدة","إعادة إلزامية لاختبار مهارات القيادة على الطريق","تحويل CDL إلى رخصة للمواد الخطرة فقط"],"explanation":"يجب على السائقين غير المستثنين (الفئة A/C) الاحتفاظ بشهادة MEC سارية، تُرسَل الآن إلكترونيًا من السجل الوطني؛ ويؤدي الإخفاق في ذلك إلى تخفيض رخصة CDL/CLP. المصدر: Nebraska DMV news release on the Medical Examiner's Certification rule."},"99":{"q":"كيف يُحجز عمومًا موعد اختبار مهارات CDL في نبراسكا، ومن الذي يجب أن يتصل؟","options":["بموعد مسبق فقط، ويجب على الشخص الذي سيؤدي الاختبار فعليًا أن يجري المكالمة","بالحضور دون موعد فقط، دون قبول أي موعد مسبق","من قبل مدير السلامة لدى صاحب العمل نيابةً عن السائق","عبر الإنترنت فقط، دون توفّر خيار الهاتف"],"explanation":"تجري نبراسكا اختبارات مهارات CDL بموعد مسبق فقط، ويجب أن يكون المتقدم الذي سيؤدي الاختبار هو من يتصل لتحديد الموعد. المصدر: Nebraska DMV, CDL Testing page."}}};
